    const wordCount = document.getElementById('wordCount');
    const reverseTime = document.getElementById('reverseTime');

    input.addEventListener('input', () => {
      const start = performance.now();
      const text = input.value;
      const reversed = text.split('').reverse().join('');

      outputBox.innerHTML = '';

      if (reversed.length === 0) {
        outputBox.innerHTML = '<span class="placeholder-text">Your reversed text will appear here...</span>';
      } else {
        reversed.split('').forEach((char, i) => {
          const span = document.createElement('span');
          span.classList.add('char-span');
          if (char === ' ') {
            span.classList.add('space');
            span.textContent = '\u00A0';
          } else {
            span.textContent = char;
          }
          span.style.animationDelay = `${i * 18}ms`;
          outputBox.appendChild(span);
        });
      }

      // Update stats
      charCount.textContent = text.length;
      wordCount.textContent = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;

