  <script>
    const textInput    = document.getElementById('textInput');
    const outputBox    = document.getElementById('outputBox');
    const clearBtn     = document.getElementById('clearBtn');
    const charCount    = document.getElementById('charCount');
    const statChars    = document.getElementById('statChars');
    const statWords    = document.getElementById('statWords');
    const statPalindrome = document.getElementById('statPalindrome');
    const copyBtn      = document.getElementById('copyBtn');
    const copyIcon     = document.getElementById('copyIcon');
    const copyText     = document.getElementById('copyText');
    const toast        = document.getElementById('toast');

    let animationQueue = null;

    function reverseString(str) {
      return str.split('').reverse().join('');
    }

    function isPalindrome(str) {
      if (!str) return false;
      const clean = str.toLowerCase().replace(/[^a-z0-9]/g, '');
      return clean.length > 0 && clean === clean.split('').reverse().join('');
    }

    function countWords(str) {
      return str.trim() === '' ? 0 : str.trim().split(/\s+/).length;
    }

    function getCharColor(index, total) {
      const hues = [
        '#a78bfa', '#818cf8', '#60a5fa', '#34d399',
        '#fbbf24', '#f472b6', '#fb923c', '#4ade80'
      ];
      return hues[index % hues.length];
    }

    function renderOutput(text) {
      outputBox.innerHTML = '';

      if (!text) {
        outputBox.innerHTML = '<span class="placeholder-text">Your reversed text will appear here...</span>';
        return;
      }

      const reversed = reverseString(text);
      const total    = reversed.length;

      reversed.split('').forEach((char, i) => {
        const span = document.createElement('span');
        span.classList.add('char-span');

        if (char === ' ') {
          span.classList.add('space-char');
          span.innerHTML = '&nbsp;';
        } else {
          span.textContent = char;
          span.style.color = getCharColor(i, total);
          span.style.textShadow = `0 0 12px ${getCharColor(i, total)}55`;
        }

        span.style.animationDelay = `${i * 28}ms`;
        outputBox.appendChild(span);
      });
    }

    function updateStats(text) {
      const chars  = text.length;
      const words  = countWords(text);
      const palind = isPalindrome(text);

      statChars.textContent = chars;
      statWords.textContent = words;
      statPalindrome.textContent = chars > 0 ? (palind ? '✓ Yes' : '✗ No') : '—';
      statPalindrome.style.background = chars > 0
        ? (palind
            ? 'linear-gradient(90deg,#34d399,#10b981)'
            : 'linear-gradient(90deg,#f87171,#ef4444)')
        : 'linear-gradient(90deg,#a78bfa,#60a5fa)';

      charCount.textContent = `${chars} character${chars !== 1 ? 's' : ''}`;

      copyBtn.disabled = chars === 0;
    }

    textInput.addEventListener('input', () => {
      const val = textInput.value;

      clearBtn.style.display = val.length > 0 ? 'block' : 'none';

      renderOutput(val);
      updateStats(val);
    });

    clearBtn.addEventListener('click', () => {
      textInput.value = '';
      textInput.focus();
      clearBtn.style.display = 'none';
      renderOutput('');
      updateStats('');
    });

    copyBtn.addEventListener('click', async () => {
      const reversed = reverseString(textInput.value);
      if (!reversed) return;

      try {
        await navigator.clipboard.writeText(reversed);
      } catch {
        const ta = document.createElement('textarea');
        ta.value = reversed;
        ta.style.position = 'fixed';
        ta.style.opacity  = '0';
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
      }

      copyBtn.classList.add('copied');
      copyIcon.textContent = '✓';
      copyText.textContent = 'Copied!';

      showToast();

      setTimeout(() => {
        copyBtn.classList.remove('copied');
        copyIcon.textContent = '📋';
        copyText.textContent = 'Copy Reversed Text';
      }, 2000);
    });

    function showToast() {
      toast.classList.add('show');
      setTimeout(() => toast.classList.remove('show'), 2500);
    }

    textInput.focus();
  </script>
