<body>

  <h1>🔍 Binary Search Visualizer</h1>
  <p class="subtitle">Step through the algorithm one iteration at a time</p>

  <div class="array-container" id="arrayContainer"></div>

  <div class="controls">
    <label for="targetInput">Target value:</label>
    <input type="number" id="targetInput" placeholder="e.g. 37" />
    <button id="startBtn" onclick="startSearch()">Start</button>
    <button id="stepBtn" onclick="step()" disabled>Step →</button>
    <button id="resetBtn" onclick="resetAll()">Reset</button>
  </div>

  <div class="status-panel">
    <div class="status-message" id="statusMsg">Enter a target value and press <strong>Start</strong>.</div>
    <div class="pointers" id="pointersDisplay" style="display:none">
      <span class="pointer-badge pointer-low"  id="lowLabel">Low: –</span>
      <span class="pointer-badge pointer-mid"  id="midLabel">Mid: –</span>
      <span class="pointer-badge pointer-high" id="highLabel">High: –</span>
    </div>
    <div class="step-counter" id="stepCounter"></div>
  </div>

  <div class="legend">
    <div class="legend-item"><div class="legend-dot dot-range"></div> Active range</div>
    <div class="legend-item"><div class="legend-dot dot-mid"></div> Mid element</div>
    <div class="legend-item"><div class="legend-dot dot-found"></div> Found</div>
    <div class="legend-item"><div class="legend-dot dot-elim"></div> Eliminated</div>
  </div>

  <script>
    const DATA = [2, 5, 8, 12, 16, 23, 29, 34, 37, 41, 45, 50, 56, 63, 71, 78, 84, 90, 95, 99];

    let low, high, mid, target, stepCount, done, foundIndex;

    function buildArray() {
      const container = document.getElementById('arrayContainer');
      container.innerHTML = '';
      DATA.forEach((val, idx) => {
        const box = document.createElement('div');
        box.classList.add('box');
        box.id = `box-${idx}`;
        box.innerHTML = `<span class="index-label">${idx}</span>${val}`;
        container.appendChild(box);
      });
    }

    function renderState() {
      DATA.forEach((_, idx) => {
        const box = document.getElementById(`box-${idx}`);
        box.className = 'box';

        if (done && foundIndex === idx) {
          box.classList.add('found');
        } else if (!done && idx === mid) {
          box.classList.add('mid');
        } else if (!done && idx >= low && idx <= high) {
          box.classList.add('in-range');
        } else {
          box.classList.add('eliminated');
        }
      });
    }

    function updateStatus(msg, cls = '') {
      const el = document.getElementById('statusMsg');
      el.className = 'status-message' + (cls ? ' ' + cls : '');
      el.innerHTML = msg;
    }

    function updatePointers(visible) {
      const panel = document.getElementById('pointersDisplay');
      panel.style.display = visible ? 'flex' : 'none';
      if (visible) {
        document.getElementById('lowLabel').textContent  = `Low: ${low} (${DATA[low]})`;
        document.getElementById('midLabel').textContent  = `Mid: ${mid} (${DATA[mid]})`;
        document.getElementById('highLabel').textContent = `High: ${high} (${DATA[high]})`;
      }
    }

    function startSearch() {
      const input = document.getElementById('targetInput').value.trim();
      if (input === '') {
        updateStatus('⚠️ Please enter a target value first.');
        return;
      }
      target = parseInt(input, 10);
      if (isNaN(target)) {
        updateStatus('⚠️ Please enter a valid integer.');
        return;
      }

      low       = 0;
      high      = DATA.length - 1;
      stepCount = 0;
      done      = false;
      foundIndex = -1;
      mid       = Math.floor((low + high) / 2);

      document.getElementById('stepBtn').disabled = false;
      document.getElementById('stepCounter').textContent = '';

      renderState();
      updatePointers(true);
      updateStatus(`Searching for <strong>${target}</strong>. Press <strong>Step</strong> to begin.`);
    }

    function step() {
      if (done) return;

      stepCount++;
      mid = Math.floor((low + high) / 2);

      document.getElementById('stepCounter').textContent = `Step ${stepCount}`;

      if (DATA[mid] === target) {
        done       = true;
        foundIndex = mid;
        renderState();
        updatePointers(false);
        updateStatus(`🎉 Found <strong>${target}</strong> at index <strong>${mid}</strong> in ${stepCount} step${stepCount > 1 ? 's' : ''}!`, 'result-found');
        document.getElementById('stepBtn').disabled = true;
        return;
      }

      renderState();
      updatePointers(true);

      if (DATA[mid] < target) {
        updateStatus(`Step ${stepCount}: <strong>${DATA[mid]}</strong> (index ${mid}) &lt; <strong>${target}</strong> → search <span style="color:#93c5fd">right half</span>`);
        low = mid + 1;
      } else {
        updateStatus(`Step ${stepCount}: <strong>${DATA[mid]}</strong> (index ${mid}) &gt; <strong>${target}</strong> → search <span style="color:#c4b5fd">left half</span>`);
        high = mid - 1;
      }

      if (low > high) {
        done = true;
        DATA.forEach((_, idx) => {
          document.getElementById(`box-${idx}`).className = 'box eliminated';
        });
        updatePointers(false);
        updateStatus(`❌ <strong>${target}</strong> not found in the array after ${stepCount} step${stepCount > 1 ? 's' : ''}.`, 'result-not-found');
        document.getElementById('stepBtn').disabled = true;
      }
    }

    function resetAll() {
      done       = false;
      foundIndex = -1;
      stepCount  = 0;
      document.getElementById('stepBtn').disabled = true;
      document.getElementById('stepCounter').textContent = '';
      document.getElementById('targetInput').value = '';
      updatePointers(false);
      updateStatus('Enter a target value and press <strong>Start</strong>.');
      buildArray();
    }

    // Init
    buildArray();
  </script>
</body>
</html>
```

### How it works

| Element | Description |
|---|---|
| **Array** | 20 pre-sorted integers (2 → 99) rendered as labeled boxes |
| **Start** | Validates the target, initialises `low`/`high`/`mid`, and enables the Step button |
| **Step →** | Advances exactly one iteration — compares `mid`, then moves `low` or `high` accordingly |
| **Highlighting** | 🔵 Active range · 🟡 Current mid · 🟢 Found · Dimmed = eliminated |
| **Status panel** | Shows the comparison made each step, pointer values, and the final Found / Not Found result |
| **Reset** | Clears everything back to the initial state |

