    <p>Type below and watch your text flip in real time</p>
  </div>

  <!-- Input -->
  <div class="input-wrapper">
    <label for="userInput">Your Text</label>
    <input
      type="text"
      id="userInput"
      placeholder="Start typing here…"
      maxlength="200"
      autocomplete="off"
      spellcheck="false"
    />
    <span class="char-count" id="charCount">0 / 200</span>
  </div>

  <!-- Divider -->
  <div class="divider">REVERSED OUTPUT</div>

  <!-- Output -->
  <div class="output-label">Result</div>
  <div class="output-box" id="outputBox">
    <span class="output-placeholder" id="outputPlaceholder">Your reversed text will appear here…</span>
  </div>

  <!-- Palindrome Badge -->
  <div class="palindrome-badge" id="palindromeBadge">
    ⭐ Palindrome detected! It reads the same both ways.
  </div>

  <!-- Stats -->
  <div class="stats">
    <div class="stat-pill">
      <div class="stat-value" id="statChars">0</div>
      <div class="stat-label">Characters</div>
    </div>
    <div class="stat-pill">
      <div class="stat-value" id="statWords">0</div>
      <div class="stat-label">Words</div>
    </div>
    <div class="stat-pill">
      <div class="stat-value" id="statUnique">0</div>
      <div class="stat-label">Unique Chars</div>
    </div>
  </div>

  <!-- Buttons -->
  <button class="copy-btn" id="copyBtn" disabled>
    <span id="copyIcon">📋</span>
    <span id="copyText">Copy Reversed Text</span>
  </button>
  <button class="clear-btn" id="clearBtn" disabled>
    ✕ Clear
  </button>

</div>

<script>
  // ── Element References ──────────────────────────────────────────────────────
  const userInput         = document.getElementById('userInput');
  const outputBox         = document.getElementById('outputBox');
  const outputPlaceholder = document.getElementById('outputPlaceholder');
  const charCountEl       = document.getElementById('charCount');
  const palindromeBadge   = document.getElementById('palindromeBadge');
  const statChars         = document.getElementById('statChars');
  const statWords         = document.getElementById('statWords');
  const statUnique        = document.getElementById('statUnique');
  const copyBtn           = document.getElementById('copyBtn');
  const copyIcon          = document.getElementById('copyIcon');
  const copyText          = document.getElementById('copyText');
  const clearBtn          = document.getElementById('clearBtn');

  const MAX_LEN = 200;

  // ── Animation delay per character (ms) ─────────────────────────────────────
  const CHAR_DELAY = 28;

  // ── Core Logic ──────────────────────────────────────────────────────────────
  function reverseString(str) {
    // Handles Unicode surrogate pairs / emoji correctly
    return [...str].reverse().join('');
  }

  function isPalindrome(str) {
    if (str.length < 2) return false;
    const cleaned = str.toLowerCase().replace(/[^a-z0-9]/g, '');
    return cleaned.length >= 2 && cleaned === [...cleaned].reverse().join('');
  }

  function countWords(str) {
    const trimmed = str.trim();
    if (!trimmed) return 0;
    return trimmed.split(/\s+/).length;
  }

  function countUnique(str) {
    return new Set([...str].filter(c => c !== ' ')).size;
  }

  // ── Render Animated Characters ──────────────────────────────────────────────
  function renderAnimatedChars(text) {
    // Clear previous content
    outputBox.innerHTML = '';

    if (!text) {
      outputBox.appendChild(outputPlaceholder);
      outputBox.classList.remove('has-content');
      return;
    }

    outputBox.classList.add('has-content');

    const chars = [...text]; // spread handles emoji/unicode
    chars.forEach((char, index) => {
      const span = document.createElement('span');
      span.classList.add('char-span');

      if (char === ' ') {
        span.classList.add('space');
        span.textContent = '\u00A0'; // non-breaking space
      } else {
        span.textContent = char;
      }

      // Stagger the animation
      span.style.animationDelay = `${index * CHAR_DELAY}ms`;
      outputBox.appendChild(span);
    });
  }

  // ── Update UI ───────────────────────────────────────────────────────────────
  let debounceTimer = null;

  function updateUI() {
    const raw     = userInput.value;
    const len     = [...raw].length; // emoji-safe length
    const reversed = reverseString(raw);
    const hasText  = raw.length > 0;

    // Character counter
    charCountEl.textContent = `${raw.length} / ${MAX_LEN}`;
    charCountEl.className = 'char-count' +
      (raw.length >= MAX_LEN ? ' max' : raw.length >= MAX_LEN * 0.8 ? ' warn' : '');

    // Animated output
    renderAnimatedChars(reversed);

    // Palindrome badge
    if (isPalindrome(raw)) {
      palindromeBadge.classList.add('show');
    } else {
      palindromeBadge.classList.remove('show');
    }

    // Stats
    statChars.textContent  = len;
    statWords.textContent  = countWords(raw);
    statUnique.textContent = countUnique(raw);

    // Buttons
    copyBtn.disabled  = !hasText;
    clearBtn.disabled = !hasText;
  }

  // ── Copy to Clipboard ───────────────────────────────────────────────────────
  async function copyToClipboard() {
    const reversed = reverseString(userInput.value);
    if (!reversed) return;

    try {
      await navigator.clipboard.writeText(reversed);
      // Success feedback
      copyBtn.classList.add('copied');
      copyIcon.textContent = '✅';
      copyText.textContent = 'Copied!';

      setTimeout(() => {
        copyBtn.classList.remove('copied');
        copyIcon.textContent = '📋';
        copyText.textContent = 'Copy Reversed Text';
      }, 2000);
    } catch {
      // Fallback for older browsers
      const ta = document.createElement('textarea');
      ta.value = reversed;
      ta.style.position = 'fixed';
      ta.style.opacity  = '0';
      document.body.appendChild(ta);
      ta.select();
      document.execCommand('copy');
      document.body.removeChild(ta);

      copyIcon.textContent = '✅';
      copyText.textContent = 'Copied!';
      setTimeout(() => {
        copyIcon.textContent = '📋';
        copyText.textContent = 'Copy Reversed Text';
      }, 2000);
    }
  }

  // ── Clear ───────────────────────────────────────────────────────────────────
  function clearAll() {
    userInput.value = '';
    userInput.focus();
    updateUI();
  }

  // ── Event Listeners ─────────────────────────────────────────────────────────
  userInput.addEventListener('input', () => {
    clearTimeout(debounceTimer);
    // Instant update feels snappy for short strings
    // tiny debounce prevents jank on rapid paste of very long text
    debounceTimer = setTimeout(updateUI, 30);
  });

  copyBtn.addEventListener('click', copyToClipboard);
  clearBtn.addEventListener('click', clearAll);

  // ── Init ─────────────────────────────────────────────────────────────────────
  updateUI();
  userInput.focus();
</script>
</body>
</html>
```

## What's included and how it works

### Core Features
- **Real-time reversal** — the output updates as you type with a 30 ms debounce to keep things smooth
- **Character animation** — each character in the reversed output fades and slides in with a staggered delay (`nth-child` colour cycling gives each one a unique colour)
- **Emoji / Unicode safe** — uses the spread operator `[...str]` instead of `.split('')` so emoji and multi-byte characters reverse correctly

### Extra Touches
| Feature | Detail |
|---|---|
| **Palindrome detector** | A gold badge appears when the input is a palindrome (e.g. *racecar*, *A man a plan a canal Panama*) |
| **Live stats** | Shows character count, word count and unique character count |
| **Character counter** | Turns amber at 80 % capacity and red when full |
| **Copy button** | Uses the modern Clipboard API with an `execCommand` fallback; turns green on success |
| **Clear button** | Resets everything and returns focus to the input |
| **Glassmorphism card** | Frosted-glass effect with a deep purple gradient background |
| **Floating icon** | Subtle CSS keyframe animation on the header icon |

