      margin-bottom: 0.4rem;
    }

    .header p {
      color: var(--muted);
      font-size: 0.95rem;
    }

    /* Card */
    .card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 20px;
      padding: 2rem;
      display: flex;
      flex-direction: column;
      gap: 1.5rem;
      box-shadow: 0 0 60px rgba(124,106,255,0.08);
      transition: box-shadow 0.3s;
    }

    .card:focus-within {
      box-shadow: 0 0 80px rgba(124,106,255,0.18);
    }

    /* Label */
    .field-label {
      font-size: 0.75rem;
      font-weight: 700;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: var(--muted);
      margin-bottom: 0.5rem;
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }

    .field-label .dot {
      width: 6px;
      height: 6px;
      border-radius: 50%;
      background: var(--accent);
      display: inline-block;
    }

    .field-label .dot.green { background: var(--accent3); }

    /* Input */
    .input-wrap {
      position: relative;
    }

    #inputField {
      width: 100%;
      background: var(--surface2);
      border: 1.5px solid var(--border);
      border-radius: 12px;
      padding: 1rem 1.2rem;
      font-size: 1.1rem;
      font-family: 'Courier New', monospace;
      color: var(--text);
      outline: none;
      transition: border-color 0.2s, box-shadow 0.2s;
      letter-spacing: 0.05em;
    }

    #inputField::placeholder { color: var(--muted); }

    #inputField:focus {
      border-color: var(--accent);
      box-shadow: 0 0 0 3px var(--glow);
    }

    /* Char counter */
    .char-counter {
      position: absolute;
      right: 1rem;
      bottom: 0.85rem;
      font-size: 0.72rem;
      color: var(--muted);
      font-family: monospace;
      transition: color 0.2s;
    }

    /* Stats bar */
    .stats {
      display: flex;
      gap: 1rem;
      flex-wrap: wrap;
    }

    .stat-pill {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: 999px;
      padding: 0.3rem 0.85rem;
      font-size: 0.75rem;
      color: var(--muted);
      display: flex;
      align-items: center;
      gap: 0.4rem;
      transition: all 0.2s;
    }

    .stat-pill span.val {
      color: var(--accent3);
      font-weight: 700;
      font-family: monospace;
      min-width: 1ch;
    }

    /* Divider */
    .divider {
      display: flex;
      align-items: center;
      gap: 1rem;
      color: var(--muted);
      font-size: 0.8rem;
    }

    .divider::before, .divider::after {
      content: '';
      flex: 1;
      height: 1px;
      background: var(--border);
    }

    .arrow-icon {
      width: 28px;
      height: 28px;
      background: linear-gradient(135deg, var(--accent), var(--accent2));
      border-radius: 50%;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 0.85rem;
      animation: pulse 2s ease-in-out infinite;
      flex-shrink: 0;
    }

    @keyframes pulse {
      0%, 100% { box-shadow: 0 0 0 0 var(--glow); }
      50% { box-shadow: 0 0 0 6px transparent; }
    }

    /* Output */
    .output-box {
      background: var(--surface2);
      border: 1.5px solid var(--border);
      border-radius: 12px;
      padding: 1rem 1.2rem;
      min-height: 56px;
      font-family: 'Courier New', monospace;
      font-size: 1.1rem;
      letter-spacing: 0.05em;
      display: flex;
      flex-wrap: wrap;
      align-items: center;
      gap: 1px;
      transition: border-color 0.3s;
      position: relative;
      overflow: hidden;
    }

    .output-box.active { border-color: var(--accent3); }

    .output-box .empty-hint {
      color: var(--muted);
      font-size: 0.9rem;
      font-style: italic;
      font-family: 'Segoe UI', system-ui, sans-serif;
    }

    /* Individual animated characters */
    .char-span {
      display: inline-block;
      position: relative;
      transition: color 0.15s;
      animation: charPop 0.25s cubic-bezier(0.34,1.56,0.64,1) both;
    }

    @keyframes charPop {
      from { opacity: 0; transform: translateY(-8px) scale(0.6); }
      to   { opacity: 1; transform: translateY(0) scale(1); }
    }

    .char-span.space-char {
      width: 0.55em;
      display: inline-block;
    }

    /* Color bands for chars */
    .char-span[data-idx="0n"] { color: #ff6ab0; }

    /* Hue cycling via CSS custom property */
    .char-span { color: var(--char-color, var(--text)); }

    /* Controls row */
    .controls {
      display: flex;
      gap: 0.75rem;
      flex-wrap: wrap;
    }

    button {
      flex: 1;
      min-width: 120px;
      padding: 0.7rem 1rem;
      border: none;
      border-radius: 10px;
      font-size: 0.85rem;
      font-weight: 700;
      cursor: pointer;
      transition: all 0.2s;
      letter-spacing: 0.04em;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 0.4rem;
    }

    #copyBtn {
      background: linear-gradient(135deg, var(--accent), #5a4fe0);
      color: #fff;
      box-shadow: 0 4px 20px rgba(124,106,255,0.3);
    }

    #copyBtn:hover { transform: translateY(-1px); box-shadow: 0 6px 24px rgba(124,106,255,0.45); }
    #copyBtn:active { transform: translateY(0); }

    #clearBtn {
      background: var(--surface2);
      color: var(--muted);
      border: 1.5px solid var(--border);
    }

    #clearBtn:hover { border-color: var(--accent2); color: var(--accent2); }

    #swapBtn {
      background: var(--surface2);
      color: var(--muted);
      border: 1.5px solid var(--border);
    }

    #swapBtn:hover { border-color: var(--accent3); color: var(--accent3); }

    /* Toast */
    .toast {
      position: fixed;
      bottom: 2rem;
      left: 50%;
      transform: translateX(-50%) translateY(20px);
      background: var(--accent3);
      color: #0f0f13;
      padding: 0.6rem 1.4rem;
      border-radius: 999px;
      font-size: 0.85rem;
      font-weight: 700;
      opacity: 0;
      pointer-events: none;
      transition: all 0.3s cubic-bezier(0.34,1.56,0.64,1);
      z-index: 100;
    }

    .toast.show {
      opacity: 1;
      transform: translateX(-50%) translateY(0);
    }

    /* Progress bar */
    .progress-bar-wrap {
      height: 3px;
      background: var(--border);
      border-radius: 999px;
      overflow: hidden;
    }

    .progress-bar {
      height: 100%;
      width: 0%;
      background: linear-gradient(90deg, var(--accent), var(--accent2), var(--accent3));
      border-radius: 999px;
      transition: width 0.15s ease;
    }

    /* Ripple on output update */
    .ripple {
      position: absolute;
      inset: 0;
      background: linear-gradient(135deg, rgba(106,255,218,0.06), transparent);
      animation: rippleFade 0.4s ease forwards;
      pointer-events: none;
    }

    @keyframes rippleFade {
      from { opacity: 1; }
      to   { opacity: 0; }
    }

    /* Responsive */
    @media (max-width: 480px) {
      .card { padding: 1.4rem; }
      button { min-width: 90px; font-size: 0.78rem; }
    }
  </style>
