  const pointerRow     = document.getElementById('pointerRow');
  const stepInfo       = document.getElementById('stepInfo');
  const startBtn       = document.getElementById('startBtn');
  const stepBtn        = document.getElementById('stepBtn');
  const resetBtn       = document.getElementById('resetBtn');
  const targetInput    = document.getElementById('targetInput');

  function buildArray() {
    arrayContainer.innerHTML = '';
    pointerRow.innerHTML = '';
    ARRAY.forEach((val, i) => {
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.id = `cell-${i}`;
      cell.innerHTML = `${val}<span class="index-label">${i}</span>`;
      arrayContainer.appendChild(cell);

      const ptr = document.createElement('div');
      ptr.className = 'pointer-cell';
      ptr.id = `ptr-${i}`;
      pointerRow.appendChild(ptr);
    });
  }

  function precomputeSteps(arr, tgt) {
    const s = [];
    let l = 0, h = arr.length - 1;
    while (l <= h) {
      const m = Math.floor((l + h) / 2);
      s.push({ lo: l, hi: h, mid: m, val: arr[m], cmp: arr[m] === tgt ? 0 : arr[m] < tgt ? -1 : 1 });
      if      (arr[m] === tgt) break;
      else if (arr[m] < tgt)   l = m + 1;
      else                      h = m - 1;
    }
    return s;
  }

  function applyStep(stepIdx, finished) {
    const step = steps[stepIdx];

    ARRAY.forEach((_, i) => {
      const cell = document.getElementById(`cell-${i}`);
      const ptr  = document.getElementById(`ptr-${i}`);
      ptr.textContent = '';
      ptr.className = 'pointer-cell';

      if (finished && step.cmp === 0 && i === step.mid) {
        cell.className = 'cell found';
      } else if (i < step.lo || i > step.hi) {
        cell.className = 'cell eliminated';
      } else if (i === step.mid) {
        cell.className = 'cell mid';
      } else {
        cell.className = 'cell in-range';
      }
    });

    // Pointer labels
    const labels = {};
    labels[step.lo]  = (labels[step.lo]  || []).concat(['lo']);
    labels[step.mid] = (labels[step.mid] || []).concat(['mid']);
    labels[step.hi]  = (labels[step.hi]  || []).concat(['hi']);

    Object.entries(labels).forEach(([idx, tags]) => {
      const ptr = document.getElementById(`ptr-${idx}`);
      const parts = tags.map(t => {
        const cls = t === 'lo' ? 'ptr-lo' : t === 'mid' ? 'ptr-mid' : 'ptr-hi';
        return `<span class="${cls}">${t === 'lo' ? '↑ lo' : t === 'mid' ? '↑ mid' : '↑ hi'}</span>`;
      });
      ptr.innerHTML = parts.join(' ');
    });

    // Info text
    let html = `Step <strong>${stepIdx + 1}</strong> of ${steps.length} &nbsp;|&nbsp; `;
    html += `<span class="lo-text">lo=${step.lo}</span>  `;
    html += `<span class="hi-text">hi=${step.hi}</span>  `;
    html += `<span class="mid-text">mid=${step.mid}</span>  `;
    html += `&nbsp;→&nbsp; arr[mid] = <strong>${step.val}</strong>`;

    if (finished) {
      if (step.cmp === 0) {
        html += `<br><span class="result-msg result-found">✓ Found ${target} at index ${step.mid}!</span>`;
      } else {
        html += `<br><span class="result-msg result-not-found">✗ ${target} is not in the array.</span>`;
      }
    } else {
      if (step.cmp < 0)       html += `<br>${step.val} &lt; ${target} → search <strong>right half</strong>`;
      else if (step.cmp > 0)  html += `<br>${step.val} &gt; ${target} → search <strong>left half</strong>`;
    }

    stepInfo.innerHTML = html;
  }

  function showNotFound() {
    ARRAY.forEach((_, i) => {
      document.getElementById(`cell-${i}`).className = 'cell eliminated';
      document.getElementById(`ptr-${i}`).textContent = '';
    });
    stepInfo.innerHTML = `<span class="result-msg result-not-found">✗ ${target} is not in the array. Search space exhausted.</span>`;
  }

  startBtn.addEventListener('click', () => {
    target = parseInt(targetInput.value, 10);
    if (isNaN(target)) { stepInfo.textContent = 'Please enter a valid number.'; return; }

    steps     = precomputeSteps(ARRAY, target);
    stepIndex = 0;
    done      = false;

    buildArray();
    stepBtn.disabled = false;
    startBtn.disabled = true;

    stepInfo.innerHTML = `Searching for <strong>${target}</strong>. Press <strong>Next Step</strong> to begin.`;
  });

  stepBtn.addEventListener('click', () => {
    if (stepIndex >= steps.length) return;

    const step     = steps[stepIndex];
    const isLast   = stepIndex === steps.length - 1;
    const finished = isLast;

    applyStep(stepIndex, finished);

    if (finished) {
      stepBtn.disabled  = true;
      startBtn.disabled = false;
      if (step.cmp !== 0) showNotFound();
    }

    stepIndex++;
  });

  resetBtn.addEventListener('click', () => {
    buildArray();
    stepBtn.disabled  = true;
    startBtn.disabled = false;
    stepInfo.innerHTML = 'Enter a target value and press <strong>Start Search</strong> to begin.';
  });

  buildArray();
</script>
</body>
</html>
```

This gives you a fully interactive binary search visualizer. Here's what it does:

- **Pre-computes all steps** upfront so navigation is instant and accurate
- **Color-coded states** — blue for active search range, amber for the current mid element, green for found, faded/shrunk for eliminated cells
- **Pointer labels** (↑ lo, ↑ mid, ↑ hi) float above the relevant boxes and animate into position each step
- **Info panel** explains exactly what happened at each step — the comparison result and which half gets searched next
- **Found / Not Found** result displayed inline with a styled badge
- Works on any screen size with horizontal scroll for the array row
- Entirely self-contained — no dependencies, no external requests

