            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 5px;
        }

        .cell {
            width: 56px;
            height: 56px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 10px;
            font-size: 1.1rem;
            font-weight: 700;
            border: 2px solid #333;
            background: #12122a;
            color: #ccc;
            transition: all 0.4s ease;
            position: relative;
        }

        .cell-index {
            font-size: 0.7rem;
            color: #555;
        }

        .cell.in-range {
            border-color: #4a90d9;
            background: #0d2340;
            color: #7ec8ff;
        }

        .cell.mid {
            border-color: #f7c948;
            background: #2a1f00;
            color: #f7c948;
            transform: scale(1.15);
            box-shadow: 0 0 18px rgba(247, 201, 72, 0.5);
            z-index: 2;
        }

        .cell.found {
            border-color: #4cff91;
            background: #002a14;
            color: #4cff91;
            transform: scale(1.2);
            box-shadow: 0 0 22px rgba(76, 255, 145, 0.6);
            animation: pulse 0.8s ease infinite alternate;
