"Bob
Newline",40,Paris,"Multi-line
field example"
Alice,35,"San Francisco, CA","Quoted, with, many, commas"
"Eve ""Hacker"" Stone",28,Berlin,Escaped quotes test`;

    function parseCSV(text) {
      const rows = [];
      let row = [];
      let field = '';
      let inQuotes = false;
      let i = 0;

      // Normalize line endings
      text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

      while (i < text.length) {
        const ch = text[i];

        if (inQuotes) {
          if (ch === '"') {
            // Peek ahead
            if (text[i + 1] === '"') {
              // Escaped quote: "" -> "
              field += '"';
              i += 2;
            } else {
              // Closing quote
              inQuotes = false;
              i++;
            }
          } else {
            field += ch;
            i++;
          }
        } else {
          if (ch === '"') {
            inQuotes = true;
            i++;
          } else if (ch === ',') {
            row.push(field);
            field = '';
            i++;
          } else if (ch === '\n') {
            row.push(field);
            field = '';
            rows.push(row);
            row = [];
            i++;
          } else {
            field += ch;
            i++;
          }
        }
      }

      // Push last field and row
      if (field !== '' || row.length > 0) {
        row.push(field);
        rows.push(row);
      }

      // Remove trailing empty row if CSV ends with newline
      if (rows.length > 0) {
        const last = rows[rows.length - 1];
        if (last.length === 1 && last[0] === '') {
          rows.pop();
        }
      }

      return rows;
    }

    function renderTable(rows) {
      const head = document.getElementById('csvHead');
      const body = document.getElementById('csvBody');
      head.innerHTML = '';
      body.innerHTML = '';

      if (rows.length === 0) return;

      const headers = rows[0];
      const colCount = Math.max(...rows.map(r => r.length));

      // Header row
      const headTr = document.createElement('tr');
      const numTh = document.createElement('th');
      numTh.textContent = '#';
      numTh.className = 'row-num';
      headTr.appendChild(numTh);
      headers.forEach(h => {
        const th = document.createElement('th');
        th.textContent = h;
        headTr.appendChild(th);
      });
      // Fill missing header columns
      for (let i = headers.length; i < colCount; i++) {
        const th = document.createElement('th');
        th.textContent = `Col ${i + 1}`;
        headTr.appendChild(th);
      }
      head.appendChild(headTr);

      // Data rows
      rows.slice(1).forEach((row, idx) => {
        const tr = document.createElement('tr');
        const numTd = document.createElement('td');
        numTd.textContent = idx + 1;
        numTd.className = 'row-num';
        tr.appendChild(numTd);
        for (let c = 0; c < colCount; c++) {
          const td = document.createElement('td');
          td.textContent = row[c] !== undefined ? row[c] : '';
          tr.appendChild(td);
        }
        body.appendChild(tr);
      });
    }

    function showError(msg) {
      const el = document.getElementById('error');
      el.textContent = msg;
      el.style.display = 'block';
      document.getElementById('info').style.display = 'none';
      document.getElementById('tableContainer').style.display = 'none';
    }

    function showInfo(msg) {
      const el = document.getElementById('info');
      el.textContent = msg;
      el.style.display = 'block';
      document.getElementById('error').style.display = 'none';
    }

    document.getElementById('parseBtn').addEventListener('click', () => {
      const raw = document.getElementById('csvInput').value.trim();
      if (!raw) {
        showError('Please paste some CSV data first.');
        return;
      }

      try {
        const rows = parseCSV(raw);
        if (rows.length === 0) {
          showError('No data found.');
          return;
        }
        renderTable(rows);
        document.getElementById('tableContainer').style.display = 'block';
        showInfo(`Parsed ${rows.length - 1} data row(s) with ${rows[0].length} column(s).`);
      } catch (e) {
        showError('Parse error: ' + e.message);
      }
    });

    document.getElementById('clearBtn').addEventListener('click', () => {
      document.getElementById('csvInput').value = '';
      document.getElementById('error').style.display = 'none';
      document.getElementById('info').style.display = 'none';
      document.getElementById('tableContainer').style.display = 'none';
    });

    document.getElementById('loadSampleBtn').addEventListener('click', () => {
      document.getElementById('csvInput').value = SAMPLE;
    });
  </script>

