<script>
    // ─── Data Structure ───────────────────────────────────────────────────────
    class Node {
        constructor(val) {
            this.val = val;
            this.next = null;
        }
    }

    class LinkedList {
        constructor() {
            this.head = null;
            this.size = 0;
        }

        insertHead(val) {
            const node = new Node(val);
            node.next = this.head;
            this.head = node;
            this.size++;
        }

        insertTail(val) {
            const node = new Node(val);
            if (!this.head) {
                this.head = node;
            } else {
                let cur = this.head;
                while (cur.next) cur = cur.next;
                cur.next = node;
            }
            this.size++;
        }

        delete(val) {
            if (!this.head) return false;
            if (this.head.val === val) {
                this.head = this.head.next;
                this.size--;
                return true;
            }
            let cur = this.head;
            while (cur.next) {
                if (cur.next.val === val) {
                    cur.next = cur.next.next;
                    this.size--;
                    return true;
                }
                cur = cur.next;
            }
            return false;
        }

        search(val) {
            let cur = this.head, idx = 0;
            while (cur) {
                if (cur.val === val) return idx;
                cur = cur.next;
                idx++;
            }
            return -1;
        }

        toArray() {
            const arr = [];
            let cur = this.head;
            while (cur) { arr.push(cur.val); cur = cur.next; }
            return arr;
        }

        getTail() {
            if (!this.head) return null;
            let cur = this.head;
            while (cur.next) cur = cur.next;
            return cur.val;
        }

        clear() {
            this.head = null;
            this.size = 0;
        }
    }

    // ─── State ────────────────────────────────────────────────────────────────
    const ll = new LinkedList();
    let highlightedIndex = -1;
    let animatingNodes = new Set(); // indices of newly added nodes
    let nodeAnimProgress = {}; // index -> 0..1

    // ─── Canvas Setup ─────────────────────────────────────────────────────────
    const canvas = document.getElementById('llCanvas');
    const ctx = canvas.getContext('2d');

    const NODE_W = 80;
    const NODE_H = 56;
    const ARROW_GAP = 48;
    const PADDING = 40;
    const ROW_H = 120;
    const NODES_PER_ROW = Math.floor((window.innerWidth - 80) / (NODE_W + ARROW_GAP)) || 6;

    function getCanvasSize(count) {
        if (count === 0) return { w: 400, h: 180 };
        const rows = Math.ceil(count / NODES_PER_ROW);
        const cols = Math.min(count, NODES_PER_ROW);
        const w = Math.max(400, cols * (NODE_W + ARROW_GAP) + PADDING * 2);
        const h = rows * ROW_H + PADDING * 2;
        return { w, h };
    }

    // ─── Drawing Helpers ──────────────────────────────────────────────────────
    function roundRect(ctx, x, y, w, h, r) {
        ctx.beginPath();
        ctx.moveTo(x + r, y);
        ctx.lineTo(x + w - r, y);
        ctx.quadraticCurveTo(x + w, y, x + w, y + r);
        ctx.lineTo(x + w, y + h - r);
        ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
        ctx.lineTo(x + r, y + h);
        ctx.quadraticCurveTo(x, y + h, x, y + h - r);
        ctx.lineTo(x, y + r);
        ctx.quadraticCurveTo(x, y, x + r, y);
        ctx.closePath();
    }

    function drawArrow(ctx, x1, y1, x2, y2, color) {
        const headLen = 10;
        const angle = Math.atan2(y2 - y1, x2 - x1);
        ctx.save();
        ctx.strokeStyle = color;
        ctx.fillStyle = color;
        ctx.lineWidth = 2.5;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(x2, y2);
        ctx.lineTo(x2 - headLen * Math.cos(angle - Math.PI / 6), y2 - headLen * Math.sin(angle - Math.PI / 6));
        ctx.lineTo(x2 - headLen * Math.cos(angle + Math.PI / 6), y2 - headLen * Math.sin(angle + Math.PI / 6));
        ctx.closePath();
        ctx.fill();
        ctx.restore();
    }

    function getNodePos(index) {
        const row = Math.floor(index / NODES_PER_ROW);
        const col = index % NODES_PER_ROW;
        // Alternate row direction (snake layout)
        const rowLen = Math.min(NODES_PER_ROW, ll.size - row * NODES_PER_ROW);
        const actualCol = (row % 2 === 0) ? col : (rowLen - 1 - col);
        const x = PADDING + actualCol * (NODE_W + ARROW_GAP) + NODE_W / 2;
        const y = PADDING + row * ROW_H + NODE_H / 2;
        return { x, y };
    }

    // ─── Main Draw ────────────────────────────────────────────────────────────
    function draw() {
        const arr = ll.toArray();
        const { w, h } = getCanvasSize(arr.length);
        canvas.width = w;
        canvas.height = h;

        // Background
        ctx.clearRect(0, 0, w, h);

        if (arr.length === 0) {
            drawEmptyState(w, h);
            return;
        }

        // Draw arrows first (behind nodes)
        for (let i = 0; i < arr.length - 1; i++) {
            const pos = getNodePos(i);
            const nextPos = getNodePos(i + 1);
            const row = Math.floor(i / NODES_PER_ROW);
            const nextRow = Math.floor((i + 1) / NODES_PER_ROW);

            const scale = nodeAnimProgress[i] !== undefined ? nodeAnimProgress[i] : 1;
            const nextScale = nodeAnimProgress[i + 1] !== undefined ? nodeAnimProgress[i + 1] : 1;
            if (scale < 0.5 || nextScale < 0.5) continue;

            const arrowColor = 'rgba(148,163,184,0.6)';

            if (row === nextRow) {
                // Same row: horizontal arrow
                const fromX = pos.x + NODE_W / 2;
                const toX = nextPos.x - NODE_W / 2;
                drawArrow(ctx, fromX, pos.y, toX, nextPos.y, arrowColor);
            } else {
                // Row wrap: draw a bent arrow going down
                const fromX = pos.x + (row % 2 === 0 ? NODE_W / 2 : -NODE_W / 2);
                const fromY = pos.y;
                const midY = pos.y + ROW_H / 2;
                const toX = nextPos.x + (nextRow % 2 === 0 ? -NODE_W / 2 : NODE_W / 2);
                const toY = nextPos.y;

                ctx.save();
                ctx.strokeStyle = arrowColor;
                ctx.lineWidth = 2.5;
                ctx.setLineDash([5, 4]);
                ctx.beginPath();
                ctx.moveTo(fromX, fromY);
                ctx.lineTo(fromX, midY);
                ctx.lineTo(toX, midY);
                ctx.lineTo(toX, toY - 6);
                ctx.stroke();
                ctx.setLineDash([]);
                ctx.restore();
                // Arrowhead
                drawArrow(ctx, toX, toY - 14, toX, toY - 2, arrowColor);
            }
        }

        // NULL indicator after last node
        if (arr.length > 0) {
            const lastPos = getNodePos(arr.length - 1);
            const row = Math.floor((arr.length - 1) / NODES_PER_ROW);
            const nullX = lastPos.x + (row % 2 === 0 ? NODE_W / 2 + 30 : -NODE_W / 2 - 30);
            const nullY = lastPos.y;
            const scale = nodeAnimProgress[arr.length - 1] !== undefined ? nodeAnimProgress[arr.length - 1] : 1;
            if (scale > 0.7) {
                drawArrow(ctx,
                    lastPos.x + (row % 2 === 0 ? NODE_W / 2 : -NODE_W / 2),
                    nullY,
                    nullX + (row % 2 === 0 ? -8 : 8),
                    nullY,
                    'rgba(148,163,184,0.5)'
                );
                ctx.save();
                ctx.font = 'bold 11px monospace';
                ctx.fillStyle = 'rgba(148,163,184,0.7)';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText('NULL', nullX, nullY);
                ctx.restore();
            }
        }

        // Draw nodes
        for (let i = 0; i < arr.length; i++) {
            drawNode(arr[i], i, arr.length);
        }

        updateStats(arr);
    }

    function drawNode(val, index, total) {
        const pos = getNodePos(index);
        const x = pos.x - NODE_W / 2;
        const y = pos.y - NODE_H / 2;

        const scale = nodeAnimProgress[index] !== undefined ? nodeAnimProgress[index] : 1;
        const isHighlighted = index === highlightedIndex;
        const isHead = index === 0;
        const isTail = index === total - 1;

        ctx.save();
        ctx.translate(pos.x, pos.y);
        ctx.scale(scale, scale);
        ctx.translate(-pos.x, -pos.y);

        // Shadow
        ctx.shadowColor = isHighlighted ? 'rgba(52,211,153,0.5)' :
            isHead ? 'rgba(251,113,133,0.4)' :
                isTail ? 'rgba(56,189,248,0.4)' : 'rgba(139,92,246,0.3)';
        ctx.shadowBlur = isHighlighted ? 20 : 12;

        // Gradient fill
        let grad;
        if (isHighlighted) {
            grad = ctx.createLinearGradient(x, y, x + NODE_W, y + NODE_H);
            grad.addColorStop(0, '#065f46');
            grad.addColorStop(1, '#34d399');
        } else if (isHead) {
            grad = ctx.createLinearGradient(x, y, x + NODE_W, y + NODE_H);
            grad.addColorStop(0, '#be123c');
            grad.addColorStop(1, '#fb7185');
        } else if (isTail) {
            grad = ctx.createLinearGradient(x, y, x + NODE_W, y + NODE_H);
            grad.addColorStop(0, '#0369a1');
            grad.addColorStop(1, '#38bdf8');
        } else {
            grad = ctx.createLinearGradient(x, y, x + NODE_W, y + NODE_H);
            grad.addColorStop(0, '#7c3aed');
            grad.addColorStop(1, '#a78bfa');
        }

        roundRect(ctx, x, y, NODE_W, NODE_H, 10);
        ctx.fillStyle = grad;
        ctx.fill();

        // Border
        ctx.shadowBlur = 0;
        roundRect(ctx, x, y, NODE_W, NODE_H, 10);
        ctx.strokeStyle = isHighlighted ? 'rgba(110,231,183,0.8)' : 'rgba(255,255,255,0.2)';
        ctx.lineWidth = isHighlighted ? 2.5 : 1.5;
        ctx.stroke();

        // Value text
        ctx.fillStyle = '#fff';
        ctx.font = `bold ${val.toString().length > 4 ? '13' : '18'}px 'Segoe UI', sans-serif`;
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.shadowColor = 'rgba(0,0,0,0.4)';
        ctx.shadowBlur = 4;
        ctx.fillText(val, pos.x, pos.y - 4);

        // Label below value
        ctx.shadowBlur = 0;
        ctx.font = '9px monospace';
        ctx.fillStyle = 'rgba(255,255,255,0.55)';
        const label = isHead && isTail ? 'HEAD · TAIL' : isHead ? 'HEAD' : isTail ? 'TAIL' : `[${index}]`;
        ctx.fillText(label, pos.x, pos.y + 14);

        ctx.restore();

        // Highlighted pulse ring
        if (isHighlighted) {
            ctx.save();
            ctx.strokeStyle = 'rgba(52,211,153,0.35)';
            ctx.lineWidth = 3;
            roundRect(ctx, x - 5, y - 5, NODE_W + 10, NODE_H + 10, 14);
            ctx.stroke();
            ctx.restore();
        }
    }

    function drawEmptyState(w, h) {
        ctx.save();
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';

        // Icon
        ctx.font = '48px serif';
        ctx.fillText('🔗', w / 2, h / 2 - 28);

        ctx.font = 'bold 16px Segoe UI';
        ctx.fillStyle = 'rgba(148,163,184,0.8)';
        ctx.fillText('The list is empty', w / 2, h / 2 + 20);

        ctx.font = '12px Segoe UI';
        ctx.fillStyle = 'rgba(100,116,139,0.7)';
        ctx.fillText('Use the controls above to insert nodes', w / 2, h / 2 + 44);
        ctx.restore();
    }

    // ─── Animation ────────────────────────────────────────────────────────────
    function animateNewNode(index) {
        nodeAnimProgress[index] = 0;
        let start = null;
        const duration = 350;

        function step(ts) {
            if (!start) start = ts;
            const t = Math.min((ts - start) / duration, 1);
            // Ease out elastic-ish
            nodeAnimProgress[index] = t < 1 ? easeOutBack(t) : 1;
            draw();
            if (t < 1) requestAnimationFrame(step);
            else {
                delete nodeAnimProgress[index];
                draw();
            }
        }
        requestAnimationFrame(step);
    }

    function easeOutBack(t) {
        const c1 = 1.70158, c3 = c1 + 1;
        return 1 + c3 * Math.pow(t - 1, 3) + c1 * Math.pow(t - 1, 2);
    }

    // ─── Message ──────────────────────────────────────────────────────────────
    let msgTimer = null;
    function showMessage(text, type = 'info') {
        const box = document.getElementById('messageBox');
        box.innerHTML = `<span class="msg ${type}">${text}</span>`;
        if (msgTimer) clearTimeout(msgTimer);
        msgTimer = setTimeout(() => box.innerHTML = '', 3000);
    }

    // ─── Stats ────────────────────────────────────────────────────────────────
    function updateStats(arr) {
        document.getElementById('statSize').textContent = arr.length;
        document.getElementById('statHead').textContent = arr.length ? arr[0] : '—';
        document.getElementById('statTail').textContent = arr.length ? arr[arr.length - 1] : '—';
    }

    // ─── Controls ─────────────────────────────────────────────────────────────
    function getVal(id) {
        const v = document.getElementById(id).value.trim();
        if (v === '') return null;
        return parseInt(v, 10);
    }

    function clearInput(id) {
        document.getElementById(id).value = '';
    }

    function insertHead() {
        const val = getVal('headVal');
        if (val === null || isNaN(val)) { showMessage('Please enter a valid number.', 'error'); return; }
        ll.insertHead(val);
        highlightedIndex = -1;
        // Shift existing animation indices
        const newProgress = {};
        for (const k in nodeAnimProgress) newProgress[parseInt(k) + 1] = nodeAnimProgress[k];
        Object.assign(nodeAnimProgress, newProgress);
        clearInput('headVal');
        animateNewNode(0);
        showMessage(`Inserted <b>${val}</b> at head.`, 'success');
    }

    function insertTail() {
        const val = getVal('tailVal');
        if (val === null || isNaN(val)) { showMessage('Please enter a valid number.', 'error'); return; }
        const idx = ll.size; // will be the new tail index
        ll.insertTail(val);
        highlightedIndex = -1;
        clearInput('tailVal');
        animateNewNode(idx);
        showMessage(`Inserted <b>${val}</b> at tail.`, 'success');
    }

    function deleteNode() {
        const val = getVal('delVal');
        if (val === null || isNaN(val)) { showMessage('Please enter a valid number.', 'error'); return; }
        const found = ll.delete(val);
        highlightedIndex = -1;
        clearInput('delVal');
        if (found) {
            showMessage(`Deleted node with value <b>${val}</b>.`, 'success');
        } else {
            showMessage(`Value <b>${val}</b> not found in the list.`, 'error');
        }
        draw();
    }

    function searchNode() {
        const val = getVal('searchVal');
        if (val === null || isNaN(val)) { showMessage('Please enter a valid number.', 'error'); return; }
        const idx = ll.search(val);
        clearInput('searchVal');
        if (idx !== -1) {
            highlightedIndex = idx;
            showMessage(`Found <b>${val}</b> at index <b>${idx}</b>! 🎉`, 'success');
            draw();
            // Auto-clear highlight after 2.5s
            setTimeout(() => { highlightedIndex = -1; draw(); }, 2500);
        } else {
            highlightedIndex = -1;
            showMessage(`Value <b>${val}</b> not found in the list.`, 'error');
            draw();
        }
    }

    function clearList() {
        ll.clear();
        highlightedIndex = -1;
        nodeAnimProgress = {};
        draw();
        showMessage('List cleared.', 'info');
    }

    // ─── Keyboard Shortcuts ───────────────────────────────────────────────────
    document.addEventListener('keydown', e => {
        if (e.target.tagName === 'INPUT') {
            if (e.key === 'Enter') {
                const id = e.target.id;
                if (id === 'headVal') insertHead();
                else if (id === 'tailVal') insertTail();
                else if (id === 'delVal') deleteNode();
                else if (id === 'searchVal') searchNode();
            }
        }
    });

    // ─── Init ─────────────────────────────────────────────────────────────────
    // Seed with a few nodes for demo
    [10, 25, 37, 42, 58].forEach(v => ll.insertTail(v));
    draw();
</script>
</body>
</html>
```

## Features

Here's what's packed into this single file:

### 🎨 Visual Design
- **Dark gradient background** with glassmorphism control panels
- **Color-coded nodes**: Red = Head, Blue = Tail, Green = Found, Purple = Normal
- **Snake/wrap layout** for long lists — nodes flow across rows with bent dashed arrows connecting rows
- **NULL terminator** shown after the last node

### ⚙️ Operations
| Control | Action |
|---|---|
| **Insert Head** | Adds node at the front |
| **Insert Tail** | Appends node at the end |
| **Delete** | Removes first node matching the value |
| **Search** | Highlights the found node in green for 2.5s |
| **Clear All** | Wipes the entire list |

### ✨ Extra Polish
- **Bounce-in animation** when inserting new nodes (ease-out-back easing)
- **Pulse ring** around the highlighted/found node
- **Live stats bar** showing node count, head value, and tail value
- **Status messages** with color-coded success/error/info states
- **⏎ Enter key** works on all inputs
- **Seeded with demo data** (5 nodes) so it's not empty on load

Here's a self-contained HTML file that handles all your requirements:

