        if (ch === '"') {
          // Peek at next character
          if (i + 1 < text.length && text[i + 1] === '"') {
            // Escaped quote ("")
            field += '"';
            i += 2;
          } else {
            // Closing quote
            inQuotes = false;
            i++;
          }
        } else {
          field += ch;
          i++;
        }
      } else {
        if (ch === '"') {
          inQuotes = true;
          i++;
        } else if (ch === delimiter) {
          row.push(field);
          field = '';
          i++;
        } else if (ch === '\n') {
          row.push(field);
          field = '';
          rows.push(row);
          row = [];
          i++;
        } else {
          field += ch;
          i++;
        }
      }
    }

    // Push the last field and row (handles files without trailing newline)
    row.push(field);
    if (row.some(f => f !== '') || rows.length === 0) {
      rows.push(row);
    }

    // Remove completely empty trailing rows
    while (rows.length && rows[rows.length - 1].every(f => f === '')) {
      rows.pop();
    }

    return rows;
  }

  /* ── Auto-detect delimiter ──────────────────────────────────────────────── */
  function detectDelimiter(text) {
    const candidates = [',', ';', '\t', '|'];
    const firstLine = text.split(/\r?\n/)[0];
    let best = ',';
    let bestCount = 0;
    for (const d of candidates) {
      // Simple count outside quotes
      let count = 0, inQ = false;
      for (const ch of firstLine) {
        if (ch === '"') inQ = !inQ;
        else if (!inQ && ch === d) count++;
      }
      if (count > bestCount) { bestCount = count; best = d; }
    }
    return best;
  }

  /* ── Build HTML Table ───────────────────────────────────────────────────── */
  function buildTable(rows, { firstRowHeader, trimWhitespace, showRowNumbers }) {
    if (rows.length === 0) return null;

    // Trim whitespace if requested
    if (trimWhitespace) {
      rows = rows.map(r => r.map(f => f.trim()));
    }

    // Determine max column count
    const maxCols = Math.max(...rows.map(r => r.length));

    // Pad rows with fewer columns
    rows = rows.map(r => {
      while (r.length < maxCols) r.push('');
      return r;
    });

    const table = document.createElement('table');
    const thead = document.createElement('thead');
    const tbody = document.createElement('tbody');

    const headerRow = document.createElement('tr');

    // Row-number header cell
    if (showRowNumbers) {
      const rh = document.createElement('th');
      rh.className = 'row-num-header';
      rh.textContent = '#';
      headerRow.appendChild(rh);
    }

    const headerData = firstRowHeader ? rows[0] : rows[0].map((_, i) => `Column ${i + 1}`);
    headerData.forEach(text => {
      const th = document.createElement('th');
      th.textContent = text;
      headerRow.appendChild(th);
    });
    thead.appendChild(headerRow);
    table.appendChild(thead);

    const dataRows = firstRowHeader ? rows.slice(1) : rows;
    dataRows.forEach((cols, rowIdx) => {
      const tr = document.createElement('tr');

      if (showRowNumbers) {
        const rn = document.createElement('td');
        rn.className = 'row-num';
        rn.textContent = rowIdx + 1;
        tr.appendChild(rn);
      }

      cols.forEach(val => {
        const td = document.createElement('td');
        if (val === '') {
          td.innerHTML = '<span class="cell-empty">—</span>';
        } else {
          td.textContent = val;
        }
        tr.appendChild(td);
      });
      tbody.appendChild(tr);
    });

    table.appendChild(tbody);
    return { table, rowCount: dataRows.length, colCount: maxCols };
  }

  /* ── Main parse handler ─────────────────────────────────────────────────── */
  function handleParse() {
    const raw = document.getElementById('csvInput').value;
    const errorBox = document.getElementById('errorBox');
    const output = document.getElementById('output');
    const stats = document.getElementById('stats');

    errorBox.style.display = 'none';
    errorBox.textContent = '';
    output.innerHTML = '';
    stats.textContent = '';

    if (!raw.trim()) {
      showError('Please paste some CSV data first.');
      return;
    }

    let delimiter = document.getElementById('delimiter').value;
    if (delimiter === 'auto') delimiter = detectDelimiter(raw);

    let rows;
    try {
      rows = parseCSV(raw, delimiter);
    } catch (e) {
      showError('Parsing error: ' + e.message);
      return;
    }

    if (rows.length === 0) {
      showError('No data found. Please check your input.');
      return;
    }

    const options = {
      firstRowHeader: document.getElementById('firstRowHeader').checked,
      trimWhitespace: document.getElementById('trimWhitespace').checked,
      showRowNumbers: document.getElementById('showRowNumbers').checked,
    };

    const result = buildTable(rows, options);
    if (!result) {
      showError('Could not build table from the provided data.');
      return;
    }

    const wrapper = document.createElement('div');
    wrapper.className = 'table-wrapper';
    wrapper.appendChild(result.table);
    output.appendChild(wrapper);

    const delimLabel = delimiter === '\t' ? 'Tab' : `"${delimiter}"`;
    stats.textContent =
      `✅ Parsed ${result.rowCount} data row(s) × ${result.colCount} column(s) — delimiter: ${delimLabel}`;

    output.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }

  function showError(msg) {
    const errorBox = document.getElementById('errorBox');
    errorBox.textContent = msg;
    errorBox.style.display = 'block';
  }

  /* ── Sample data ────────────────────────────────────────────────────────── */
  const SAMPLE = `name,age,city,occupation,notes
"Smith, John",30,"New York",Engineer,"Loves ""coffee"" and coding"
Jane Doe,25,London,Designer,
"O'Brien, Pat",42,"San Francisco",Manager,"Works on ""AI"" projects"
李明,28,Beijing,Researcher,Specialises in NLP
,,,Incomplete Row,Missing first three fields
Maria García,35,"São Paulo",Analyst,"Enjoys hiking, cycling, and travel"`;

  document.getElementById('sampleBtn').addEventListener('click', () => {
    document.getElementById('csvInput').value = SAMPLE;
    document.getElementById('delimiter').value = 'auto';
    document.getElementById('firstRowHeader').checked = true;
    document.getElementById('trimWhitespace').checked = true;
    document.getElementById('showRowNumbers').checked = true;
  });

  document.getElementById('parseBtn').addEventListener('click', handleParse);

  document.getElementById('clearBtn').addEventListener('click', () => {
    document.getElementById('csvInput').value = '';
    document.getElementById('output').innerHTML = '';
    document.getElementById('stats').textContent = '';
    document.getElementById('errorBox').style.display = 'none';
  });

  // Allow Ctrl+Enter to parse
  document.getElementById('csvInput').addEventListener('keydown', e => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') handleParse();
  });
</script>
</body>
</html>
```

---

### What's included

| Feature | Detail |
|---|---|
| **CSV Parser** | Hand-written state-machine handles quoted fields, embedded commas, and `""` escaped quotes correctly |
| **Auto-detect delimiter** | Scans the first line for `,` `;` `\t` `\|` and picks the most frequent |
| **Ragged rows** | Rows with fewer columns are padded so the table stays rectangular |
| **Options** | First-row-as-header toggle, whitespace trimming, row-number column, manual delimiter override |
| **Styled table** | Dark header, alternating `odd/even` row colours, hover highlight, responsive horizontal scroll |
| **Empty cells** | Displayed as a muted `—` so structure is always visible |
| **Sample data** | Covers quoted commas, escaped quotes, Unicode, and intentionally incomplete rows |
| **Keyboard shortcut** | `Ctrl / ⌘ + Enter` triggers parsing from the textarea |

