<script>
  // ─── CSV Parser ───────────────────────────────────────────────────────────────
  // Fully RFC-4180 compliant parser supporting:
  //   • Quoted fields (may contain delimiter, newlines, escaped quotes)
  //   • Escaped double-quotes ("")
  //   • Varying column counts per row
  //   • CRLF and LF line endings

  function parseCSVText(text, delimiter) {
    const rows = [];
    let row = [];
    let i = 0;
    const len = text.length;

    while (i < len) {
      // ── Quoted field ──────────────────────────────────────────────────────
      if (text[i] === '"') {
        i++; // skip opening quote
        let field = '';
        while (i < len) {
          if (text[i] === '"') {
            if (i + 1 < len && text[i + 1] === '"') {
              // Escaped quote: "" → "
              field += '"';
              i += 2;
            } else {
              // Closing quote
              i++;
              break;
            }
          } else {
            field += text[i];
            i++;
          }
        }
        row.push(field);

        // After closing quote, expect delimiter or newline
        if (i < len && text[i] === delimiter) {
          i++;
          // If delimiter is the last char on line, push empty field next iteration
        }
      }
      // ── Newline ───────────────────────────────────────────────────────────
      else if (text[i] === '\r' || text[i] === '\n') {
        // Handle CRLF
        if (text[i] === '\r' && i + 1 < len && text[i + 1] === '\n') {
          i++;
        }
        i++;
        rows.push(row);
        row = [];
      }
      // ── Delimiter (empty field) ───────────────────────────────────────────
      else if (text[i] === delimiter) {
        row.push('');
        i++;
        // If next char is also delimiter or newline, we already pushed empty
        // and the loop will handle the next field correctly
      }
      // ── Unquoted field ────────────────────────────────────────────────────
      else {
        let field = '';
        while (i < len && text[i] !== delimiter && text[i] !== '\r' && text[i] !== '\n') {
          field += text[i];
          i++;
        }
        row.push(field);
        if (i < len && text[i] === delimiter) {
          i++; // consume delimiter; next iteration handles next field
        }
      }
    }

    // Push final row if non-empty
    if (row.length > 0) {
      rows.push(row);
    }

    return rows;
  }

  // ─── Main Parse & Render ──────────────────────────────────────────────────────
  function parseCSV() {
    const raw = document.getElementById('csvInput').value;
    const delimiter = document.getElementById('delimiterSelect').value;
    const firstRowHeader = document.getElementById('firstRowHeader').checked;
    const showRowNumbers = document.getElementById('showRowNumbers').checked;
    const trimWS = document.getElementById('trimWhitespace').checked;

    hideMessage();

    if (!raw.trim()) {
      showMessage('Please paste some CSV data first.', 'error');
      return;
    }

    let rows = parseCSVText(raw, delimiter);

    // Trim whitespace from each cell if requested
    if (trimWS) {
      rows = rows.map(row => row.map(cell => cell.trim()));
    }

    // Remove completely empty trailing rows
    while (rows.length > 0 && rows[rows.length - 1].every(c => c === '')) {
      rows.pop();
    }

    if (rows.length === 0) {
      showMessage('No data found after parsing.', 'error');
      return;
    }

    // Determine max column count across all rows
    const maxCols = Math.max(...rows.map(r => r.length));

    let headers = [];
    let dataRows = rows;

    if (firstRowHeader && rows.length > 0) {
      headers = rows[0];
      dataRows = rows.slice(1);
    }

    // Pad headers to maxCols
    while (headers.length < maxCols) {
      headers.push('');
    }

    renderTable(headers, dataRows, maxCols, firstRowHeader, showRowNumbers);

    const totalRows = dataRows.length;
    const totalCols = maxCols;
    showMessage(
      `✅ Parsed successfully: ${totalRows} data row${totalRows !== 1 ? 's' : ''}, ${totalCols} column${totalCols !== 1 ? 's' : ''}.`,
      'info'
    );
  }

  function renderTable(headers, dataRows, maxCols, hasHeader, showRowNumbers) {
    const thead = document.getElementById('tableHead');
    const tbody = document.getElementById('tableBody');
    thead.innerHTML = '';
    tbody.innerHTML = '';

    // ── Header row ────────────────────────────────────────────────────────────
    const headTr = document.createElement('tr');

    if (showRowNumbers) {
      const th = document.createElement('th');
      th.className = 'row-num-header';
      th.textContent = '#';
      headTr.appendChild(th);
    }

    for (let c = 0; c < maxCols; c++) {
      const th = document.createElement('th');
      if (hasHeader) {
        const label = headers[c] !== undefined && headers[c] !== '' ? headers[c] : `Column ${c + 1}`;
        th.innerHTML = escapeHtml(label) + `<span class="col-index">col ${c + 1}</span>`;
      } else {
        th.innerHTML = `Column ${c + 1}<span class="col-index">col ${c + 1}</span>`;
      }
      headTr.appendChild(th);
    }
    thead.appendChild(headTr);

    // ── Data rows ─────────────────────────────────────────────────────────────
    if (dataRows.length === 0) {
      const tr = document.createElement('tr');
      const td = document.createElement('td');
      td.colSpan = maxCols + (showRowNumbers ? 1 : 0);
      td.style.textAlign = 'center';
      td.style.color = '#aaa';
      td.style.padding = '20px';
      td.textContent = '(No data rows)';
      tr.appendChild(td);
      tbody.appendChild(tr);
    } else {
      dataRows.forEach((row, rowIdx) => {
        const tr = document.createElement('tr');
        const isMismatched = row.length !== maxCols;

        if (showRowNumbers) {
          const td = document.createElement('td');
          td.className = 'row-num';
          td.textContent = rowIdx + 1;
          tr.appendChild(td);
        }

        for (let c = 0; c < maxCols; c++) {
          const td = document.createElement('td');
          const cellVal = row[c];

          if (cellVal === undefined) {
            // Column count mismatch — highlight cell
            td.className = 'empty-cell mismatched';
            td.textContent = '—';
            td.title = 'Missing field (row has fewer columns than expected)';
          } else if (cellVal === '') {
            td.className = 'empty-cell';
            td.textContent = '(empty)';
          } else {
            td.textContent = cellVal;
            if (isMismatched && c >= row.length) {
              td.classList.add('mismatched');
            }
          }
          tr.appendChild(td);
        }
        tbody.appendChild(tr);
      });
    }

    // Show table, hide empty state
    document.getElementById('emptyState').style.display = 'none';
    document.getElementById('tableContainer').style.display = 'block';
    document.getElementById('tableMeta').textContent =
      `${dataRows.length} row${dataRows.length !== 1 ? 's' : ''} × ${maxCols} column${maxCols !== 1 ? 's' : ''}`;
  }

  // ─── Helpers ──────────────────────────────────────────────────────────────────
  function escapeHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function showMessage(text, type) {
    const el = document.getElementById('message');
    el.textContent = text;
    el.className = 'message ' + type;
  }

  function hideMessage() {
    const el = document.getElementById('message');
    el.className = 'message';
    el.textContent = '';
  }

  function clearAll() {
    document.getElementById('csvInput').value = '';
    document.getElementById('tableHead').innerHTML = '';
    document.getElementById('tableBody').innerHTML = '';
    document.getElementById('tableContainer').style.display = 'none';
    document.getElementById('emptyState').style.display = 'block';
    hideMessage();
  }

  function loadSample() {
    document.getElementById('csvInput').value =
`Name,Age,City,Occupation,Notes
"Smith, John",30,New York,Engineer,"Loves ""coding"" and coffee"
"Jane ""JJ"" Doe",25,London,Designer,
Bob,42,Sydney,Manager,"Manages a team of 10"
Alice,28,Toronto,Developer,"Enjoys hiking
and outdoor activities"
Charlie,,Berlin,Analyst,"Missing age above"
"Extra, Comma, Test",35,Paris,Chef,"Has, multiple, commas"`;
    hideMessage();
  }

  // Allow Ctrl+Enter to parse
  document.getElementById('csvInput').addEventListener('keydown', function(e) {
    if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
      parseCSV();
    }
  });
</script>
</body>
</html>
```

