        </div>
        <div class="stats">
            <span>Comparisons: <strong id="cmp-merge">0</strong></span>
            <span>Swaps: <strong id="swp-merge">0</strong></span>
        </div>
        <div class="chart-area" id="chart-merge">
            <div class="done-overlay" id="done-merge" style="background:#6bcb7718;color:#6bcb77">✓ Done</div>
