<!-- Complexity Reference -->
<div class="complexity-section">
    <h2>📊 Time &amp; Space Complexity Reference</h2>
    <table>
        <thead>
            <tr>
                <th>Algorithm</th>
                <th>Best Case</th>
                <th>Average Case</th>
                <th>Worst Case</th>
                <th>Space</th>
                <th>Notes</th>
            </tr>
        </thead>
        <tbody>
            <tr>
                <td><span style="color:#ff6b6b;font-weight:700">Bubble Sort</span></td>
                <td class="complexity-ok">O(n)</td>
                <td class="complexity-bad">O(n²)</td>
                <td class="complexity-bad">O(n²)</td>
                <td class="complexity-good">O(1)</td>
                <td>Simple but slow. Useful only for nearly-sorted tiny arrays. Each pass "bubbles" the largest unsorted element to its correct position.</td>
            </tr>
            <tr>
                <td><span style="color:#6bcb77;font-weight:700">Merge Sort</span> <span class="winner-tag">★ Stable</span></td>
                <td class="complexity-good">O(n log n)</td>
                <td class="complexity-good">O(n log n)</td>
                <td class="complexity-good">O(n log n)</td>
                <td class="complexity-ok">O(n)</td>
                <td>Divide-and-conquer. Guaranteed O(n log n) in all cases. Stable sort — preserves order of equal elements. Great for linked lists and external sorting.</td>
            </tr>
            <tr>
                <td><span style="color:#4d96ff;font-weight:700">Quick Sort</span> <span class="winner-tag">★ Fast in practice</span></td>
                <td class="complexity-good">O(n log n)</td>
                <td class="complexity-good">O(n log n)</td>
                <td class="complexity-bad">O(n²)*</td>
                <td class="complexity-good">O(log n)</td>
                <td>Divide-and-conquer with a pivot. Extremely fast in practice due to cache efficiency. Worst case avoided with randomized pivot. Used in most standard libraries.</td>
            </tr>
        </tbody>
    </table>
    <p style="font-size:0.78rem;color:#666;margin-top:12px">
        * Quick Sort worst case O(n²) occurs with already-sorted data and a naive pivot — randomized pivot selection makes this astronomically unlikely in practice.
    </p>
</div>

<script>
    // ─── State ────────────────────────────────────────────────────────────────
    let originalArray = [];
    let running = false;

    const sizeSlider  = document.getElementById('sizeSlider');
    const speedSlider = document.getElementById('speedSlider');
    const sizeVal     = document.getElementById('sizeVal');
    const speedVal    = document.getElementById('speedVal');
    const btnGenerate = document.getElementById('btnGenerate');
    const btnSort     = document.getElementById('btnSort');
    const btnReset    = document.getElementById('btnReset');

    // ─── Helpers ──────────────────────────────────────────────────────────────
    function getDelay() {
        // speed 1 = 300ms, speed 10 = 5ms
        const s = parseInt(speedSlider.value);
        return Math.round(305 - s * 30);
    }

    function sleep(ms) {
        return new Promise(r => setTimeout(r, ms));
    }

    function randomArray(n) {
        return Array.from({ length: n }, () => Math.floor(Math.random() * 90) + 10);
    }

    // ─── Bar rendering ────────────────────────────────────────────────────────
    const COLORS = {
        default:  '#3a3a6a',
        compare:  '#ffd93d',
        swap:     '#ff6b6b',
        pivot:    '#ff9f43',
        sorted:   null,          // set per-algorithm
        merge:    '#a29bfe',
    };

    const SORTED_COLORS = {
        bubble: '#ff6b6b',
        merge:  '#6bcb77',
        quick:  '#4d96ff',
    };

    function buildBars(chartId, arr) {
        const chart = document.getElementById(chartId);
        // remove old bars (keep overlay)
        [...chart.querySelectorAll('.bar')].forEach(b => b.remove());

        const max = Math.max(...arr);
        const chartH = 188; // approx usable height

        arr.forEach(val => {
            const bar = document.createElement('div');
            bar.className = 'bar';
            bar.style.height = `${(val / max) * chartH}px`;
            bar.style.background = COLORS.default;
            chart.appendChild(bar);
        });
    }

    function getBars(chartId) {
        return [...document.getElementById(chartId).querySelectorAll('.bar')];
    }

    function colorBar(chartId, index, color) {
        const bars = getBars(chartId);
        if (bars[index]) bars[index].style.background = color;
    }

    function setBarHeight(chartId, index, val, max, chartH = 188) {
        const bars = getBars(chartId);
        if (bars[index]) bars[index].style.height = `${(val / max) * chartH}px`;
    }

    function updateStats(algo, cmp, swp) {
        document.getElementById(`cmp-${algo}`).textContent = cmp;
        document.getElementById(`swp-${algo}`).textContent = swp;
    }

    function setStatus(algo, text) {
        document.getElementById(`status-${algo}`).textContent = text;
    }

    function showDone(algo) {
        document.getElementById(`done-${algo}`).classList.add('show');
    }

    function hideDone(algo) {
        document.getElementById(`done-${algo}`).classList.remove('show');
    }

    // ─── Generate ─────────────────────────────────────────────────────────────
    function generate() {
        const n = parseInt(sizeSlider.value);
        originalArray = randomArray(n);
        ['bubble','merge','quick'].forEach(algo => {
            buildBars(`chart-${algo}`, [...originalArray]);
            updateStats(algo, 0, 0);
            setStatus(algo, 'Ready');
            hideDone(algo);
        });
    }

    function resetArrays() {
        ['bubble','merge','quick'].forEach(algo => {
            buildBars(`chart-${algo}`, [...originalArray]);
            updateStats(algo, 0, 0);
            setStatus(algo, 'Ready');
            hideDone(algo);
        });
    }

    // ─── Bubble Sort ──────────────────────────────────────────────────────────
    async function bubbleSort(arr) {
        const algo   = 'bubble';
        const max    = Math.max(...arr);
        let cmp = 0, swp = 0;
        const n = arr.length;

        for (let i = 0; i < n - 1; i++) {
            let swapped = false;
            for (let j = 0; j < n - i - 1; j++) {
                if (!running) return;

                // highlight comparing pair
                colorBar(algo, j,   COLORS.compare);
                colorBar(algo, j+1, COLORS.compare);
                cmp++;
                updateStats(algo, cmp, swp);
                setStatus(algo, `Pass ${i+1}: comparing [${j}] & [${j+1}]`);

                await sleep(getDelay());
                if (!running) return;

                if (arr[j] > arr[j+1]) {
                    // swap
                    colorBar(algo, j,   COLORS.swap);
                    colorBar(algo, j+1, COLORS.swap);

                    [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
                    swp++;
                    updateStats(algo, cmp, swp);

                    setBarHeight(algo, j,   arr[j],   max);
                    setBarHeight(algo, j+1, arr[j+1], max);

                    await sleep(getDelay());
                    swapped = true;
                }

                // restore colors
                colorBar(algo, j,   COLORS.default);
                colorBar(algo, j+1, COLORS.default);
            }
            // mark sorted position
            colorBar(algo, n - i - 1, SORTED_COLORS.bubble);
            if (!swapped) break;
        }

        // color all sorted
        getBars(algo).forEach(b => b.style.background = SORTED_COLORS.bubble);
        setStatus(algo, `Done! ${cmp} comparisons, ${swp} swaps`);
        showDone(algo);
    }

    // ─── Merge Sort ───────────────────────────────────────────────────────────
    async function mergeSort(arr) {
        const algo = 'merge';
        const max  = Math.max(...arr);
        let cmp = 0, swp = 0;

        async function merge(arr, l, m, r) {
            const left  = arr.slice(l, m+1);
            const right = arr.slice(m+1, r+1);
            let i = 0, j = 0, k = l;

            while (i < left.length && j < right.length) {
                if (!running) return;
                cmp++;

                colorBar(algo, k, COLORS.compare);
                updateStats(algo, cmp, swp);
                setStatus(algo, `Merging [${l}..${m}] & [${m+1}..${r}]`);
                await sleep(getDelay());
                if (!running) return;

                if (left[i] <= right[j]) {
                    arr[k] = left[i++];
                } else {
                    arr[k] = right[j++];
                    swp++;
                }
                colorBar(algo, k, COLORS.merge);
                setBarHeight(algo, k, arr[k], max);
                updateStats(algo, cmp, swp);
                k++;
            }

            while (i < left.length) {
                if (!running) return;
                arr[k] = left[i++];
                colorBar(algo, k, COLORS.merge);
                setBarHeight(algo, k, arr[k], max);
                k++;
                await sleep(Math.max(2, getDelay() / 3));
            }
            while (j < right.length) {
                if (!running) return;
                arr[k] = right[j++];
                colorBar(algo, k, COLORS.merge);
                setBarHeight(algo, k, arr[k], max);
                k++;
                await sleep(Math.max(2, getDelay() / 3));
            }

            // mark this segment as sorted
            for (let x = l; x <= r; x++) {
                colorBar(algo, x, SORTED_COLORS.merge);
            }
        }

        async function split(arr, l, r) {
            if (!running) return;
            if (l >= r) {
                colorBar(algo, l, SORTED_COLORS.merge);
                return;
            }
            const m = Math.floor((l + r) / 2);
            await split(arr, l, m);
            await split(arr, m+1, r);
            await merge(arr, l, m, r);
        }

        await split(arr, 0, arr.length - 1);
        if (!running) return;

        getBars(algo).forEach(b => b.style.background = SORTED_COLORS.merge);
        setStatus(algo, `Done! ${cmp} comparisons, ${swp} swaps`);
        showDone(algo);
    }

    // ─── Quick Sort ───────────────────────────────────────────────────────────
    async function quickSort(arr) {
        const algo = 'quick';
        const max  = Math.max(...arr);
        let cmp = 0, swp = 0;

        async function partition(arr, low, high) {
            // randomized pivot
            const pivotIdx = low + Math.floor(Math.random() * (high - low + 1));
            [arr[pivotIdx], arr[high]] = [arr[high], arr[pivotIdx]];
            setBarHeight(algo, high, arr[high], max);
            setBarHeight(algo, pivotIdx, arr[pivotIdx], max);

            const pivot = arr[high];
            colorBar(algo, high, COLORS.pivot);
            let i = low - 1;

            for (let j = low; j < high; j++) {
                if (!running) return i;
                cmp++;
                colorBar(algo, j, COLORS.compare);
                setStatus(algo, `Pivot=${pivot}, comparing index ${j}`);
                updateStats(algo, cmp, swp);
                await sleep(getDelay());
                if (!running) return i;

                if (arr[j] <= pivot) {
                    i++;
                    if (i !== j) {
                        colorBar(algo, i, COLORS.swap);
                        colorBar(algo, j, COLORS.swap);
                        [arr[i], arr[j]] = [arr[j], arr[i]];
                        swp++;
                        setBarHeight(algo, i, arr[i], max);
                        setBarHeight(algo, j, arr[j], max);
                        updateStats(algo, cmp, swp);
                        await sleep(getDelay());
                    }
                    colorBar(algo, i, COLORS.default);
                }
                colorBar(algo, j, COLORS.default);
            }

            // place pivot
            [arr[i+1], arr[high]] = [arr[high], arr[i+1]];
            swp++;
            setBarHeight(algo, i+1, arr[i+1], max);
            setBarHeight(algo, high, arr[high], max);
            colorBar(algo, i+1, SORTED_COLORS.quick);
            colorBar(algo, high, COLORS.default);
            updateStats(algo, cmp, swp);

            return i + 1;
        }

        async function qsort(arr, low, high) {
            if (!running) return;
            if (low < high) {
                const pi = await partition(arr, low, high);
                await qsort(arr, low, pi - 1);
                await qsort(arr, pi + 1, high);
            } else if (low === high) {
                colorBar(algo, low, SORTED_COLORS.quick);
            }
        }

        await qsort(arr, 0, arr.length - 1);
        if (!running) return;

        getBars(algo).forEach(b => b.style.background = SORTED_COLORS.quick);
        setStatus(algo, `Done! ${cmp} comparisons, ${swp} swaps`);
        showDone(algo);
    }

    // ─── Run all ──────────────────────────────────────────────────────────────
    async function sortAll() {
        if (running) return;
        running = true;
        btnSort.disabled     = true;
        btnGenerate.disabled = true;
        btnReset.disabled    = true;

        const b = [...originalArray];
        const m = [...originalArray];
        const q = [...originalArray];

        await Promise.all([
            bubbleSort(b),
            mergeSort(m),
            quickSort(q),
        ]);

        running = false;
        btnSort.disabled     = false;
        btnGenerate.disabled = false;
        btnReset.disabled    = false;
    }

    // ─── Event listeners ──────────────────────────────────────────────────────
    sizeSlider.addEventListener('input', () => {
        sizeVal.textContent = sizeSlider.value;
        if (!running) generate();
    });

    speedSlider.addEventListener('input', () => {
        speedVal.textContent = speedSlider.value;
    });

    btnGenerate.addEventListener('click', () => { if (!running) generate(); });
    btnSort.addEventListener('click', sortAll);
    btnReset.addEventListener('click', () => {
        if (!running) resetArrays();
    });

    // ─── Init ─────────────────────────────────────────────────────────────────
    generate();
</script>
</body>
</html>
```

## What's included

**Three algorithms running in parallel on identical data:**
- 🫧 **Bubble Sort** — O(n²) shown in red
- 🔀 **Merge Sort** — O(n log n) shown in green
- ⚡ **Quick Sort** — O(n log n) shown in blue

**Interactive controls:**
- **Array size slider** — 10 to 80 elements
- **Speed slider** — from slow (for teaching) to fast (for comparison)
- **New Array** — generates fresh random data synced across all three
- **Sort All** — starts all three simultaneously
- **Reset** — restores the original unsorted array

**Visual feedback:**
- 🟡 Yellow bars = being compared
- 🔴 Red bars = being swapped
- 🟠 Orange bar = Quick Sort pivot
- Colored bars = confirmed sorted positions
- Live comparison and swap counters per algorithm
- ✓ Done overlay when each algorithm finishes

**Reference table** at the bottom explains best/average/worst case and space complexity with notes.

