            </div>
            <div class="stat-box">
                <span class="stat-value merge-stat" id="swaps-merge">0</span>
                <span class="stat-label">Merges</span>
            </div>
            <div class="stat-box">
                <span class="stat-value merge-stat" id="time-merge">0ms</span>
