        <div class="stat"><span class="stat-val comparisons" id="m-cmp">0</span><span class="stat-label">Comparisons</span></div>
        <div class="stat"><span class="stat-val swaps" id="m-swp">0</span><span class="stat-label">Writes</span></div>
        <div class="stat"><span class="stat-val time" id="m-time">—</span><span class="stat-label">Steps</span></div>
