<script>
// ─── Configuration ────────────────────────────────────────────────────────────
const ALGORITHMS = [
  {
    id: 'bubble',
    name: 'Bubble Sort',
    color: '#f06060',
    badge: 'slow',
    complexity: {
      best: 'O(n)', avg: 'O(n²)', worst: 'O(n²)', space: 'O(1)'
    },
    desc: 'Repeatedly steps through the list, compares adjacent elements and swaps them if they are in the wrong order. Very inefficient on large lists.'
  },
  {
    id: 'merge',
    name: 'Merge Sort',
    color: '#40f090',
    badge: 'fast',
    complexity: {
      best: 'O(n log n)', avg: 'O(n log n)', worst: 'O(n log n)', space: 'O(n)'
    },
    desc: 'Divides the array in half, recursively sorts each half, then merges them. Guaranteed O(n log n) in all cases.'
  },
  {
    id: 'quick',
    name: 'Quick Sort',
    color: '#60c0ff',
    badge: 'fast',
    complexity: {
      best: 'O(n log n)', avg: 'O(n log n)', worst: 'O(n²)', space: 'O(log n)'
    },
    desc: 'Picks a pivot, partitions elements around it, then recursively sorts partitions. Very fast in practice due to cache efficiency.'
  }
];

// ─── State ────────────────────────────────────────────────────────────────────
let baseArray = [];
let states = {};       // per-algo animation state
let canvases = {};
let ctxs = {};
let statEls = {};
let running = false;
let animFrameId = null;
let lastFrameTime = 0;

const sizeSlider  = document.getElementById('sizeSlider');
const speedSlider = document.getElementById('speedSlider');
const sizeVal     = document.getElementById('sizeVal');
const speedLabel  = document.getElementById('speedLabel');
const btnStart    = document.getElementById('btnStart');
const btnReset    = document.getElementById('btnReset');
const globalStatus= document.getElementById('globalStatus');

// ─── DOM Setup ────────────────────────────────────────────────────────────────
function buildUI() {
  const grid = document.getElementById('grid');
  grid.innerHTML = '';
  canvases = {}; ctxs = {}; statEls = {};

  ALGORITHMS.forEach(algo => {
    const panel = document.createElement('div');
    panel.className = 'panel';
    panel.innerHTML = `
      <div class="panel-header">
        <span class="algo-name" style="color:${algo.color}">${algo.name}</span>
        <span class="badge badge-${algo.badge}" id="badge-${algo.id}">
          ${algo.badge === 'slow' ? '🐢 Slow' : '⚡ Fast'}
        </span>
      </div>
      <div class="stats">
        <div class="stat-comparisons">
          Comparisons<br><span class="stat-val" id="cmp-${algo.id}">0</span>
        </div>
        <div class="stat-swaps">
          Swaps / Writes<br><span class="stat-val" id="swp-${algo.id}">0</span>
        </div>
        <div class="stat-time">
          Status<br><span class="stat-val" id="status-${algo.id}">Ready</span>
        </div>
      </div>
      <div class="chart-wrap">
        <canvas id="canvas-${algo.id}"></canvas>
      </div>
      <div class="complexity-box">
        <strong>Complexity:</strong>
        Best <span style="color:#4f8">${algo.complexity.best}</span> ·
        Avg <span style="color:#fa6">${algo.complexity.avg}</span> ·
        Worst <span style="color:#f66">${algo.complexity.worst}</span> ·
        Space <span style="color:#9cf">${algo.complexity.space}</span><br>
        <span style="color:#888;font-size:0.8rem">${algo.desc}</span>
      </div>
    `;
    grid.appendChild(panel);

    const canvas = panel.querySelector(`#canvas-${algo.id}`);
    canvases[algo.id] = canvas;
    ctxs[algo.id] = canvas.getContext('2d');
    statEls[algo.id] = {
      cmp:    document.getElementById(`cmp-${algo.id}`),
      swp:    document.getElementById(`swp-${algo.id}`),
      status: document.getElementById(`status-${algo.id}`),
      badge:  document.getElementById(`badge-${algo.id}`)
    };
  });
}

// ─── Array Generation ─────────────────────────────────────────────────────────
function generateArray(n) {
  const arr = Array.from({length: n}, (_, i) => i + 1);
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

// ─── Drawing ──────────────────────────────────────────────────────────────────
function drawBars(algoId, arr, highlights) {
  const canvas = canvases[algoId];
  const ctx = ctxs[algoId];
  const dpr = window.devicePixelRatio || 1;
  const w = canvas.clientWidth;
  const h = canvas.clientHeight;

  if (canvas.width !== w * dpr || canvas.height !== h * dpr) {
    canvas.width  = w * dpr;
    canvas.height = h * dpr;
    ctx.scale(dpr, dpr);
  }

  ctx.clearRect(0, 0, w, h);

  const n = arr.length;
  const barW = w / n;
  const maxVal = n;

  for (let i = 0; i < n; i++) {
    const barH = (arr[i] / maxVal) * (h - 2);
    const x = i * barW;
    const y = h - barH;

    let color = ALGORITHMS.find(a => a.id === algoId).color + 'bb';

    if (highlights) {
      if (highlights.sorted && highlights.sorted.has(i))       color = '#cfff44cc';
      else if (highlights.comparing && highlights.comparing.includes(i)) color = '#ffffff';
      else if (highlights.pivot === i)                          color = '#ffaa00';
      else if (highlights.merging && highlights.merging.has(i)) color = '#ff88ffcc';
    }

    ctx.fillStyle = color;
    ctx.fillRect(x + 0.5, y, Math.max(barW - 1, 1), barH);
  }
}

// ─── Algorithm Generators ─────────────────────────────────────────────────────

function* bubbleSortGen(arr) {
  const a = [...arr];
  const n = a.length;
  let comparisons = 0, swaps = 0;
  const sorted = new Set();

  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - i - 1; j++) {
      comparisons++;
      yield { arr: a, highlights: { comparing: [j, j+1], sorted }, comparisons, swaps };
      if (a[j] > a[j+1]) {
        [a[j], a[j+1]] = [a[j+1], a[j]];
        swaps++;
        swapped = true;
        yield { arr: a, highlights: { comparing: [j, j+1], sorted }, comparisons, swaps };
      }
    }
    sorted.add(n - 1 - i);
    if (!swapped) {
      for (let k = 0; k < n; k++) sorted.add(k);
      break;
    }
  }
  sorted.add(0);
  yield { arr: a, highlights: { sorted }, comparisons, swaps, done: true };
}

function* mergeSortGen(arr) {
  const a = [...arr];
  let comparisons = 0, swaps = 0;
  const sorted = new Set();

  function* merge(left, right, start) {
    const result = [];
    let i = 0, j = 0;
    const merging = new Set();
    for (let k = start; k < start + left.length + right.length; k++) merging.add(k);

    while (i < left.length && j < right.length) {
      comparisons++;
      yield { arr: a, highlights: { merging, sorted }, comparisons, swaps };
      if (left[i] <= right[j]) {
        result.push(left[i++]);
      } else {
        result.push(right[j++]);
      }
    }
    while (i < left.length)  result.push(left[i++]);
    while (j < right.length) result.push(right[j++]);

    for (let k = 0; k < result.length; k++) {
      a[start + k] = result[k];
      swaps++;
    }
    yield { arr: a, highlights: { merging, sorted }, comparisons, swaps };
  }

  function* msort(lo, hi) {
    if (hi - lo <= 1) return;
    const mid = Math.floor((lo + hi) / 2);
    yield* msort(lo, mid);
    yield* msort(mid, hi);
    yield* merge(a.slice(lo, mid), a.slice(mid, hi), lo);
  }

  yield* msort(0, a.length);
  for (let k = 0; k < a.length; k++) sorted.add(k);
  yield { arr: a, highlights: { sorted }, comparisons, swaps, done: true };
}

function* quickSortGen(arr) {
  const a = [...arr];
  let comparisons = 0, swaps = 0;
  const sorted = new Set();

  function* partition(lo, hi) {
    const pivotVal = a[hi];
    let i = lo;
    for (let j = lo; j < hi; j++) {
      comparisons++;
      yield { arr: a, highlights: { comparing: [j, hi], pivot: hi, sorted }, comparisons, swaps };
      if (a[j] <= pivotVal) {
        if (i !== j) { [a[i], a[j]] = [a[j], a[i]]; swaps++; }
        i++;
        yield { arr: a, highlights: { comparing: [i-1, j], pivot: hi, sorted }, comparisons, swaps };
      }
    }
    [a[i], a[hi]] = [a[hi], a[i]]; swaps++;
    yield { arr: a, highlights: { pivot: i, sorted }, comparisons, swaps };
    return i;
  }

  function* qsort(lo, hi) {
    if (lo >= hi) {
      if (lo === hi) sorted.add(lo);
      return;
    }
    const p = yield* partition(lo, hi);
    sorted.add(p);
    yield* qsort(lo, p - 1);
    yield* qsort(p + 1, hi);
  }

  yield* qsort(0, a.length - 1);
  for (let k = 0; k < a.length; k++) sorted.add(k);
  yield { arr: a, highlights: { sorted }, comparisons, swaps, done: true };
}

const GENERATORS = {
  bubble: bubbleSortGen,
  merge:  mergeSortGen,
  quick:  quickSortGen
};

// ─── Animation Loop ───────────────────────────────────────────────────────────
function getDelay() {
  const speed = parseInt(speedSlider.value);
  // speed 1 = ~200ms/step, speed 10 = ~1ms/step
  return Math.round(200 / (speed * speed * 0.09 + 0.1));
}

function stepAll(timestamp) {
  const delay = getDelay();
  const elapsed = timestamp - lastFrameTime;
  if (elapsed < delay) {
    animFrameId = requestAnimationFrame(stepAll);
    return;
  }
  lastFrameTime = timestamp;

  // Number of steps per frame scales with speed
  const speed = parseInt(speedSlider.value);
  const stepsPerFrame = speed >= 8 ? 12 : speed >= 5 ? 4 : 1;

  let anyRunning = false;

  for (let s = 0; s < stepsPerFrame; s++) {
    ALGORITHMS.forEach(algo => {
      const st = states[algo.id];
      if (st.done) return;
      anyRunning = true;

      const result = st.gen.next();
      if (result.done || (result.value && result.value.done)) {
        st.done = true;
        const v = result.value || st.last;
        if (v) {
          drawBars(algo.id, v.arr, v.highlights);
          statEls[algo.id].cmp.textContent    = v.comparisons.toLocaleString();
          statEls[algo.id].swp.textContent    = v.swaps.toLocaleString();
          statEls[algo.id].status.textContent = '✅ Done';
          const badge = statEls[algo.id].badge;
          badge.className = 'badge badge-done';
          badge.textContent = '✅ Done';
        }
      } else {
        const v = result.value;
        st.last = v;
        drawBars(algo.id, v.arr, v.highlights);
        statEls[algo.id].cmp.textContent = v.comparisons.toLocaleString();
        statEls[algo.id].swp.textContent = v.swaps.toLocaleString();
        statEls[algo.id].status.textContent = '⚙ Sorting…';
      }
    });
  }

  const allDone = ALGORITHMS.every(a => states[a.id].done);
  if (allDone) {
    running = false;
    btnStart.disabled = false;
    btnReset.disabled = false;
    globalStatus.textContent = '🏁 All done! Notice the difference in comparisons & swaps.';

    // Highlight winner
    let minCmp = Infinity, winner = null;
    ALGORITHMS.forEach(a => {
      const cmp = parseInt(statEls[a.id].cmp.textContent.replace(/,/g,''));
      if (cmp < minCmp) { minCmp = cmp; winner = a.id; }
    });
    if (winner) {
      statEls[winner].status.textContent = '🏆 Winner!';
    }
  } else {
    animFrameId = requestAnimationFrame(stepAll);
  }
}

// ─── Controls ─────────────────────────────────────────────────────────────────
function resetAll() {
  if (animFrameId) cancelAnimationFrame(animFrameId);
  running = false;
  btnStart.disabled = false;
  globalStatus.textContent = '';

  const n = parseInt(sizeSlider.value);
  baseArray = generateArray(n);

  ALGORITHMS.forEach(algo => {
    states[algo.id] = { gen: null, done: false, last: null };
    drawBars(algo.id, baseArray, null);
    statEls[algo.id].cmp.textContent    = '0';
    statEls[algo.id].swp.textContent    = '0';
    statEls[algo.id].status.textContent = 'Ready';
    const badge = statEls[algo.id].badge;
    badge.className = `badge badge-${algo.badge}`;
    badge.textContent = algo.badge === 'slow' ? '🐢 Slow' : '⚡ Fast';
  });
}

function startSort() {
  if (running) return;
  running = true;
  btnStart.disabled = true;
  btnReset.disabled = true;
  globalStatus.textContent = '⚙ Sorting in progress…';

  ALGORITHMS.forEach(algo => {
    states[algo.id] = {
      gen:  GENERATORS[algo.id]([...baseArray]),
      done: false,
      last: null
    };
  });

  lastFrameTime = 0;
  animFrameId = requestAnimationFrame(stepAll);
}

sizeSlider.addEventListener('input', () => {
  sizeVal.textContent = sizeSlider.value;
  if (!running) resetAll();
});

speedSlider.addEventListener('input', () => {
  speedLabel.textContent = speedSlider.value;
});

btnReset.addEventListener('click', resetAll);
btnStart.addEventListener('click', startSort);

// ─── Init ─────────────────────────────────────────────────────────────────────
buildUI();
resetAll();

window.addEventListener('resize', () => {
  if (!running) {
    ALGORITHMS.forEach(algo => drawBars(algo.id, baseArray, null));
  }
});
</script>
</body>
</html>
```

