<body>

<h1>⚔️ Sorting Algorithm Death Match ⚔️</h1>
<p class="subtitle">Bubble Sort vs. The World — A Humiliation in Real Time</p>

<div class="controls">
  <button id="startBtn" onclick="startRace()">▶ START THE CARNAGE</button>
  <button id="resetBtn" onclick="resetAll()">↺ Reset</button>
  <div class="speed-control">
    <span>Speed:</span>
    <input type="range" id="speedSlider" min="1" max="10" value="5">
    <span id="speedLabel">5x</span>
  </div>
  <div class="speed-control">
    <label for="sizeSlider">Array Size:</label>
    <input type="range" id="sizeSlider" min="10" max="80" value="40">
    <span id="sizeLabel">40</span>
  </div>
</div>

<div id="globalStatus">Press START to witness Bubble Sort's shame.</div>

<div class="arenas" id="arenas">
  <!-- Arenas injected by JS -->
</div>

<div class="verdict" id="verdict"></div>

<script>
// ─── Config ───────────────────────────────────────────────────────────────────

const ALGORITHMS = [
  {
    id: 'bubble',
    name: '🫧 Bubble Sort',
    color: '#ff4444',
    worstColor: '#ff6666',
    complexity: {
      best:  ['O(n)',    'ok'],
      avg:   ['O(n²)',   'bad'],
      worst: ['O(n²)',   'bad'],
      space: ['O(1)',    'good'],
    },
    description: 'The algorithm equivalent of sorting cards by shuffling them randomly and checking if they\'re sorted.',
    generate: bubbleSortSteps,
  },
  {
    id: 'merge',
    name: '🔀 Merge Sort',
    color: '#00aaff',
    worstColor: '#44ccff',
    complexity: {
      best:  ['O(n log n)', 'good'],
      avg:   ['O(n log n)', 'good'],
      worst: ['O(n log n)', 'good'],
      space: ['O(n)',       'ok'],
    },
    description: 'Divide, conquer, and make Bubble Sort cry.',
    generate: mergeSortSteps,
  },
  {
    id: 'quick',
    name: '⚡ Quick Sort',
    color: '#00ff88',
    worstColor: '#88ffcc',
    complexity: {
      best:  ['O(n log n)', 'good'],
      avg:   ['O(n log n)', 'good'],
      worst: ['O(n²)',      'ok'],
      space: ['O(log n)',   'good'],
    },
    description: 'So fast it\'s practically showing off.',
    generate: quickSortSteps,
  },
];

// ─── State ────────────────────────────────────────────────────────────────────

let originalArray = [];
let runners = [];       // { algo, steps, stepIndex, done, comparisons, swaps, startTime, endTime }
let animFrame = null;
let running = false;
let finishOrder = [];
let lastTimestamp = 0;
let speedMultiplier = 5;
let stepsPerFrame = 1;

// ─── Utility ──────────────────────────────────────────────────────────────────

function randomArray(n) {
  return Array.from({ length: n }, () => Math.floor(Math.random() * 95) + 5);
}

function cloneArr(a) { return [...a]; }

function speedFromSlider(v) {
  // 1→1 stp/frame, 10→200 stp/frame
  return Math.round(Math.pow(2, (v - 1) * 0.85));
}

// ─── Step Generators ──────────────────────────────────────────────────────────
// Each yields { array, highlights: [i,j,...], comparisons, swaps }

function* bubbleSortSteps(arr) {
  arr = cloneArr(arr);
  let n = arr.length, comps = 0, swaps = 0;
  for (let i = 0; i < n - 1; i++) {
    for (let j = 0; j < n - i - 1; j++) {
      comps++;
      yield { array: cloneArr(arr), highlights: [j, j+1], comparisons: comps, swaps, phase: 'compare' };
      if (arr[j] > arr[j+1]) {
        [arr[j], arr[j+1]] = [arr[j+1], arr[j]];
        swaps++;
        yield { array: cloneArr(arr), highlights: [j, j+1], comparisons: comps, swaps, phase: 'swap' };
      }
    }
  }
  yield { array: cloneArr(arr), highlights: [], comparisons: comps, swaps, phase: 'done' };
}

function* mergeSortSteps(arr) {
  arr = cloneArr(arr);
  let comps = 0, swaps = 0;

  function* mergeSort(a, left) {
    if (a.length <= 1) return a;
    const mid = Math.floor(a.length / 2);
    const L = yield* mergeSort(a.slice(0, mid), left);
    const R = yield* mergeSort(a.slice(mid), left + mid);
    // merge
    let i = 0, j = 0, k = left;
    const merged = [];
    while (i < L.length && j < R.length) {
      comps++;
      yield { array: cloneArr(arr), highlights: [left+i, left+mid+j], comparisons: comps, swaps, phase: 'compare' };
      if (L[i] <= R[j]) { merged.push(L[i++]); }
      else               { merged.push(R[j++]); }
    }
    while (i < L.length) merged.push(L[i++]);
    while (j < R.length) merged.push(R[j++]);
    for (let x = 0; x < merged.length; x++) {
      if (arr[left+x] !== merged[x]) swaps++;
      arr[left+x] = merged[x];
    }
    yield { array: cloneArr(arr), highlights: Array.from({length: merged.length}, (_,x)=>left+x), comparisons: comps, swaps, phase: 'merge' };
    return merged;
  }

  yield* mergeSort(arr, 0);
  yield { array: cloneArr(arr), highlights: [], comparisons: comps, swaps, phase: 'done' };
}

function* quickSortSteps(arr) {
  arr = cloneArr(arr);
  let comps = 0, swaps = 0;

  function* quickSort(lo, hi) {
    if (lo >= hi) return;
    const pivot = arr[hi];
    let i = lo;
    for (let j = lo; j < hi; j++) {
      comps++;
      yield { array: cloneArr(arr), highlights: [j, hi], comparisons: comps, swaps, phase: 'compare' };
      if (arr[j] < pivot) {
        [arr[i], arr[j]] = [arr[j], arr[i]];
        swaps++;
        yield { array: cloneArr(arr), highlights: [i, j], comparisons: comps, swaps, phase: 'swap' };
        i++;
      }
    }
    [arr[i], arr[hi]] = [arr[hi], arr[i]];
    swaps++;
    yield { array: cloneArr(arr), highlights: [i, hi], comparisons: comps, swaps, phase: 'pivot' };
    yield* quickSort(lo, i - 1);
    yield* quickSort(i + 1, hi);
  }

  yield* quickSort(0, arr.length - 1);
  yield { array: cloneArr(arr), highlights: [], comparisons: comps, swaps, phase: 'done' };
}

// ─── DOM Building ─────────────────────────────────────────────────────────────

function buildArenas() {
  const container = document.getElementById('arenas');
  container.innerHTML = '';
  ALGORITHMS.forEach(algo => {
    const div = document.createElement('div');
    div.className = 'arena';
    div.id = `arena-${algo.id}`;
    div.innerHTML = `
      <div class="arena-title" style="color:${algo.color}">${algo.name}</div>
      <div class="complexity">
        Best: <span class="${algo.complexity.best[1]}">${algo.complexity.best[0]}</span> &nbsp;
        Avg: <span class="${algo.complexity.avg[1]}">${algo.complexity.avg[0]}</span> &nbsp;
        Worst: <span class="${algo.complexity.worst[1]}">${algo.complexity.worst[0]}</span><br>
        Space: <span class="${algo.complexity.space[1]}">${algo.complexity.space[0]}</span>
      </div>
      <div class="chart-container" id="chart-${algo.id}"></div>
      <div class="progress-bar"><div class="progress-fill" id="prog-${algo.id}" style="background:${algo.color}"></div></div>
      <div class="stats">
        <div class="stat-box">
          <div class="stat-label">Comparisons</div>
          <div class="stat-value" id="comps-${algo.id}">0</div>
        </div>
        <div class="stat-box">
          <div class="stat-label">Swaps/Writes</div>
          <div class="stat-value" id="swaps-${algo.id}">0</div>
        </div>
        <div class="stat-box">
          <div class="stat-label">Steps Done</div>
          <div class="stat-value" id="steps-${algo.id}">0</div>
        </div>
        <div class="stat-box">
          <div class="stat-label">Time (ms)</div>
          <div class="stat-value" id="time-${algo.id}">—</div>
        </div>
      </div>
      <div class="status-bar" id="status-${algo.id}">Waiting…</div>
    `;
    container.appendChild(div);
  });
}

function renderBars(algoId, array, highlights, algoColor, highlightColor) {
  const container = document.getElementById(`chart-${algoId}`);
  if (!container) return;
  const max = Math.max(...array);
  const bars = container.querySelectorAll('.bar');

  if (bars.length !== array.length) {
    container.innerHTML = '';
    array.forEach((v, i) => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = `${(v / max) * 100}%`;
      bar.style.background = highlights.includes(i) ? highlightColor : algoColor;
      container.appendChild(bar);
    });
  } else {
    bars.forEach((bar, i) => {
      bar.style.height = `${(array[i] / max) * 100}%`;
      bar.style.background = highlights.includes(i) ? highlightColor : algoColor;
    });
  }
}

function updateStats(algoId, comps, swaps, steps, totalSteps, timeMs) {
  document.getElementById(`comps-${algoId}`).textContent = comps.toLocaleString();
  document.getElementById(`swaps-${algoId}`).textContent = swaps.toLocaleString();
  document.getElementById(`steps-${algoId}`).textContent = steps.toLocaleString();
  document.getElementById(`time-${algoId}`).textContent = timeMs !== null ? timeMs : '—';
  const pct = totalSteps > 0 ? Math.min(100, (steps / totalSteps) * 100) : 0;
  document.getElementById(`prog-${algoId}`).style.width = pct + '%';
}

// ─── Race Logic ───────────────────────────────────────────────────────────────

function resetAll() {
  if (animFrame) cancelAnimationFrame(animFrame);
  running = false;
  finishOrder = [];
  const n = parseInt(document.getElementById('sizeSlider').value);
  originalArray = randomArray(n);
  buildArenas();
  ALGORITHMS.forEach(algo => {
    renderBars(algo.id, originalArray, [], algo.color, algo.worstColor);
  });
  document.getElementById('verdict').innerHTML = '';
  document.getElementById('globalStatus').textContent = 'Press START to witness Bubble Sort\'s shame.';
  document.getElementById('startBtn').disabled = false;
}

function startRace() {
  if (running) return;
  running = true;
  finishOrder = [];
  document.getElementById('startBtn').disabled = true;
  document.getElementById('globalStatus').textContent = '🏁 Race in progress…';

  // Estimate total steps for progress bar (rough)
  const n = originalArray.length;
  const bubbleTotal = n * n;
  const fastTotal   = Math.ceil(n * Math.log2(n)) * 3;

  runners = ALGORITHMS.map(algo => ({
    algo,
    gen: algo.generate(cloneArr(originalArray)),
    stepIndex: 0,
    done: false,
    comparisons: 0,
    swaps: 0,
    lastStep: null,
    startTime: performance.now(),
    endTime: null,
    totalSteps: algo.id === 'bubble' ? bubbleTotal : fastTotal,
  }));

  lastTimestamp = performance.now();
  animFrame = requestAnimationFrame(tick);
}

function tick(ts) {
  speedMultiplier = parseInt(document.getElementById('speedSlider').value);
  stepsPerFrame = speedFromSlider(speedMultiplier);
  document.getElementById('speedLabel').textContent = speedMultiplier + 'x';

  const allDone = runners.every(r => r.done);
  if (allDone) {
    running = false;
    showVerdict();
    return;
  }

  runners.forEach(runner => {
    if (runner.done) return;
    const algo = runner.algo;

    for (let s = 0; s < stepsPerFrame; s++) {
      const result = runner.gen.next();
      if (result.done || (result.value && result.value.phase === 'done')) {
        runner.done = true;
        runner.endTime = performance.now();
        finishOrder.push(algo.id);

        const lastVal = result.value || runner.lastStep;
        if (lastVal) {
          renderBars(algo.id, lastVal.array, [], algo.color, algo.worstColor);
          runner.comparisons = lastVal.comparisons;
          runner.swaps       = lastVal.swaps;
        }

        const elapsed = Math.round(runner.endTime - runner.startTime);
        updateStats(algo.id, runner.comparisons, runner.swaps, runner.stepIndex, runner.totalSteps, elapsed);

        const arena = document.getElementById(`arena-${algo.id}`);
        const statusEl = document.getElementById(`status-${algo.id}`);
        const place = finishOrder.length;
        if (place === 1) {
          arena.classList.add('winner');
          statusEl.innerHTML = `<span class="done-badge winner-badge">🏆 FINISHED FIRST (${elapsed}ms)</span>`;
        } else {
          arena.classList.add('loser');
          statusEl.innerHTML = `<span class="done-badge loser-badge">💀 Finished ${place}${['st','nd','rd'][place-1]||'th'} (${elapsed}ms)</span>`;
        }
        document.getElementById(`prog-${algo.id}`).style.width = '100%';
        break;
      }

      const step = result.value;
      if (!step) break;
      runner.lastStep = step;
      runner.stepIndex++;
      runner.comparisons = step.comparisons;
      runner.swaps       = step.swaps;

      // Only render last step of the batch for perf
      if (s === stepsPerFrame - 1) {
        renderBars(algo.id, step.array, step.highlights, algo.color, algo.worstColor);
        const elapsed = Math.round(performance.now() - runner.startTime);
        updateStats(algo.id, step.comparisons, step.swaps, runner.stepIndex, runner.totalSteps, elapsed);
      }
    }
  });

  animFrame = requestAnimationFrame(tick);
}

// ─── Verdict ─────────────────────────────────────────────────────────────────

const ROASTS = [
  "Bubble Sort finished so late the other algorithms had already gone home, showered, and filed their taxes.",
  "Bubble Sort looked at O(n²) and said 'yeah, that's fine.' It is not fine.",
  "Bubble Sort is the algorithm your CS professor uses as a cautionary tale, not a solution.",
  "If algorithms were cars, Bubble Sort would be a shopping cart rolling downhill. Technically moving. Barely.",
  "Bubble Sort just called. It wants to know if the race has started yet.",
  "Bubble Sort: because sometimes you want to sort things, but also hate yourself and your users.",
  "The gap between Bubble Sort and the others is why your colleague's opinion is a public health concern.",
  "Bubble Sort did its best. Its best was catastrophically, embarrassingly insufficient.",
];

function showVerdict() {
  const bubbleRunner = runners.find(r => r.algo.id === 'bubble');
  const others = runners.filter(r => r.algo.id !== 'bubble');
  const bubbleTime = Math.round(bubbleRunner.endTime - bubbleRunner.startTime);

  let html = '<div class="roast">';
  html += `<strong>📊 Final Verdict:</strong><br><br>`;

  others.forEach(r => {
    const t = Math.round(r.endTime - r.startTime);
    const ratio = bubbleRunner.comparisons > 0 ? (bubbleRunner.comparisons / Math.max(r.comparisons,1)).toFixed(1) : '?';
    html += `<strong>${r.algo.name}</strong> finished in <strong>${t}ms</strong> with <strong>${r.comparisons.toLocaleString()}</strong> comparisons. `;
    html += `Bubble Sort needed <strong>${bubbleRunner.comparisons.toLocaleString()}</strong> comparisons — that's <strong>${ratio}×</strong> more.<br><br>`;
  });

  const roast = ROASTS[Math.floor(Math.random() * ROASTS.length)];
  html += `<em>"${roast}"</em>`;
  html += '</div>';

  document.getElementById('verdict').innerHTML = html;
  document.getElementById('globalStatus').textContent = '✅ Race complete. Show this to your colleague.';
}

// ─── Slider listeners ─────────────────────────────────────────────────────────

document.getElementById('sizeSlider').addEventListener('input', function() {
  document.getElementById('sizeLabel').textContent = this.value;
  if (!running) resetAll();
});

document.getElementById('speedSlider').addEventListener('input', function() {
  document.getElementById('speedLabel').textContent = this.value + 'x';
});

// ─── Init ─────────────────────────────────────────────────────────────────────
resetAll();
</script>
</body>
</html>
```

## What it does:

- **3 side-by-side animated bar charts** — Bubble Sort vs Merge Sort vs Quick Sort
- **Real-time step execution** — all three race simultaneously on the **same data**
- **Tracks comparisons, swaps/writes, steps, and elapsed time** per algorithm
- **Progress bars** so you can watch Bubble Sort fall behind immediately
- **Winner/loser highlighting** — green glow for first finish, red shame for last
- **Randomized roast** at the end with exact comparison ratios ("Bubble Sort needed **47×** more comparisons")
- **Speed slider** (1x to 10x) and **array size slider** (10–80 elements)
- **Big-O complexity table** per algorithm with color-coded ratings

