           + <span class="str">"WHERE name = ?"</span>;  <span class="cmt">// ← placeholder</span>

db.run(query, [<span class="var">userInput</span>]);
<span class="cmt">// userInput is bound as DATA</span>
<span class="cmt">// not as SQL code</span>

