<script>
// ─── In-Memory "Database" ───────────────────────────────────────────────────
const products = [
    { id: 1,  name: "Laptop Pro 15",      category: "Electronics", price: 1299, stock: 14 },
    { id: 2,  name: "Wireless Mouse",     category: "Electronics", price: 29,   stock: 83 },
