// ─── Tab Switching ──────────────────────────────────────────────────────────
function switchTab(tab) {
    document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
    document.getElementById('panel-' + tab).classList.add('active');
    document.querySelector('.tab-btn.' + tab).classList.add('active');
    if (tab === 'vulnerable') renderFullDbTable();
}

// ─── Query Display Helpers ──────────────────────────────────────────────────
function escapeHtml(str) {
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

function buildVulnQueryString(name, cat, price) {
    let q = "SELECT * FROM products WHERE 1=1";
    if (name)  q += ` AND name LIKE '%${name}%'`;
    if (cat)   q += ` AND category = '${cat}'`;
    if (price) q += ` AND price <= ${price}`;
    return q;
}

function highlightInjection(queryStr) {
    // Highlight anything that looks like injected SQL
    const injectionPatterns = [
        /(OR\s+'?1'?='?1'?)/gi,
        /(OR\s+1=1)/gi,
        /(--.*)/gi,
        /(DROP\s+TABLE[^;]*;?)/gi,
        /(UNION\s+SELECT[^;]*)/gi,
        /(category\s*=\s*'admin')/gi,
        /(category\s*=\s*'secret')/gi,
    ];
    let result = escapeHtml(queryStr);
    injectionPatterns.forEach(pat => {
        result = result.replace(pat, '<span class="injection">$1</span>');
    });
    return result;
}

function updateVulnQuery() {
    const name  = document.getElementById('vuln-name').value;
    const cat   = document.getElementById('vuln-cat').value;
    const price = document.getElementById('vuln-price').value;
    const q = buildVulnQueryString(name, cat, price);
    document.getElementById('vuln-query-display').innerHTML = highlightInjection(q);
}

function updateSafeQuery() {
    const name  = document.getElementById('safe-name').value;
    const cat   = document.getElementById('safe-cat').value;
    const price = document.getElementById('safe-price').value;

    let q = "SELECT * FROM products WHERE 1=1";
    const params = [];
    if (name)  { q += " AND name LIKE <span class='param'>?1</span>";  params.push(`?1 = "${escapeHtml(name)}"`); }
    if (cat)   { q += " AND category = <span class='param'>?2</span>"; params.push(`?2 = "${escapeHtml(cat)}"`); }
    if (price) { q += " AND price &lt;= <span class='param'>?3</span>";params.push(`?3 = ${escapeHtml(price)}`); }

    let display = q;
    if (params.length) display += `<br><span style="color:#555;font-size:0.8em">Params: [${params.join(', ')}]</span>`;
    document.getElementById('safe-query-display').innerHTML = display;
}

// ─── Preset Injection Buttons ───────────────────────────────────────────────
function injectPreset(payload) {
    document.getElementById('vuln-name').value = payload;
    updateVulnQuery();
}

function injectPresetSafe(payload) {
    document.getElementById('safe-name').value = payload;
    updateSafeQuery();
}

// ─── Vulnerable Search (simulates string concat) ────────────────────────────
function runVulnerableSearch() {
    const name  = document.getElementById('vuln-name').value.trim();
    const cat   = document.getElementById('vuln-cat').value.trim();
    const price = document.getElementById('vuln-price').value.trim();

    updateVulnQuery();

    // Simulate what string concatenation would do
    // We parse the "constructed query" to decide what to return
    const queryStr = buildVulnQueryString(name, cat, price).toLowerCase();

    let results = [];
    let alertMsg = '';
    let alertType = '';
    let isInjected = false;

    // Detect injection patterns
    const hasOrTrue       = /or\s+'?1'?='?1'?/i.test(name) || /or\s+1=1/i.test(name);
    const hasComment      = /--/.test(name);
    const hasDrop         = /drop\s+table/i.test(name);
    const hasUnion        = /union\s+select/i.test(name);
    const hasAdminInject  = /category\s*=\s*'admin'/i.test(name);
    const hasSecretInject = /category\s*=\s*'secret'/i.test(name);

    if (hasDrop) {
        isInjected = true;
        alertMsg = '💥 DROP TABLE detected! In a real DB this could destroy your entire table. Here we simulate the attempt — the table is shown as "dropped" below.';
        alertType = 'danger';
        results = [];
        renderVulnResults(results, alertMsg, alertType, true);
        return;
    }

    if (hasUnion) {
        isInjected = true;
        alertMsg = '🔓 UNION SELECT injection! In a real attack this could merge data from another table (e.g., users, credentials) into the results.';
        alertType = 'danger';
        // Return all rows including secret ones
        results = [...products];
    } else if (hasOrTrue || hasComment) {
        isInjected = true;
        alertMsg = '🚨 Injection successful! The OR condition is always true — ALL rows returned, including hidden admin/secret rows!';
        alertType = 'danger';
        results = [...products];
    } else if (hasAdminInject) {
        isInjected = true;
        alertMsg = '🔓 Category injection! Forced category=admin — hidden admin rows exposed!';
        alertType = 'danger';
        results = products.filter(p => p.category === 'admin');
    } else if (hasSecretInject) {
        isInjected = true;
        alertMsg = '🔓 Secret rows exposed via injection!';
        alertType = 'danger';
        results = products.filter(p => p.category === 'secret');
    } else {
        // Normal (non-injected) search
        results = products.filter(p => {
            const nameOk  = !name  || p.name.toLowerCase().includes(name.toLowerCase());
            const catOk   = !cat   || p.category.toLowerCase() === cat.toLowerCase();
            const priceOk = !price || p.price <= parseFloat(price);
            // Normal search never shows admin/secret rows
            const notHidden = p.category !== 'admin' && p.category !== 'secret';
            return nameOk && catOk && priceOk && notHidden;
        });
        if (results.length === 0) {
            alertMsg = 'No products matched your search.';
            alertType = 'info';
        }
    }

    renderVulnResults(results, alertMsg, alertType, false, isInjected);
}

function renderVulnResults(results, alertMsg, alertType, dropped, isInjected) {
    const area = document.getElementById('vuln-results-area');
    area.style.display = 'block';

    let html = `<div class="results-header">
        <div class="results-count">Found <span>${dropped ? 0 : results.length}</span> result(s)</div>
    </div>`;

    if (alertMsg) {
        html += `<div class="alert-box ${alertType}">
            <span>${alertType === 'danger' ? '🚨' : alertType === 'success' ? '✅' : 'ℹ️'}</span>
            <span>${alertMsg}</span>
        </div>`;
    }

    if (dropped) {
        html += `<div class="no-results" style="border:1px solid #ff4444; color:#ff6666">
            💥 TABLE DROPPED — products table destroyed!<br>
            <small style="color:#666;margin-top:8px;display:block">In a real database, this would permanently delete all data.</small>
        </div>`;
    } else if (results.length === 0) {
        html += `<div class="no-results">No results found.</div>`;
    } else {
        html += renderTable(results, isInjected);
    }

    area.innerHTML = html;
}

// ─── Safe Search (parameterized simulation) ──────────────────────────────────
function runSafeSearch() {
    const rawName  = document.getElementById('safe-name').value.trim();
    const rawCat   = document.getElementById('safe-cat').value.trim();
    const rawPrice = document.getElementById('safe-price').value.trim();

    updateSafeQuery();

    // Sanitize: treat ALL input as plain literal strings/numbers
    // Injection characters are just part of the search string — not SQL
    const safeName  = rawName;   // treated as literal value, not SQL
    const safeCat   = rawCat;
    const safePrice = parseFloat(rawPrice); // NaN if not a number

    const results = products.filter(p => {
        // Only search visible products
        if (p.category === 'admin' || p.category === 'secret') return false;

        // Name: literal substring match (injection chars included as literals)
        const nameOk = !safeName || p.name.toLowerCase().includes(safeName.toLowerCase());

        // Category: exact literal match
        const catOk = !safeCat || p.category.toLowerCase() === safeCat.toLowerCase();

        // Price: numeric comparison only
        const priceOk = isNaN(safePrice) || p.price <= safePrice;

        return nameOk && catOk && priceOk;
    });

    renderSafeResults(results, rawName, rawCat, rawPrice);
}

function renderSafeResults(results, rawName, rawCat, rawPrice) {
    const area = document.getElementById('safe-results-area');
    area.style.display = 'block';

    // Detect if injection was attempted (for educational display)
    const injectionAttempted = /('|--|OR\s+1|UNION|DROP|;)/i.test(rawName + rawCat + rawPrice);

    let html = `<div class="results-header">
        <div class="results-count">Found <span>${results.length}</span> result(s)</div>
    </div>`;

    if (injectionAttempted) {
        html += `<div class="alert-box success">
            ✅ <span>Injection attempt detected in input — but it was treated as a <strong>plain string literal</strong>, not SQL code. 
            The database engine received the exact characters you typed as data, not as query logic. Attack neutralized!</span>
        </div>`;
    }

    if (results.length === 0) {
        html += `<div class="no-results">
            No products matched your search.<br>
            <small style="color:#555;margin-top:8px;display:block">
                ${injectionAttempted ? 'The injection payload was searched for literally as a product name — no match found.' : 'Try a different search term.'}
            </small>
        </div>`;
    } else {
        html += renderTable(results, false);
    }

    area.innerHTML = html;
}

// ─── Table Renderer ──────────────────────────────────────────────────────────
function renderTable(rows, highlightSecret) {
    const catClass = {
        'Electronics': 'cat-electronics',
        'Clothing':    'cat-clothing',
        'Books':       'cat-books',
        'Food':        'cat-food',
        'admin':       'cat-admin',
        'secret':      'cat-secret',
    };

    let html = `<table>
        <thead>
            <tr>
                <th>ID</th>
                <th>Product Name</th>
                <th>Category</th>
                <th>Price</th>
                <th>Stock</th>
            </tr>
        </thead>
        <tbody>`;

    rows.forEach(p => {
        const isSecret = p.category === 'admin' || p.category === 'secret';
        const rowClass = isSecret && highlightSecret ? 'secret-row' : '';
        const cc = catClass[p.category] || '';
        html += `<tr class="${rowClass}">
            <td>${p.id}</td>
            <td>${escapeHtml(p.name)}</td>
            <td><span class="category-badge ${cc}">${escapeHtml(p.category)}</span></td>
            <td class="price">$${p.price.toFixed(2)}</td>
            <td>${p.stock}</td>
        </tr>`;
    });

    html += `</tbody></table>`;
    return html;
}

// ─── Full DB Table (visible in vulnerable panel) ─────────────────────────────
function renderFullDbTable() {
    const visibleProducts = products.filter(p => p.category !== 'admin' && p.category !== 'secret');
    let html = renderTable(visibleProducts, false);
    html += `<p style="font-size:0.78rem;color:#444;margin-top:10px;text-align:right">
        + 2 hidden rows (admin/secret) — only accessible via injection in vulnerable mode
    </p>`;
    document.getElementById('full-db-table').innerHTML = html;
}

// ─── Init ────────────────────────────────────────────────────────────────────
renderFullDbTable();
</script>
