    <!-- Explanation -->
    <div class="explanation-panel">
        <h2>📚 How It Works — Why Parameterization Prevents Injection</h2>

        <div class="explanation-grid">
            <div class="explanation-card danger">
                <h3>⚠️ Vulnerable: String Concatenation</h3>
                <ul>
                    <li>
                        <span class="bullet">🔴</span>
                        User input is directly embedded into the query string before evaluation.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        SQL syntax characters like <code>'</code>, <code>--</code>, <code>OR</code>
                        are interpreted as part of the query logic.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        An attacker can close the original string and append new conditions,
                        changing what the query returns.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        Input <code>' OR '1'='1</code> makes the WHERE clause always true,
                        returning every row including hidden ones.
                    </li>
                    <li>
                        <span class="bullet">🔴</span>
                        Real attacks can also DROP tables, exfiltrate data from other tables,
                        or create admin accounts.
                    </li>
                </ul>
            </div>

            <div class="explanation-card success">
                <h3>✅ Safe: Parameterized Queries</h3>
                <ul>
                    <li>
                        <span class="bullet">🟢</span>
                        The query structure is defined first, with a placeholder
                        (<code>?</code> or <code>:param</code>) for user input.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        The database engine receives the query template and the data
                        <em>separately</em> — they are never combined as a string.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        The engine treats the entire input as a literal data value,
                        not as executable SQL syntax.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        <code>' OR '1'='1</code> is searched for literally as a product
                        name — no special SQL meaning is applied.
                    </li>
                    <li>
                        <span class="bullet">🟢</span>
                        No matter what characters the user types, they cannot alter
                        the query's structure or logic.
                    </li>
                </ul>
            </div>
        </div>

        <div class="how-it-works">
            <h3>🔬 Step-by-Step: What Happens with <code>' OR '1'='1</code></h3>

            <div style="display:grid; grid-template-columns:1fr 1fr; gap:20px;">
                <div>
                    <p style="color:#ff8888; font-size:0.8rem; margin-bottom:10px; font-weight:600;">
                        ⚠️ VULNERABLE PATH
                    </p>
                    <div class="step">
                        <div class="step-num">1</div>
                        <div class="step-text">
                            App builds: <code>"SELECT * FROM products WHERE name LIKE '%" + input + "%'"</code>
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">2</div>
                        <div class="step-text">
                            Result string becomes:
                            <code>SELECT * FROM products WHERE name LIKE '%' OR '1'='1%'</code>
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">3</div>
                        <div class="step-text">
                            The <code>OR '1'='1'</code> condition is always true, so
                            the WHERE clause matches every single row.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">4</div>
                        <div class="step-text">
                            All records are returned — including hidden, admin, and
                            sensitive rows that should never be visible.
                        </div>
                    </div>
                </div>

                <div>
                    <p style="color:#44ff88; font-size:0.8rem; margin-bottom:10px; font-weight:600;">
                        ✅ SAFE PATH
                    </p>
                    <div class="step">
                        <div class="step-num">1</div>
                        <div class="step-text">
                            App sends template: <code>SELECT * FROM products WHERE name LIKE ?</code>
                            — structure is locked in.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">2</div>
                        <div class="step-text">
                            Input <code>' OR '1'='1</code> is passed as a separate
                            data parameter, wrapped as <code>%' OR '1'='1%</code>.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">3</div>
                        <div class="step-text">
                            Database treats the entire value as a literal string to
                            match against — SQL keywords have no effect here.
                        </div>
                    </div>
                    <div class="step">
                        <div class="step-num">4</div>
                        <div class="step-text">
                            No product named <code>' OR '1'='1</code> exists, so
                            zero results are returned. Attack completely neutralized.
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <script>
        // ─────────────────────────────────────────────
        // SIMULATED DATABASE
        // ─────────────────────────────────────────────
        const database = [
            { id: 1,  name: "Laptop Pro 15",        category: "Electronics", price: 1299.99, stock: 45,  hidden: false },
            { id: 2,  name: "Wireless Mouse",        category: "Electronics", price: 29.99,  stock: 200, hidden: false },
            { id: 3,  name: "USB-C Hub",             category: "Electronics", price: 49.99,  stock: 150, hidden: false },
            { id: 4,  name: "Mechanical Keyboard",   category: "Electronics", price: 149.99, stock: 80,  hidden: false },
            { id: 5,  name: "4K Monitor",            category: "Electronics", price: 599.99, stock: 30,  hidden: false },
            { id: 6,  name: "Running Shoes",         category: "Sports",      price: 89.99,  stock: 120, hidden: false },
            { id: 7,  name: "Yoga Mat",              category: "Sports",      price: 34.99,  stock: 95,  hidden: false },
            { id: 8,  name: "Water Bottle",          category: "Sports",      price: 19.99,  stock: 300, hidden: false },
            { id: 9,  name: "Coffee Maker",          category: "Kitchen",     price: 79.99,  stock: 60,  hidden: false },
            { id: 10, name: "Blender Pro",           category: "Kitchen",     price: 59.99,  stock: 75,  hidden: false },
            // Hidden/sensitive rows — should NEVER appear in normal searches
            { id: 11, name: "ADMIN_CREDENTIALS",     category: "SYSTEM",      price: 0,      stock: 1,   hidden: true  },
            { id: 12, name: "USER_PASSWORDS_DUMP",   category: "SYSTEM",      price: 0,      stock: 1,   hidden: true  },
            { id: 13, name: "INTERNAL_API_KEYS",     category: "SYSTEM",      price: 0,      stock: 1,   hidden: true  },
            { id: 14, name: "SECRET_PRODUCT_DRAFT",  category: "RESTRICTED",  price: 999,    stock: 0,   hidden: true  },
        ];

        // ─────────────────────────────────────────────
        // INJECTION PRESETS
        // ─────────────────────────────────────────────
        const presets = [
            {
                code: "laptop",
                desc: "Normal search — works correctly in both modes"
            },
            {
                code: "' OR '1'='1",
                desc: "Classic injection — makes WHERE clause always true"
            },
            {
                code: "' OR 1=1 --",
                desc: "With comment — comments out the rest of the query"
            },
            {
                code: "electronics' OR category='SYSTEM",
                desc: "Category bypass — injects a different category filter"
            },
            {
                code: "' OR hidden=true OR name='",
                desc: "Targets the hidden column directly"
            },
            {
                code: "x' OR 'x'='x",
                desc: "Always-true condition using string equality"
            },
            {
                code: "keyboard",
                desc: "Normal partial search — safe in both modes"
            },
            {
                code: "'; DROP TABLE products; --",
                desc: "DROP TABLE attempt (simulated — shows the concept)"
            },
        ];

        // ─────────────────────────────────────────────
        // RENDER DATABASE TABLE
        // ─────────────────────────────────────────────
        function renderDatabaseTable() {
            const tbody = document.getElementById('dbTableBody');
            tbody.innerHTML = database.map(row => `
                <tr class="${row.hidden ? 'hidden-row' : ''}">
                    <td>${row.id}</td>
                    <td>
                        ${row.name}
                        ${row.hidden ? '<span class="hidden-badge">HIDDEN</span>' : ''}
                    </td>
                    <td>${row.category}</td>
                    <td>$${row.price.toFixed(2)}</td>
                    <td>${row.stock}</td>
                    <td>${row.hidden
                        ? '<span style="color:#ff6666">🔒 Restricted</span>'
                        : '<span style="color:#44ff88">✓ Public</span>'
                    }</td>
                </tr>
            `).join('');
        }

        // ─────────────────────────────────────────────
        // RENDER PRESETS
        // ─────────────────────────────────────────────
        function renderPresets() {
            const grid = document.getElementById('presetGrid');
            grid.innerHTML = presets.map(p => `
                <button class="preset-btn" onclick="applyPreset(${JSON.stringify(p.code)})">
                    <span class="preset-code">${escapeHtml(p.code)}</span>
                    <span class="preset-desc">${p.desc}</span>
                </button>
            `).join('');
        }

        function applyPreset(code) {
            document.getElementById('vulnerableInput').value = code;
            document.getElementById('safeInput').value = code;
            runVulnerableSearch();
            runSafeSearch();
        }

        // ─────────────────────────────────────────────
        // SYNC INPUTS
        // ─────────────────────────────────────────────
        function syncInputs(source) {
            const val = document.getElementById(
                source === 'vulnerable' ? 'vulnerableInput' : 'safeInput'
            ).value;
            document.getElementById(
                source === 'vulnerable' ? 'safeInput' : 'vulnerableInput'
            ).value = val;
        }

        // ─────────────────────────────────────────────
        // VULNERABLE SEARCH — simulates string concatenation
        // ─────────────────────────────────────────────
        function runVulnerableSearch() {
            const input = document.getElementById('vulnerableInput').value;

            // Show the "constructed query" as it would look with string concatenation
            const constructedQuery = `SELECT * FROM products WHERE (name LIKE '%${input}%' OR category LIKE '%${input}%') AND visible = true`;

            // Highlight the injected portion
            const safeInput = escapeHtml(input);
            const displayQuery = `SELECT * FROM products WHERE (name LIKE '<span class="highlight-injection">%${safeInput}%</span>' OR category LIKE '<span class="highlight-injection">%${safeInput}%</span>') AND visible = true`;
            document.getElementById('vulnerableQuery').innerHTML = displayQuery;

            // Detect if this looks like a DROP attempt
            const upperInput = input.toUpperCase();
            if (upperInput.includes('DROP') || upperInput.includes('DELETE') || upperInput.includes('TRUNCATE')) {
                document.getElementById('vulnerableResults').innerHTML = `
                    <div class="status-bar status-danger">
                        ⚠️ Destructive query detected! In a real database, this could delete or destroy data.
                        This simulation skips execution to protect the demo data.
                    </div>
                    <div class="no-results">Destructive operation simulated — no results shown</div>
                `;
                document.getElementById('vulnerableStatus').innerHTML = `
                    <div class="status-bar status-danger">🚨 INJECTION DETECTED — Destructive SQL attempted</div>
                `;
                return;
            }

            // Simulate the vulnerable evaluation:
            // We parse the input for OR conditions that would make the filter always true
            const results = simulateVulnerableQuery(input);

            renderResults('vulnerableResults', results, true);
            renderVulnerableStatus(input, results);
        }

        // ─────────────────────────────────────────────
        // SAFE SEARCH — simulates parameterized query
        // ─────────────────────────────────────────────
        function runSafeSearch() {
            const input = document.getElementById('safeInput').value;

            // Show the parameterized template + bound value separately
            document.getElementById('safeQuery').innerHTML =
                `Template: SELECT * FROM products WHERE (name LIKE <span class="highlight-param">?</span> OR category LIKE <span class="highlight-param">?</span>) AND visible = true\n` +
                `Bound value: <span class="highlight-param">"${escapeHtml(input)}"</span> (treated as literal string data)`;

            // Safe: just do a literal string match — no SQL parsing of input
            const searchTerm = input.toLowerCase().trim();
            const results = database.filter(row =>
                !row.hidden &&
                (
                    row.name.toLowerCase().includes(searchTerm) ||
                    row.category.toLowerCase().includes(searchTerm)
                )
            );

            renderResults('safeResults', results, false);
            renderSafeStatus(input, results);
        }

        // ─────────────────────────────────────────────
        // SIMULATE VULNERABLE QUERY EVALUATION
        // This mimics how SQL injection exploits work by
        // detecting common injection patterns and acting on them.
        // ─────────────────────────────────────────────
        function simulateVulnerableQuery(input) {
            const upper = input.toUpperCase().trim();

            // Detect always-true injection patterns
            const alwaysTruePatterns = [
                /'\s*OR\s*'1'\s*=\s*'1/i,
                /'\s*OR\s*1\s*=\s*1/i,
                /'\s*OR\s*'x'\s*=\s*'x/i,
                /'\s*OR\s*'\w+'\s*=\s*'\w+/i,
                /'\s*OR\s+\w+\s*=\s*\w+/i,
                /OR\s+TRUE/i,
            ];

            const isAlwaysTrue = alwaysTruePatterns.some(p => p.test(input));

            // Detect hidden column targeting
            const targetsHidden = /hidden\s*=\s*true/i.test(input);

            // Detect category injection
            const categoryMatch = input.match(/category\s*=\s*'?([^'"\s]+)/i);

            if (isAlwaysTrue || targetsHidden) {
                // Return ALL rows including hidden — injection succeeded
                return database.map(r => ({ ...r, injected: true }));
            }

            if (categoryMatch) {
                const injectedCategory = categoryMatch[1].toUpperCase();
                return database.filter(row =>
                    row.category.toUpperCase() === injectedCategory ||
                    (!row.hidden && (
                        row.name.toLowerCase().includes(input.split("'")[0].toLowerCase()) ||
                        row.category.toLowerCase().includes(input.split("'")[0].toLowerCase())
                    ))
                ).map(r => ({ ...r, injected: r.hidden }));
            }

            // Normal (non-injected) vulnerable query — still filters hidden
            // but only because the injection didn't trigger
            const searchTerm = input.toLowerCase().trim();
            return database.filter(row =>
                !row.hidden &&
                (
                    row.name.toLowerCase().includes(searchTerm) ||
                    row.category.toLowerCase().includes(searchTerm)
                )
            );
        }

        // ─────────────────────────────────────────────
        // RENDER RESULTS
        // ─────────────────────────────────────────────
        function renderResults(containerId, results, showLeakedBadge) {
            const container = document.getElementById(containerId);

            if (results.length === 0) {
                container.innerHTML = '<div class="no-results">🔍 No products found matching your search</div>';
                return;
            }

            const countBadge = `<div class="count-badge">${results.length} result${results.length !== 1 ? 's' : ''} returned</div>`;

            const cards = results.map(row => {
                const isLeaked = row.hidden || row.injected;
                return `
                    <div class="result-card ${isLeaked ? 'leaked' : ''}">
                        <div>
                            <div class="product-name">${escapeHtml(row.name)}</div>
                            <div class="product-meta">${row.category} · Stock: ${row.stock}</div>
                        </div>
                        <div style="display:flex;align-items:center;gap:8px;">
                            <span class="product-price">$${row.price.toFixed(2)}</span>
                            ${isLeaked && showLeakedBadge ? '<span class="leaked-badge">⚠ LEAKED</span>' : ''}
                        </div>
                    </div>
                `;
            }).join('');

            container.innerHTML = countBadge + cards;
        }

        // ─────────────────────────────────────────────
        // STATUS BARS
        // ─────────────────────────────────────────────
        function renderVulnerableStatus(input, results) {
            const statusEl = document.getElementById('vulnerableStatus');
            const hasLeaked = results.some(r => r.hidden || r.injected);

            if (!input.trim()) {
                statusEl.innerHTML = '';
                return;
            }

            if (hasLeaked) {
                statusEl.innerHTML = `
                    <div class="status-bar status-danger">
                        🚨 INJECTION SUCCESSFUL — ${results.filter(r => r.hidden).length} hidden/sensitive record(s) exposed!
                    </div>
                `;
            } else if (input.includes("'") || input.toUpperCase().includes(' OR ')) {
                statusEl.innerHTML = `
                    <div class="status-bar status-danger">
                        ⚠️ Injection attempt detected in input — this pattern could be dangerous
                    </div>
                `;
            } else {
                statusEl.innerHTML = `
                    <div class="status-bar status-neutral">
                        ℹ️ Normal search executed — no injection triggered this time
                    </div>
                `;
            }
        }

        function renderSafeStatus(input, results) {
            const statusEl = document.getElementById('safeStatus');

            if (!input.trim()) {
                statusEl.innerHTML = '';
                return;
            }

            if (input.includes("'") || input.toUpperCase().includes(' OR ')) {
                statusEl.innerHTML = `
                    <div class="status-bar status-success">
                        ✅ Injection attempt neutralized — input treated as literal string data
                    </div>
                `;
            } else {
                statusEl.innerHTML = `
                    <div class="status-bar status-success">
                        ✅ Safe query executed — parameterized filtering applied
                    </div>
                `;
            }
        }

        // ─────────────────────────────────────────────
        // UTILITY
        // ─────────────────────────────────────────────
        function escapeHtml(str) {
            return String(str)
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .replace(/"/g, '&quot;')
                .replace(/'/g, '&#39;');
        }

        // ─────────────────────────────────────────────
        // KEYBOARD SUPPORT
        // ─────────────────────────────────────────────
        document.addEventListener('DOMContentLoaded', () => {
            renderDatabaseTable();
            renderPresets();

            ['vulnerableInput', 'safeInput'].forEach(id => {
                document.getElementById(id).addEventListener('keydown', e => {
                    if (e.key === 'Enter') {
                        runVulnerableSearch();
                        runSafeSearch();
                    }
                });
            });
        });
    </script>

</body>
