<span class="comment">// ✅ SAFE CODE</span>
<span class="keyword">const</span> <span class="variable">query</span> = 
  <span class="string">"SELECT * FROM products "</span> +
  <span class="string">"WHERE name LIKE ?"</span>;  <span class="comment">// placeholder</span>

<span class="keyword">const</span> <span class="variable">params</span> = [<span class="string">`%${userInput}%`</span>];

<span class="function">db.execute</span>(<span class="variable">query</span>, <span class="variable">params</span>);
<span class="comment">// DB driver escapes input automatically</span>

<span class="comment">// If userInput = "' OR '1'='1"</span>
<span class="comment">// Searches literally for:</span>
<span class="comment">// "%' OR '1'='1%"  → 0 results ✅</span>
