<script>
/* ────────────────────────────────────────────────────────────────
   THE SINGLETON
──────────────────────────────────────────────────────────────── */
class ThemeManager {
  static _instance = null;

  constructor() {
    // Guard clause — if an instance already exists, return it.
    if (ThemeManager._instance) {
      return ThemeManager._instance;
    }

    // First (and only) initialisation.
    this._theme       = 'light';
    this._toggleCount = 0;
    this._listeners   = new Set();
    this._id          = `tm_${Date.now()}`;
    this._lastChanged = null;

    ThemeManager._instance = this;
    Object.freeze(ThemeManager); // prevent static property tampering
  }

  // ── Public factory ────────────────────────────────────────────
  static getInstance() {
    if (!ThemeManager._instance) {
      new ThemeManager();
    }
    return ThemeManager._instance;
  }

  // ── Core toggle ───────────────────────────────────────────────
  toggle() {
    this._theme       = this._theme === 'light' ? 'dark' : 'light';
    this._toggleCount++;
    this._lastChanged = new Date().toLocaleTimeString();
    this._applyToDOM();
    this._notify();
  }

  // ── Apply to document ─────────────────────────────────────────
  _applyToDOM() {
    document.documentElement.setAttribute('data-theme', this._theme);
  }

  // ── Observer support ──────────────────────────────────────────
  subscribe(fn)   { this._listeners.add(fn); }
  unsubscribe(fn) { this._listeners.delete(fn); }
  _notify()       { this._listeners.forEach(fn => fn(this._theme)); }

  // ── Getters ───────────────────────────────────────────────────
  get theme()         { return this._theme; }
  get toggleCount()   { return this._toggleCount; }
  get id()            { return this._id; }
  get listenerCount() { return this._listeners.size; }
  get lastChanged()   { return this._lastChanged ?? 'never'; }
}

// Expose globally so the reader can inspect it in DevTools.
window.ThemeManager = ThemeManager;


/* ────────────────────────────────────────────────────────────────
   WIRING
──────────────────────────────────────────────────────────────── */
(function init() {
  const manager  = ThemeManager.getInstance();

  const checkbox = document.getElementById('themeCheckbox');
  const label    = document.getElementById('themeLabel');

  // ── State panel elements ──────────────────────────────────────
  const elId      = document.getElementById('instanceId');
  const elTheme   = document.getElementById('currentTheme');
  const elCount   = document.getElementById('toggleCount');
  const elListen  = document.getElementById('listenerCount');
  const elChanged = document.getElementById('lastChanged');

  // ── Update the live state panel ───────────────────────────────
  function updatePanel(theme) {
    elId.textContent      = manager.id;
    elTheme.textContent   = theme;
    elCount.textContent   = manager.toggleCount;
    elListen.textContent  = manager.listenerCount;
    elChanged.textContent = manager.lastChanged;
    label.textContent     = theme === 'dark' ? 'Dark' : 'Light';
    checkbox.checked      = theme === 'dark';
  }

  // Subscribe the panel updater as a listener on the singleton.
  manager.subscribe(updatePanel);

  // ── Toggle handler ────────────────────────────────────────────
  checkbox.addEventListener('change', () => {
    manager.toggle();
  });

  // ── Initialise panel with starting state ─────────────────────
  updatePanel(manager.theme);

  // ── Prove singleton identity in the console ───────────────────
  const a = ThemeManager.getInstance();
  const b = ThemeManager.getInstance();
  console.log('%c[Singleton Demo]', 'color:#60a5fa;font-weight:bold',
    'a === b ?', a === b,
    '| Instance ID:', a.id
  );
  console.log(
    '%cTry: ThemeManager.getInstance().toggle()',
    'color:#34d399;font-style:italic'
  );
})();
</script>
</body>
</html>
```

## What's inside and why

### Singleton implementation
The `ThemeManager` class uses a **private static `_instance` slot** as the guard. The constructor checks for an existing instance and returns it early — so even `new ThemeManager()` called twice gives you the same object. `getInstance()` is the canonical public entry point. `Object.freeze(ThemeManager)` prevents external code from overwriting the static slot.

### Theme switching mechanism
Rather than touching individual elements with JavaScript, a single `data-theme` attribute is written to `<html>`. CSS custom properties cascade from there, so **every styled element updates in one paint** with no DOM iteration.

### Singleton analysis section covers
| Topic | Detail |
|---|---|
| **Pros** | Single source of truth, lazy init, reduced memory, global access |
| **Cons** | Hidden state, tight coupling, untestable, violates SRP |
| **Alternatives** | DI, React Context, ES module exports, Zustand/Redux |

### Comparison table
Shows Singleton vs Dependency Injection vs Module Export across testability, explicitness, boilerplate, and best-use scenarios.

### Content variety to stress-test the theme
Cards, code blocks with syntax highlighting, forms, progress bars, a comparison table, blockquote, tag cloud, nav, hero, and footer — all switch cleanly between light and dark.

