  <script>
    // ─────────────────────────────────────────────
    // Regex Definitions
    // ─────────────────────────────────────────────
    const SIMPLE_RE   = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const MODERATE_RE = /^[\w._%+\-]+@[\w.\-]+\.[a-zA-Z]{2,}$/;

    // ─────────────────────────────────────────────
    // Live Validation Logic
    // ─────────────────────────────────────────────
    function applyFeedback(inputEl, iconEl, hintEl, isValid, isEmpty) {
      inputEl.classList.remove('valid', 'invalid', 'empty');
      if (isEmpty) {
        inputEl.classList.add('empty');
        iconEl.textContent = '';
        hintEl.textContent = 'Start typing to see feedback';
        hintEl.className = 'hint neu';
        return;
      }
      if (isValid) {
        inputEl.classList.add('valid');
        iconEl.textContent = '✅';
        hintEl.textContent = 'Looks valid (syntax only — not deliverability!)';
        hintEl.className = 'hint ok';
      } else {
        inputEl.classList.add('invalid');
        iconEl.textContent = '❌';
        hintEl.textContent = 'Does not match the regex pattern';
        hintEl.className = 'hint err';
      }
    }

    function wireInput(inputId, iconId, hintId, regexOrFn) {
      const input = document.getElementById(inputId);
      const icon  = document.getElementById(iconId);
      const hint  = document.getElementById(hintId);

      const validate = (typeof regexOrFn === 'function')
        ? regexOrFn
        : (v) => regexOrFn.test(v);

      input.addEventListener('input', () => {
        const val = input.value;
        if (val === '') { applyFeedback(input, icon, hint, false, true); return; }
        applyFeedback(input, icon, hint, validate(val), false);
      });
    }

    // HTML5 type="email" uses the browser's internal algorithm
    function html5Valid(val) {
      const probe = document.createElement('input');
      probe.type  = 'email';
      probe.value = val;
      return probe.validity.valid;
    }

    wireInput('email-simple',   'icon-simple',   'hint-simple',   SIMPLE_RE);
    wireInput('email-moderate', 'icon-moderate', 'hint-moderate', MODERATE_RE);
    wireInput('email-html5',    'icon-html5',    'hint-html5',    html5Valid);

    // ─────────────────────────────────────────────
    // Test Cases
    // Format: [address, rfcValid (bool), note]
    // ─────────────────────────────────────────────
    const TEST_CASES = [
      // ── Clearly valid ──
      ['user@example.com',              true,  'Standard valid'],
      ['user.name+tag@sub.example.co.uk', true, 'Subaddress + subdomain'],
      ['x@x.io',                        true,  'Short but valid'],

      // ── Valid per RFC but regex often rejects ──
      ['"john..doe"@example.com',       true,  'Quoted local part (RFC 5321)'],
      ['"very unusual"@example.com',    true,  'Quoted with space'],
      ['user@[192.168.1.1]',            true,  'IP literal domain (RFC 5321)'],
      ['user@[IPv6:2001:db8::1]',       true,  'IPv6 literal domain'],
      ['用户@例子.广告',                  true,  'Full Unicode (RFC 6531)'],
      ['θσερ@εχαμπλε.ψομ',             true,  'Greek Unicode'],
      ['user@travelersinsurance.com',   true,  'Long TLD (24 chars)'],
      ['user@museum.example',           true,  '.museum TLD'],
      ['admin@mailserver1',             true,  'No dot in domain (RFC allows)'],

      // ── Invalid per RFC but regex often accepts ──
      ['user@',                         false, 'Missing domain'],
      ['@example.com',                  false, 'Missing local part'],
      ['user@.example.com',             false, 'Domain starts with dot'],
      ['user..name@example.com',        false, 'Consecutive dots (unquoted)'],
      ['user@example..com',             false, 'Consecutive dots in domain'],
      ['user @example.com',             false, 'Space in local part'],
      ['user@exam ple.com',             false, 'Space in domain'],
      ['.user@example.com',             false, 'Leading dot in local part'],
      ['user.@example.com',             false, 'Trailing dot in local part'],

      // ── Tricky edge cases ──
      ['plainaddress',                  false, 'No @ at all'],
      ['user@com',                      false, 'TLD only domain (debatable)'],
      ['a@b.c',                         true,  'Minimal valid (single-char TLD)'],
      ['user@-example.com',             false, 'Domain starts with hyphen'],
      ['user@example-.com',             false, 'Domain ends with hyphen'],
    ];

    // ─────────────────────────────────────────────
    // Render test grid
    // ─────────────────────────────────────────────
    function badgeFor(regexResult, rfcValid) {
      if (regexResult === rfcValid) {
        return `<span class="badge pass">✓ correct</span>`;
      }
      if (regexResult && !rfcValid) {
        return `<span class="badge warn">⚠ false +</span>`;
      }
      return `<span class="badge fail">✗ false −</span>`;
    }

    const grid = document.getElementById('test-grid');

    TEST_CASES.forEach(([email, rfcValid, note]) => {
      const simpleResult   = SIMPLE_RE.test(email);
      const moderateResult = MODERATE_RE.test(email);

      const emailCell = document.createElement('div');
      emailCell.className = 'email-cell';
      emailCell.innerHTML = `
        ${escHtml(email)}
        <br/>
        <span style="font-family:sans-serif;font-size:0.7rem;color:#475569;">${escHtml(note)}</span>
        <span class="badge ${rfcValid ? 'valid' : 'fail'}" style="margin-left:0.3rem;font-size:0.65rem;">
          RFC: ${rfcValid ? 'valid' : 'invalid'}
        </span>
      `;

      const simpleCell   = document.createElement('div');
      simpleCell.innerHTML = badgeFor(simpleResult, rfcValid);

      const moderateCell = document.createElement('div');
      moderateCell.innerHTML = badgeFor(moderateResult, rfcValid);

      grid.appendChild(emailCell);
      grid.appendChild(simpleCell);
      grid.appendChild(moderateCell);
    });

    function escHtml(str) {
      return str
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
    }
  </script>
</body>
</html>
```

---

## What's inside and why each decision was made

| Section | What it does | Key design choice |
|---|---|---|
| **Live inputs** | Three inputs, each using a different validation strategy | Lets you *feel* the difference in real time |
| **Simple regex** | `/^[^\s@]+@[^\s@]+\.[^\s@]+$/` | Intentionally permissive to show false positives |
| **Moderate regex** | `/^[\w._%+\-]+@[\w.\-]+\.[a-zA-Z]{2,}$/` | The "standard" tutorial regex — still wrong |
| **HTML5 type=email** | Browser's built-in algorithm via `validity.valid` | A WHATWG "willful violation" of RFC 5322 — pragmatic but incomplete |
| **Test case grid** | 25 addresses with RFC ground truth | Badges show ✓ correct, ⚠ false positive, ✗ false negative |
| **Limitations section** | 7 fundamental reasons regex fails | Grounded in RFC 5321/5322/6531 citations |
| **Alternatives section** | 6 production strategies with pros/cons | Layered approach recommended |

The core honest takeaway: **use regex only as a first-pass UX hint, never as a security or correctness gate**, and always verify via a confirmation email.

