      </div>
<pre><code><span class="kw">class</span> <span class="fn">ThemeManager</span> {
  <span class="cm">// Private static field holds the single instance</span>
  <span class="kw">static</span> #instance = <span class="kw">null</span>;

  <span class="fn">constructor</span>() {
    <span class="kw">if</span> (<span class="fn">ThemeManager</span>.#instance) {
      <span class="kw">throw new</span> <span class="fn">Error</span>(<span class="str">"Use ThemeManager.getInstance()"</span>);
    }
    <span class="kw">this</span>.theme      = <span class="kw">this</span>.<span class="fn">_loadTheme</span>();
    <span class="kw">this</span>.subscribers = [];
    <span class="kw">this</span>.<span class="fn">_apply</span>();
  }

  <span class="cm">/** Returns the single shared instance (creates it on first call) */</span>
  <span class="kw">static</span> <span class="fn">getInstance</span>() {
    <span class="kw">if</span> (!<span class="fn">ThemeManager</span>.#instance) {
      <span class="fn">ThemeManager</span>.#instance = <span class="kw">new</span> <span class="fn">ThemeManager</span>();
    }
    <span class="kw">return</span> <span class="fn">ThemeManager</span>.#instance;
  }

  <span class="fn">toggle</span>() {
    <span class="kw">this</span>.theme = <span class="kw">this</span>.theme === <span class="str">"light"</span> ? <span class="str">"dark"</span> : <span class="str">"light"</span>;
    <span class="kw">this</span>.<span class="fn">_apply</span>();
    <span class="kw">this</span>.<span class="fn">_save</span>();
    <span class="kw">this</span>.<span class="fn">_notify</span>();
  }

  <span class="fn">subscribe</span>(callback) {
    <span class="kw">this</span>.subscribers.<span class="fn">push</span>(callback);
    <span class="kw">return</span> () => {   <span class="cm">// returns unsubscribe fn</span>
      <span class="kw">this</span>.subscribers = <span class="kw">this</span>.subscribers
        .<span class="fn">filter</span>(cb => cb !== callback);
    };
  }

  <span class="fn">_apply</span>()  { document.body.dataset.theme = <span class="kw">this</span>.theme; }
  <span class="fn">_save</span>()   { localStorage.<span class="fn">setItem</span>(<span class="str">"theme"</span>, <span class="kw">this</span>.theme); }
  <span class="fn">_notify</span>() { <span class="kw">this</span>.subscribers.<span class="fn">forEach</span>(cb => <span class="fn">cb</span>(<span class="kw">this</span>.theme)); }
  <span class="fn">_loadTheme</span>() {
    <span class="kw">return</span> localStorage.<span class="fn">getItem</span>(<span class="str">"theme"</span>)
      ?? (window.matchMedia(<span class="str">"(prefers-color-scheme: dark)"</span>).matches
          ? <span class="str">"dark"</span> : <span class="str">"light"</span>);
  }
}</code></pre>
