class ThemeManager {

  static #instance = null;

  #theme       = 'light';
  #listeners   = new Set();
  #toggleCount = 0;

  constructor() {
    if (ThemeManager.#instance) {
      throw new Error('Use ThemeManager.getInstance()');
    }
    this.#init();
  }

  static getInstance() {
    if (!ThemeManager.#instance) {
      ThemeManager.#instance = new ThemeManager();
    }
    return ThemeManager.#instance;
  }

  #init() {
    const saved      = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    this.#theme = saved ?? (prefersDark ? 'dark' : 'light');
    this.#apply();

    // Also react to OS-level changes while the page is open
    window.matchMedia('(prefers-color-scheme: dark)')
      .addEventListener('change', e => {
        if (!localStorage.getItem('theme')) {
          this.#theme = e.matches ? 'dark' : 'light';
          this.#apply();
        }
      });
  }

  #apply() {
    document.documentElement.setAttribute('data-theme', this.#theme);
    localStorage.setItem('theme', this.#theme);
    this.#notify();
  }

  toggle() {
    this.#theme = this.#theme === 'light' ? 'dark' : 'light';
    this.#toggleCount++;
    this.#apply();
    this.#flashEffect();
  }

  setTheme(name) {
    if (!['light', 'dark'].includes(name)) return;
    if (name === this.#theme) return;
    this.#theme = name;
    this.#toggleCount++;
    this.#apply();
  }

  // Brief visual flash to make the switch feel snappy
  #flashEffect() {
    const el = document.getElementById('themeFlash');
    if (!el) return;
    el.classList.add('active');
    setTimeout(() => el.classList.remove('active'), 150);
  }

  get theme()       { return this.#theme; }
  get isDark()      { return this.#theme === 'dark'; }
  get toggleCount() { return this.#toggleCount; }
  get listenerCount(){ return this.#listeners.size; }

  subscribe(fn)   { this.#listeners.add(fn);    return () => this.unsubscribe(fn); }
  unsubscribe(fn) { this.#listeners.delete(fn); }
  #notify()       { this.#listeners.forEach(fn => fn(this.#theme)); }
}


/* ================================================================
   2.  BOOTSTRAP — wire up the UI to the Singleton
================================================================ */
(function bootstrap() {
  const tm = ThemeManager.getInstance();

  // ── Nav toggle button ─────────────────────────────────────────
  const toggleBtn   = document.getElementById('themeToggle');
  const toggleLabel = document.getElementById('toggleLabel');
  const toggleThumb = document.getElementById('toggleThumb');

  function syncToggleButton(theme) {
    const isDark = theme === 'dark';
    toggleBtn.setAttribute('aria-pressed', isDark);
    toggleLabel.textContent = isDark ? 'Dark' : 'Light';
    toggleThumb.textContent = isDark ? '🌙' : '☀️';
  }

  toggleBtn.addEventListener('click', () => tm.toggle());

  // ── Theme selector in the form ────────────────────────────────
  const themeSelect = document.getElementById('themeSelect');
  function syncSelect(theme) {
    themeSelect.value = theme;
  }

  // ── Stats panel ───────────────────────────────────────────────
  const statToggle   = document.getElementById('statToggleCount');
  const statListeners= document.getElementById('statListeners');
  const statTheme    = document.getElementById('statTheme');

  function bumpNumber(el) {
    el.classList.remove('bump');
    void el.offsetWidth; // reflow to restart animation
    el.classList.add('bump');
    setTimeout(() => el.classList.remove('bump'), 150);
  }

  function syncStats(theme) {
    statToggle.textContent  = tm.toggleCount;
    statListeners.textContent = tm.listenerCount;
    statTheme.textContent   = theme === 'dark' ? '🌙' : '☀️';
    bumpNumber(statToggle);
    bumpNumber(statTheme);
  }

  // ── Footer ────────────────────────────────────────────────────
  const footerTheme = document.getElementById('footerTheme');
  function syncFooter(theme) {
    footerTheme.textContent = theme === 'dark' ? 'Dark mode' : 'Light mode';
  }

  // ── Register ALL subscribers — they all point to the same instance ──
  //    This proves the Singleton: no matter how many subscribers,
  //    they all receive the same event from the same source.
  const unsub1 = tm.subscribe(syncToggleButton);
  const unsub2 = tm.subscribe(syncSelect);
  const unsub3 = tm.subscribe(syncStats);
  const unsub4 = tm.subscribe(syncFooter);

  // Initial sync (no toggle has happened yet)
  syncToggleButton(tm.theme);
  syncSelect(tm.theme);
  syncStats(tm.theme);
  syncFooter(tm.theme);

  // Update listener count display after subscribing
  statListeners.textContent = tm.listenerCount;

  // Log to console so developers can inspect
  console.log(
    '%c[ThemeManager] Singleton initialised',
    'color:#6366f1;font-weight:bold',
    { instance: tm, theme: tm.theme }
  );

  // ── Demonstrate singleton identity in console ─────────────────
  const a = ThemeManager.getInstance();
  const b = ThemeManager.getInstance();
  console.assert(a === b, 'Should be the same instance');
  console.log('%c[ThemeManager] a === b:', 'color:#10b981;font-weight:bold', a === b);
})();


