     JAVASCRIPT
═══════════════════════════════════════════════ -->
<script>
(() => {
  'use strict';

  /* ── DOM refs ── */
  const canvas   = document.getElementById('tree-canvas');
  const ctx      = canvas.getContext('2d');
  const slider   = document.getElementById('depth-slider');
  const badge    = document.getElementById('depth-badge');
  const statBr   = document.getElementById('stat-branches');
  const statFr   = document.getElementById('stat-frames');
  const statTm   = document.getElementById('stat-time');
  const warning  = document.getElementById('warning-banner');

  /* ── Branch colours keyed by remaining depth ── */
  const BRANCH_COLORS = [
    '#52d65a', // depth 0 remaining → leaf tips (bright green)
    '#6bcf55',
    '#85c850',
    '#9ec04a',
    '#b8b845',
    '#c9a03d',
    '#c08030',
    '#b06025',
    '#9a4820',
    '#85341a',
    '#6e2215',
    '#5a1510', // deepest trunk
  ];

  function branchColor(depthRemaining, maxDepth) {
    const idx = Math.round(
      ((maxDepth - depthRemaining) / maxDepth) * (BRANCH_COLORS.length - 1)
    );
    return BRANCH_COLORS[Math.min(idx, BRANCH_COLORS.length - 1)];
  }

  /* ── Build colour legend ── */
  (function buildLegend() {
    const legend = document.getElementById('legend');
    const labels = ['Trunk', '', '', '', '', 'Mid', '', '', '', '', '', 'Leaves'];
    BRANCH_COLORS.slice().reverse().forEach((col, i) => {
      const item  = document.createElement('div');
      item.className = 'legend-item';
      const swatch = document.createElement('div');
      swatch.className = 'legend-swatch';
      swatch.style.background = col;
      item.appendChild(swatch);
      const lbl = labels[i] ? document.createElement('span') : null;
      if (lbl) { lbl.textContent = labels[i]; item.appendChild(lbl); }
      legend.appendChild(item);
    });
  })();

  /* ── Core recursive draw function ── */
  let branchCount = 0;

  function drawBranch(x, y, length, angle, depth, maxDepth) {
    if (depth === 0) return;

    const x2 = x + Math.cos(angle) * length;
    const y2 = y + Math.sin(angle) * length;

    /* Line width tapers from trunk to tip */
    ctx.lineWidth   = Math.max(0.5, (depth / maxDepth) * 8);
    ctx.strokeStyle = branchColor(depth, maxDepth);

    ctx.beginPath();
    ctx.moveTo(x,  y);
    ctx.lineTo(x2, y2);
    ctx.stroke();

    branchCount++;

    const childLen = length * 0.70;
    const SPREAD   = 0.436; // radians ≈ 25°

    drawBranch(x2, y2, childLen, angle - SPREAD, depth - 1, maxDepth);
    drawBranch(x2, y2, childLen, angle + SPREAD, depth - 1, maxDepth);
  }

  /* ── Main draw routine ── */
  function draw(depth) {
    const W = canvas.width;
    const H = canvas.height;

    /* Clear */
    ctx.clearRect(0, 0, W, H);

    /* Subtle gradient sky */
    const sky = ctx.createLinearGradient(0, 0, 0, H);
    sky.addColorStop(0, '#0a0e14');
    sky.addColorStop(1, '#0d1117');
    ctx.fillStyle = sky;
    ctx.fillRect(0, 0, W, H);

    /* Ground line */
    ctx.strokeStyle = '#21262d';
    ctx.lineWidth   = 1;
    ctx.beginPath();
    ctx.moveTo(0, H - 20);
    ctx.lineTo(W, H - 20);
    ctx.stroke();

    branchCount = 0;
    const t0 = performance.now();

    const trunkLength = H * 0.22;
    drawBranch(
      W / 2,          // start x  – horizontal centre
      H - 20,         // start y  – just above ground
      trunkLength,
      -Math.PI / 2,   // pointing straight up
      depth,
      depth
    );

    const elapsed = (performance.now() - t0).toFixed(2);

    /* Update stats */
    statBr.textContent = branchCount.toLocaleString();
    statFr.textContent = (depth + 1).toString();   // max simultaneous frames
    statTm.textContent = elapsed + ' ms';

    /* Warning banner */
    if (depth >= 11) {
      warning.classList.add('visible');
    } else {
      warning.classList.remove('visible');
    }
  }

  /* ── Slider event ── */
  function onSliderChange() {
    const depth = parseInt(slider.value, 10);
    badge.textContent = depth;
    draw(depth);
  }

  slider.addEventListener('input', onSliderChange);

  /* ── Initial render ── */
  onSliderChange();

  /* ── Resize: keep canvas crisp on HiDPI screens ── */
  function resizeCanvas() {
    const card    = canvas.parentElement;
    const cssW    = card.clientWidth - 32; // subtract card padding
    const dpr     = window.devicePixelRatio || 1;
    const physW   = Math.round(cssW * dpr);
    const physH   = Math.round(physW * (480 / 620) * dpr);

    if (canvas.width !== physW || canvas.height !== physH) {
      canvas.width  = physW;
      canvas.height = physH;
      canvas.style.width  = cssW + 'px';
      canvas.style.height = Math.round(cssW * (480 / 620)) + 'px';
      onSliderChange();
    }
  }

  window.addEventListener('resize', resizeCanvas);
  resizeCanvas();

})();
</script>
</body>
</html>
