<body>

<h1>Race Condition Demo</h1>
<p class="subtitle">Click "Spam +1 (×10)" to fire 10 async increments simultaneously and watch what happens</p>

<div class="panels">

  <!-- ========== BUGGY PANEL ========== -->
  <div class="panel buggy">
    <h2>⚠ Buggy Version</h2>
    <p class="desc">
      Reads counter into a local variable, waits async, then writes back.
      Concurrent calls all read the <em>same stale value</em>.
    </p>
    <div class="counter-display" id="buggy-counter">0</div>
    <div class="expected">Expected after spam: <span id="buggy-expected">—</span></div>
    <div class="btn-row">
      <button class="btn-increment" onclick="buggyIncrement()">+1</button>
      <button class="btn-spam"      onclick="buggySpam()">Spam +1 (×10)</button>
      <button class="btn-reset"     onclick="buggyReset()">Reset</button>
    </div>
    <div class="log-box" id="buggy-log"></div>
    <div class="diff-count" id="buggy-diff"></div>
  </div>

  <!-- ========== FIXED PANEL ========== -->
  <div class="panel fixed">
    <h2>✔ Fixed Version</h2>
    <p class="desc">
      Never holds a local copy. Always reads and writes the shared counter
      atomically <em>at the moment of the write</em>.
    </p>
    <div class="counter-display" id="fixed-counter">0</div>
    <div class="expected">Expected after spam: <span id="fixed-expected">—</span></div>
    <div class="btn-row">
      <button class="btn-increment" onclick="fixedIncrement()">+1</button>
      <button class="btn-spam"      onclick="fixedSpam()">Spam +1 (×10)</button>
      <button class="btn-reset"     onclick="fixedReset()">Reset</button>
    </div>
    <div class="log-box" id="fixed-log"></div>
    <div class="diff-count" id="fixed-diff"></div>
  </div>

</div>

<!-- ========== EXPLANATION ========== -->
<div class="explanation">
  <h2>🔍 Why Does This Break?</h2>

  <p>
    JavaScript is single-threaded, but <strong>asynchronous operations create interleaving</strong>.
    When you use <code>setTimeout</code> (or any async mechanism), the engine suspends that
    task and runs others before coming back. This produces a classic
    <strong>read–modify–write race condition</strong>.
  </p>

  <h3>The Buggy Pattern <span class="tag bug">BUG</span></h3>
  <pre><span class="cm">// Shared state</span>
<span class="kw">let</span> counter = <span class="num">0</span>;

<span class="kw">function</span> <span class="fn">buggyIncrement</span>() {
<span class="bad-line">  <span class="kw">const</span> current = counter;          <span class="cm">// 1. READ  — captures value NOW</span></span>
  <span class="fn">setTimeout</span>(() => {
<span class="bad-line">    counter = current + <span class="num">1</span>;           <span class="cm">// 2. WRITE — uses the stale snapshot</span></span>
  }, <span class="fn">Math</span>.random() * <span class="num">80</span>);
}</pre>

  <h3>The Race — Step by Step</h3>
  <ol class="race-steps">
    <li>Call #1 fires. It reads <code>counter = 0</code> and stores it in <code>current₁ = 0</code>.</li>
    <li>Call #2 fires immediately after. It also reads <code>counter = 0</code> → <code>current₂ = 0</code>.</li>
    <li>…calls #3 through #10 all do the same. They all captured <strong>0</strong>.</li>
    <li>Timeouts begin resolving. Call #1 writes <code>counter = 0 + 1 = 1</code>. ✓</li>
    <li>Call #2 writes <code>counter = 0 + 1 = 1</code>. It <strong>overwrites</strong> call #1's result.</li>
    <li>All 10 calls write <strong>1</strong>. Final value: <strong>1</strong> instead of <strong>10</strong>.</li>
  </ol>

  <h3>The Fixed Pattern <span class="tag fix">FIX</span></h3>
  <pre><span class="kw">let</span> counter = <span class="num">0</span>;

<span class="kw">function</span> <span class="fn">fixedIncrement</span>() {
  <span class="cm">// No local snapshot taken here</span>
  <span class="fn">setTimeout</span>(() => {
<span class="good-line">    counter = counter + <span class="num">1</span>;            <span class="cm">// READ + WRITE happen together at callback time</span></span>
  }, <span class="fn">Math</span>.random() * <span class="num">80</span>);
}</pre>

  <p>
    Because JavaScript callbacks execute on the <strong>single-threaded event loop</strong>,
    each callback runs to completion before the next one starts.
    Reading and writing <code>counter</code> inside the same callback is therefore
    <strong>atomic with respect to other callbacks</strong> — no other callback can
    sneak in between the read and the write.
  </p>

  <h3>The Key Insight</h3>
  <p>
    The bug is not about <em>when</em> the write happens — it's about
    <strong>which value is being written</strong>.
    Capturing state into a local variable before an async gap means you're
    scheduling a write of <em>yesterday's truth</em>.
    The fix keeps the read inside the callback so it always sees
    <em>today's truth</em> at the moment of execution.
  </p>

  <h3>Real-World Equivalents</h3>
  <p>
    This same pattern destroys correctness in: React <code>setState</code> calls
    that close over stale state (fix: use the updater form <code>setState(prev => prev + 1)</code>),
    database read-modify-write without transactions, and multi-threaded code
    without locks. The shape of the bug is always identical.
  </p>
</div>

<script>
  // ─── Shared state ──────────────────────────────────────────────
  let buggyCounter = 0;
  let fixedCounter = 0;

  // ─── Logging helpers ───────────────────────────────────────────
  function log(id, msg, cls) {
    const box = document.getElementById(id);
    const line = document.createElement('div');
    if (cls) line.className = cls;
    line.textContent = msg;
    box.appendChild(line);
    box.scrollTop = box.scrollHeight;
  }

  function setDisplay(id, val) {
    document.getElementById(id).textContent = val;
  }

  // ─── BUGGY implementation ──────────────────────────────────────
  // THE BUG: reads counter into a local variable BEFORE the async gap.
  // All concurrent calls capture the same stale snapshot and then
  // each overwrites the counter with (snapshot + 1), losing all
  // increments except the last one to write.

  function buggyIncrement(isSpam, spamId, expectedAfter) {
    const readValue = buggyCounter;          // ← stale snapshot captured HERE
    const delay = Math.floor(Math.random() * 80) + 10;

    if (isSpam) {
      log('buggy-log',
        `[spawn #${spamId}] read=${readValue}  delay=${delay}ms`,
        'log-info');
    }

    setTimeout(() => {
      const writtenValue = readValue + 1;    // ← uses the stale snapshot
      buggyCounter = writtenValue;
      setDisplay('buggy-counter', buggyCounter);

      if (isSpam) {
        const isRace = (buggyCounter !== expectedAfter) &&
                       (spamId < 10);        // not the last write yet — but value is wrong
        log('buggy-log',
          `[done  #${spamId}] wrote ${writtenValue}  counter=${buggyCounter}`,
          buggyCounter < expectedAfter ? 'log-race' : 'log-ok');

        if (spamId === 10) {
          const lost = expectedAfter - buggyCounter;
          const diffEl = document.getElementById('buggy-diff');
          if (lost > 0) {
            diffEl.textContent = `Lost ${lost} increment${lost > 1 ? 's' : ''}! Got ${buggyCounter}, expected ${expectedAfter}`;
            diffEl.className = 'diff-count bad';
          } else {
            diffEl.textContent = `Got lucky this time — try again!`;
            diffEl.className = 'diff-count good';
          }
        }
      }
    }, delay);
  }

  function buggySpam() {
    const before = buggyCounter;
    const expected = before + 10;
    setDisplay('buggy-expected', expected);
    document.getElementById('buggy-diff').textContent = '';
    log('buggy-log', `── spam start (counter=${before}, expect ${expected}) ──`, 'log-info');
    for (let i = 1; i <= 10; i++) {
      buggyIncrement(true, i, expected);
    }
  }

  function buggyReset() {
    buggyCounter = 0;
    setDisplay('buggy-counter', 0);
    setDisplay('buggy-expected', '—');
    document.getElementById('buggy-log').innerHTML = '';
    document.getElementById('buggy-diff').textContent = '';
  }

  // ─── FIXED implementation ──────────────────────────────────────
  // THE FIX: no local snapshot. The read and write both happen
  // inside the callback, which runs atomically on the event loop.
  // Each callback sees the latest committed value of fixedCounter.

  function fixedIncrement(isSpam, spamId, expectedAfter) {
    const delay = Math.floor(Math.random() * 80) + 10;

    if (isSpam) {
      log('fixed-log',
        `[spawn #${spamId}] (no snapshot)  delay=${delay}ms`,
        'log-info');
    }

    setTimeout(() => {
      fixedCounter = fixedCounter + 1;       // ← read + write atomically at callback time
      setDisplay('fixed-counter', fixedCounter);

      if (isSpam) {
        log('fixed-log',
          `[done  #${spamId}] counter=${fixedCounter}`,
          'log-ok');

        if (spamId === 10 || fixedCounter === expectedAfter) {
          // wait a tiny bit for all callbacks to finish before reporting
        }
      }
    }, delay);
  }

  // We need to detect when all 10 fixed callbacks have fired.
  // Use a simple completion counter per spam batch.
  function fixedSpam() {
    const before = fixedCounter;
    const expected = before + 10;
    setDisplay('fixed-expected', expected);
    document.getElementById('fixed-diff').textContent = '';
    log('fixed-log', `── spam start (counter=${before}, expect ${expected}) ──`, 'log-info');

    let completed = 0;
    for (let i = 1; i <= 10; i++) {
      const delay = Math.floor(Math.random() * 80) + 10;
      const spamId = i;
      log('fixed-log', `[spawn #${spamId}] (no snapshot)  delay=${delay}ms`, 'log-info');
      setTimeout(() => {
        fixedCounter = fixedCounter + 1;
        setDisplay('fixed-counter', fixedCounter);
        completed++;
        log('fixed-log',
          `[done  #${spamId}] counter=${fixedCounter}`,
          'log-ok');
        if (completed === 10) {
          const diffEl = document.getElementById('fixed-diff');
          const lost = expected - fixedCounter;
          if (lost === 0) {
            diffEl.textContent = `Perfect: got ${fixedCounter}, expected ${expected} ✓`;
            diffEl.className = 'diff-count good';
          } else {
            diffEl.textContent = `Unexpected: got ${fixedCounter}, expected ${expected}`;
            diffEl.className = 'diff-count bad';
          }
        }
      }, delay);
    }
  }

  function fixedReset() {
    fixedCounter = 0;
    setDisplay('fixed-counter', 0);
    setDisplay('fixed-expected', '—');
    document.getElementById('fixed-log').innerHTML = '';
    document.getElementById('fixed-diff').textContent = '';
  }
</script>
</body>
</html>
