<script>
  /* ─────────────────────────────────────────────
     Configuration
  ───────────────────────────────────────────── */
  const SPREAD = 0.42;   // branch angle spread (radians)
  const RATIO  = 0.67;   // length shrink ratio per level

  /* ─────────────────────────────────────────────
     Canvas setup
  ───────────────────────────────────────────── */
  const canvas  = document.getElementById('treeCanvas');
  const ctx     = canvas.getContext('2d');

  /* ─────────────────────────────────────────────
     DOM references
  ───────────────────────────────────────────── */
  const slider      = document.getElementById('depthSlider');
  const depthLabel  = document.getElementById('depthLabel');
  const branchCount = document.getElementById('branchCount');
  const stackDepth  = document.getElementById('stackDepth');
  const drawTimeEl  = document.getElementById('drawTime');
  const deepWarning = document.getElementById('deepWarning');
  const stackVis    = document.getElementById('stackVis');

  /* ─────────────────────────────────────────────
     Colour palette per depth level
  ───────────────────────────────────────────── */
  function branchColor(depth, maxDepth) {
    const t = 1 - depth / maxDepth;          // 0 = trunk, 1 = tip
    if (t < 0.35) {
      // trunk → dark brown
      const r = Math.round(80  + t * 60);
      const g = Math.round(45  + t * 30);
      const b = Math.round(20  + t * 10);
      return `rgb(${r},${g},${b})`;
    } else if (t < 0.75) {
      // mid → olive green
      const p = (t - 0.35) / 0.40;
      const r = Math.round(100 - p * 60);
      const g = Math.round(130 + p * 50);
      const b = Math.round(30  + p * 20);
      return `rgb(${r},${g},${b})`;
    } else {
      // tips → bright green / yellow-green
      const p = (t - 0.75) / 0.25;
      const r = Math.round(40  + p * 80);
      const g = Math.round(180 + p * 60);
      const b = Math.round(50  - p * 20);
      return `rgb(${r},${g},${b})`;
    }
  }

  /* ─────────────────────────────────────────────
     Recursive draw function
  ───────────────────────────────────────────── */
  let totalBranches = 0;

  function drawBranch(x, y, angle, length, depth, maxDepth) {
    if (depth === 0) return;

    const x2 = x + Math.cos(angle) * length;
    const y2 = y + Math.sin(angle) * length;

    ctx.beginPath();
    ctx.moveTo(x, y);
    ctx.lineTo(x2, y2);
    ctx.strokeStyle = branchColor(depth, maxDepth);
    ctx.lineWidth   = Math.max(0.5, depth * 0.9);
    ctx.lineCap     = 'round';
    ctx.stroke();

    totalBranches++;

    drawBranch(x2, y2, angle - SPREAD, length * RATIO, depth - 1, maxDepth);
    drawBranch(x2, y2, angle + SPREAD, length * RATIO, depth - 1, maxDepth);
  }

  /* ─────────────────────────────────────────────
     Update call-stack visualiser
  ───────────────────────────────────────────── */
  function updateStackVis(depth) {
    stackVis.innerHTML = '';
    const MAX_SHOW = 15;
    const frames = Math.min(depth, MAX_SHOW);

    for (let i = 0; i < frames; i++) {
      const frame = document.createElement('div');
      frame.className = 'stack-frame' + (i >= 12 ? ' overflow' : '');
      const barWidth = 80 + i * 14;
      frame.style.width = barWidth + 'px';
      frame.textContent = `drawBranch( depth=${depth - i} )`;
      stackVis.appendChild(frame);
    }

    if (depth > MAX_SHOW) {
      const more = document.createElement('div');
      more.style.cssText = 'font-size:0.75rem;color:#6a8aaa;margin-top:4px';
      more.textContent = `… and ${depth - MAX_SHOW} more frame(s)`;
      stackVis.appendChild(more);
    }
  }

  /* ─────────────────────────────────────────────
     Main render
  ───────────────────────────────────────────── */
  function render() {
    const depth = parseInt(slider.value, 10);
    depthLabel.textContent = depth;

    // Clear
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw subtle grid
    ctx.strokeStyle = '#1a2030';
    ctx.lineWidth = 0.5;
    for (let x = 0; x < canvas.width; x += 40) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += 40) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw tree
    totalBranches = 0;
    const startX  = canvas.width / 2;
    const startY  = canvas.height - 20;
    const initLen = canvas.height * 0.22;

    const t0 = performance.now();
    drawBranch(startX, startY, -Math.PI / 2, initLen, depth, depth);
    const t1 = performance.now();

    // Update stats
    branchCount.textContent = totalBranches.toLocaleString();
    stackDepth.textContent  = depth;
    drawTimeEl.textContent  = (t1 - t0).toFixed(2) + ' ms';

    // Warning
    deepWarning.classList.toggle('visible', depth >= 10);

    // Stack vis
    updateStackVis(depth);
  }

  /* ─────────────────────────────────────────────
     Event listener
  ───────────────────────────────────────────── */
  slider.addEventListener('input', render);

  // Initial draw
  render();
</script>
</body>
</html>
