  <script>
    /* ─────────────────────────────────────────
       BUGGY COUNTER
       The read of `buggyCount` happens OUTSIDE
       the setTimeout callback (stale capture).
    ───────────────────────────────────────── */
    let buggyCount  = 0;
    let buggyClicks = 0;

    const buggyDisplay = document.getElementById('buggy-display');
    const buggyShown   = document.getElementById('buggy-shown');
    const buggyClicksEl= document.getElementById('buggy-clicks');
    const buggyLostEl  = document.getElementById('buggy-lost');
    const buggyMsg     = document.getElementById('buggy-msg');
    const buggyLog     = document.getElementById('buggy-log');

    function logBuggy(msg, cls = 'log-entry-info') {
      const el = document.createElement('div');
      el.className = cls;
      el.textContent = `[${new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'})}] ${msg}`;
      buggyLog.prepend(el);
      // keep log tidy
      while (buggyLog.children.length > 40) buggyLog.removeChild(buggyLog.lastChild);
    }

    function bump(el) {
      el.classList.remove('bump');
      void el.offsetWidth; // reflow
      el.classList.add('bump');
      setTimeout(() => el.classList.remove('bump'), 150);
    }

    document.getElementById('btn-buggy').addEventListener('click', () => {
      buggyClicks++;
      buggyClicksEl.textContent = buggyClicks;

      // ❌ THE BUG: snapshot is captured synchronously right now.
      //    If you click 5 times before any timeout fires, all 5
      //    callbacks will have snapshot = same old value.
      const snapshot = buggyCount;

      logBuggy(`Click #${buggyClicks} — read count=${snapshot} (stale snapshot)`, 'log-entry-info');

      setTimeout(() => {
        buggyCount = snapshot + 1;          // ❌ stale write
        bump(buggyDisplay);
        buggyDisplay.textContent = buggyCount;
        buggyShown.textContent   = buggyCount;

        const lost = buggyClicks - buggyCount;
        buggyLostEl.textContent = lost;
        buggyMsg.textContent = lost > 0
          ? `⚠️ ${lost} update${lost===1?'':'s'} lost!`
          : '✓ No lost updates yet';

        logBuggy(
          `Callback fired → wrote ${snapshot}+1=${buggyCount} | expected=${buggyClicks} | lost=${lost}`,
          lost > 0 ? 'log-entry-bug' : 'log-entry-ok'
        );
      }, 50);
    });

    function resetBuggy() {
      buggyCount = buggyClicks = 0;
      buggyDisplay.textContent = buggyShown.textContent =
        buggyClicksEl.textContent = buggyLostEl.textContent = '0';
      buggyMsg.textContent = '\u00a0';
      buggyLog.innerHTML = '';
      logBuggy('Reset', 'log-entry-info');
    }


    /* ─────────────────────────────────────────
       FIXED COUNTER
       The read of `fixedCount` happens INSIDE
       the setTimeout callback — always fresh.
    ───────────────────────────────────────── */
    let fixedCount  = 0;
    let fixedClicks = 0;

    const fixedDisplay  = document.getElementById('fixed-display');
    const fixedShown    = document.getElementById('fixed-shown');
    const fixedClicksEl = document.getElementById('fixed-clicks');
    const fixedLostEl   = document.getElementById('fixed-lost');
    const fixedMsg      = document.getElementById('fixed-msg');
    const fixedLog      = document.getElementById('fixed-log');

    function logFixed(msg, cls = 'log-entry-info') {
      const el = document.createElement('div');
      el.className = cls;
      el.textContent = `[${new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'})}] ${msg}`;
      fixedLog.prepend(el);
      while (fixedLog.children.length > 40) fixedLog.removeChild(fixedLog.lastChild);
    }

    document.getElementById('btn-fixed').addEventListener('click', () => {
      fixedClicks++;
      fixedClicksEl.textContent = fixedClicks;

      logFixed(`Click #${fixedClicks} — queued (no read yet)`, 'log-entry-info');

      setTimeout(() => {
        // ✅ THE FIX: read + write both happen here, sequentially.
        //    JS event loop ensures callbacks run one at a time,
        //    so each one sees the result of the previous write.
        fixedCount = fixedCount + 1;       // ✅ fresh read inside callback
        bump(fixedDisplay);
        fixedDisplay.textContent = fixedCount;
        fixedShown.textContent   = fixedCount;

        const lost = fixedClicks - fixedCount;
        fixedLostEl.textContent = lost;
        fixedMsg.textContent = lost === 0
          ? '✓ All updates preserved!'
          : `⚠️ ${lost} lost`;

        logFixed(
          `Callback fired → read+wrote ${fixedCount} | expected=${fixedClicks} | lost=${lost}`,
          lost === 0 ? 'log-entry-ok' : 'log-entry-bug'
        );
      }, 50);
    });

    function resetFixed() {
      fixedCount = fixedClicks = 0;
      fixedDisplay.textContent = fixedShown.textContent =
        fixedClicksEl.textContent = fixedLostEl.textContent = '0';
      fixedMsg.textContent = '\u00a0';
      fixedLog.innerHTML = '';
      logFixed('Reset', 'log-entry-info');
    }
  </script>

</body>
</html>
```

## How to Use It

**Save** the code as `race-condition-demo.html` and open it in any browser.

---

### What You'll See

| Area | Purpose |
|---|---|
| **Left panel (red)** | Buggy async counter — rapid clicks reveal lost updates |
| **Right panel (green)** | Fixed counter — every click is always counted correctly |
| **Event log** | Real-time trace of every read/write so you can watch the race happen |
| **Lost counter** | Shows exactly how many increments were silently discarded |
| **Explanation cards** | Concept, step-by-step timeline, side-by-side code, and real-world fix patterns |

---

### How to Trigger the Bug

1. Click the **red button 5–10 times as fast as possible**
2. Watch **Clicks** jump to e.g. `8` while **Displayed** shows only `3`
3. The **Lost** counter shows the discarded updates
4. Compare with the **green button** — no matter how fast you click, it always matches

---

### The Core Insight

```
BUGGY:  read (now, sync) → wait 50ms → write (stale)
FIXED:  wait 50ms → read + write (both fresh, sequential)
```
Moving the **read inside the callback** means each callback sees the value the previous one already wrote, eliminating the race entirely.

