<body>

<h1>Race Condition: Real Demo</h1>
<p class="subtitle">Spam the buttons and watch the buggy counter silently lose increments. The fixed one never does.</p>

<div class="status-bar">
  <span>Spam delay: <strong>80–200ms async</strong> per op</span>
  <span>Ops in flight (buggy): <strong id="inflightBuggy">0</strong></span>
  <span>Ops in flight (fixed): <strong id="inflightFixed">0</strong></span>
  <span>Total clicks: <strong id="totalClicks">0</strong></span>
</div>

<div class="panels">

  <!-- ═══════════════════════════════════════════ BUGGY PANEL -->
  <div class="panel buggy">
    <div class="panel-title">🐛 Buggy — Race Condition</div>
    <div class="panel-desc">
      Each click reads the counter, waits async, then writes back.
      Overlapping reads all see the <em>same stale value</em>.
    </div>

    <div class="counter-box">
      <div class="counter-label">Counter Value</div>
      <div class="counter-value" id="buggyVal">0</div>
      <div class="expected-row">
        <span>Expected: <strong id="buggyExpected">0</strong></span>
        <span class="lost-label">Lost: <span class="lost-value" id="buggyLost">0</span></span>
      </div>
    </div>

    <div class="btn-row">
      <button class="btn-inc-buggy" onclick="buggyIncrement()">+1 (Async)</button>
      <button class="btn-spam" onclick="spamClicks('buggy', 12)">💥 Spam ×12</button>
      <button class="btn-reset" onclick="resetBuggy()">Reset</button>
    </div>

    <div class="log-title">Operation Log</div>
    <div class="log" id="buggyLog"></div>

    <div class="timeline-title">Async Timeline (last ops)</div>
    <div class="timeline" id="buggyTimeline"></div>

    <div class="explain">
      <strong>The bug:</strong> <code>read → wait → write</code> is not atomic.
      If 5 clicks fire before any write completes, they all read <strong>the same value</strong>
      (e.g. 3), add 1, and all write back 4 — so 4 increments are silently <strong>lost</strong>.
      No error is thrown. The counter just lies.
    </div>
  </div>

  <!-- ═══════════════════════════════════════════ FIXED PANEL -->
  <div class="panel fixed">
    <div class="panel-title">✅ Fixed — Serialized Queue</div>
    <div class="panel-desc">
      Each increment is queued. The next op only starts after the
      previous write commits. No stale reads possible.
    </div>

    <div class="counter-box">
      <div class="counter-label">Counter Value</div>
      <div class="counter-value" id="fixedVal">0</div>
      <div class="expected-row">
        <span>Expected: <strong id="fixedExpected">0</strong></span>
        <span class="lost-label">Lost: <span class="lost-value zero" id="fixedLost">0</span></span>
      </div>
    </div>

    <div class="btn-row">
      <button class="btn-inc-fixed" onclick="fixedIncrement()">+1 (Queued)</button>
      <button class="btn-spam" onclick="spamClicks('fixed', 12)">💥 Spam ×12</button>
      <button class="btn-reset" onclick="resetFixed()">Reset</button>
    </div>

    <div class="log-title">Operation Log</div>
    <div class="log" id="fixedLog"></div>

    <div class="timeline-title">Async Timeline (last ops)</div>
    <div class="timeline" id="fixedTimeline"></div>

    <div class="explain">
      <strong>The fix:</strong> A promise chain acts as a mutex.
      Each <code>+1</code> appends to the chain: <code>queue = queue.then(doIncrement)</code>.
      Operations execute <strong>one at a time</strong>, each reading the value
      written by the previous one. Zero increments lost, ever.
    </div>
  </div>

</div>

<script>
// ─────────────────────────────────────────────────────────────
// Shared state
// ─────────────────────────────────────────────────────────────
let buggyCounter   = 0;
let buggyExpected  = 0;
let buggyInFlight  = 0;

let fixedCounter   = 0;
let fixedExpected  = 0;
let fixedInFlight  = 0;

let totalClicks    = 0;

// Fixed version's serial queue
let fixedQueue = Promise.resolve();

// Timeline data
const buggyOps = [];
const fixedOps = [];
const TIMELINE_SLOTS = 12; // how many ops to show

// ─────────────────────────────────────────────────────────────
// Utilities
// ─────────────────────────────────────────────────────────────
function rand(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function now() {
  return performance.now();
}

function ts() {
  return (performance.now() / 1000).toFixed(3);
}

function addLog(logId, cls, text) {
  const log = document.getElementById(logId);
  const entry = document.createElement('div');
  entry.className = 'log-entry';
  entry.innerHTML = `<span class="log-time">${ts()}s</span><span class="log-op ${cls}">${text}</span>`;
  log.appendChild(entry);
  // keep last 120 entries
  while (log.children.length > 120) log.removeChild(log.firstChild);
  log.scrollTop = log.scrollHeight;
}

function flashCounter(id, cls) {
  const el = document.getElementById(id);
  el.classList.remove('flash-bad', 'flash-good');
  void el.offsetWidth; // reflow
  el.classList.add(cls);
  el.addEventListener('animationend', () => el.classList.remove(cls), { once: true });
}

function updateStatus() {
  document.getElementById('inflightBuggy').textContent = buggyInFlight;
  document.getElementById('inflightFixed').textContent = fixedInFlight;
  document.getElementById('totalClicks').textContent   = totalClicks;
}

function updateBuggyDisplay() {
  document.getElementById('buggyVal').textContent      = buggyCounter;
  document.getElementById('buggyExpected').textContent = buggyExpected;
  const lost = buggyExpected - buggyCounter;
  const lostEl = document.getElementById('buggyLost');
  lostEl.textContent = lost;
  lostEl.className = 'lost-value' + (lost > 0 ? '' : ' zero');
}

function updateFixedDisplay() {
  document.getElementById('fixedVal').textContent      = fixedCounter;
  document.getElementById('fixedExpected').textContent = fixedExpected;
  const lost = fixedExpected - fixedCounter;
  const lostEl = document.getElementById('fixedLost');
  lostEl.textContent = lost;
  lostEl.className = 'lost-value zero' + (lost > 0 ? ' zero' : '');
}

// ─────────────────────────────────────────────────────────────
// Timeline renderer
// ─────────────────────────────────────────────────────────────
const COLORS_BUGGY = ['#ef4444','#f97316','#eab308','#ec4899','#8b5cf6','#06b6d4'];
const COLORS_FIXED = ['#10b981','#3b82f6','#a855f7','#14b8a6','#84cc16','#f59e0b'];

function renderTimeline(canvasId, ops, colorPalette) {
  const container = document.getElementById(canvasId);
  container.innerHTML = '';

  if (ops.length === 0) return;

  const visible = ops.slice(-TIMELINE_SLOTS);
  const tMin = Math.min(...visible.map(o => o.readAt));
  const tMax = Math.max(...visible.map(o => o.writeAt));
  const span = Math.max(tMax - tMin, 1);
  const W    = container.offsetWidth  || 300;
  const H    = container.offsetHeight || 80;
  const rows = 4;
  const rowH = (H - 10) / rows;

  visible.forEach((op, i) => {
    const color = colorPalette[i % colorPalette.length];
    const x1 = ((op.readAt  - tMin) / span) * (W - 20) + 4;
    const x2 = ((op.writeAt - tMin) / span) * (W - 20) + 4;
    const row = i % rows;
    const y   = row * rowH + 6;

    // Read marker
    const readDot = document.createElement('div');
    readDot.className = 'timeline-track';
    readDot.style.cssText = `
      left:${x1}px; top:${y}px; width:${Math.max(x2 - x1, 8)}px;
      height:${rowH - 4}px; background:${color}33;
      border:1px solid ${color}; color:${color};
    `;
    readDot.textContent = `r:${op.readVal}→w:${op.writeVal}`;
    container.appendChild(readDot);
  });
}

// ─────────────────────────────────────────────────────────────
// BUGGY VERSION
// read → async wait → write  (no coordination)
// ─────────────────────────────────────────────────────────────
function buggyIncrement() {
  totalClicks++;
  buggyExpected++;
  buggyInFlight++;
  updateStatus();
  updateBuggyDisplay();

  const opId    = totalClicks;
  const delay   = rand(80, 220);
  const readAt  = now();

  // ⚠️ READ happens NOW (synchronously)
  const snapshot = buggyCounter;
  addLog('buggyLog', 'log-read',
    `Op#${opId} READ  counter = ${snapshot}  (${buggyInFlight} in-flight)`);

  setTimeout(() => {
    // ⚠️ WRITE happens LATER — snapshot is stale if others ran first
    const writeAt   = now();
    const newVal    = snapshot + 1;
    const wasStale  = buggyCounter !== snapshot;

    buggyCounter = newVal;
    buggyInFlight--;
    updateStatus();
    updateBuggyDisplay();

    buggyOps.push({ readAt, writeAt, readVal: snapshot, writeVal: newVal });
    if (buggyOps.length > 40) buggyOps.shift();
    renderTimeline('buggyTimeline', buggyOps, COLORS_BUGGY);

    if (wasStale) {
      addLog('buggyLog', 'log-warn',
        `Op#${opId} WRITE ${snapshot}+1=${newVal}  ⚠ STALE! real was ${buggyCounter - 1} → LOST UPDATE`);
      flashCounter('buggyVal', 'flash-bad');
    } else {
      addLog('buggyLog', 'log-write',
        `Op#${opId} WRITE ${snapshot}+1=${newVal}  ✓ (${delay}ms)`);
      flashCounter('buggyVal', 'flash-good');
    }
  }, delay);
}

// ─────────────────────────────────────────────────────────────
// FIXED VERSION
// Serial promise queue — each op waits for the previous write
// ─────────────────────────────────────────────────────────────
function fixedIncrement() {
  totalClicks++;
  fixedExpected++;
  fixedInFlight++;
  updateStatus();
  updateFixedDisplay();

  const opId  = totalClicks;
  const queueDepth = fixedInFlight;

  addLog('fixedLog', 'log-queue',
    `Op#${opId} QUEUED  (depth: ${queueDepth})`);

  fixedQueue = fixedQueue.then(() => {
    return new Promise(resolve => {
      const delay  = rand(80, 220);
      const readAt = now();

      // READ is safe: previous op already committed its write
      const snapshot = fixedCounter;
      addLog('fixedLog', 'log-read',
        `Op#${opId} READ  counter = ${snapshot}  (sequential)`);

      setTimeout(() => {
        const writeAt = now();
        const newVal  = snapshot + 1;

        fixedCounter = newVal;
        fixedInFlight--;
        updateStatus();
        updateFixedDisplay();

        fixedOps.push({ readAt, writeAt, readVal: snapshot, writeVal: newVal });
        if (fixedOps.length > 40) fixedOps.shift();
        renderTimeline('fixedTimeline', fixedOps, COLORS_FIXED);

        addLog('fixedLog', 'log-ok',
          `Op#${opId} WRITE ${snapshot}+1=${newVal}  ✓ (${delay}ms)`);
        flashCounter('fixedVal', 'flash-good');

        resolve();
      }, delay);
    });
  });
}

// ─────────────────────────────────────────────────────────────
// Spam helper
// ─────────────────────────────────────────────────────────────
function spamClicks(target, count) {
  const fn = target === 'buggy' ? buggyIncrement : fixedIncrement;
  // Fire all clicks nearly simultaneously with tiny jitter
  // to maximise overlap probability on the buggy side
  for (let i = 0; i < count; i++) {
    setTimeout(fn, rand(0, 30));
  }
}

// ─────────────────────────────────────────────────────────────
// Resets
// ─────────────────────────────────────────────────────────────
function resetBuggy() {
  buggyCounter  = 0;
  buggyExpected = 0;
  buggyInFlight = 0;
  buggyOps.length = 0;
  document.getElementById('buggyLog').innerHTML = '';
  document.getElementById('buggyTimeline').innerHTML = '';
  updateBuggyDisplay();
  updateStatus();
}

function resetFixed() {
  fixedCounter  = 0;
  fixedExpected = 0;
  // drain queue then reset
  fixedQueue = fixedQueue.then(() => {
    fixedInFlight = 0;
    fixedOps.length = 0;
    document.getElementById('fixedLog').innerHTML = '';
    document.getElementById('fixedTimeline').innerHTML = '';
    updateFixedDisplay();
    updateStatus();
  });
}

// Init displays
updateBuggyDisplay();
updateFixedDisplay();
updateStatus();
</script>
</body>
</html>
```

## What makes this demo actually show the bug

**The race is real, not simulated.** Each click on the buggy side does exactly what broken async code does in practice:

1. **Reads** `buggyCounter` synchronously (captures a snapshot)
2. **Waits** a random 80–220ms (simulating a DB call, API fetch, etc.)
3. **Writes** `snapshot + 1` back — completely blind to what happened during the wait

When you hit **Spam ×12**, all 12 reads happen within ~30ms of each other. They all capture the *same value* (say, `5`). All 12 then write back `6`. The counter goes from `5` to `6` instead of `17`. **11 increments silently vanish.** No exception, no warning — the counter just lies.

**The "Lost" counter** shows you the exact discrepancy between what the counter *should* be and what it *is*.

**The fix** uses a promise chain as a mutex: `fixedQueue = fixedQueue.then(doOp)`. No matter how fast you click, each operation waits for the previous write to commit before it reads. The lost counter stays permanently at 0.

