  <label>Depth</label>
  <input type="range" id="depthSlider" min="1" max="12" value="7">
  <div class="depth-badge" id="depthVal">7</div>
</div>

<div class="stats">
  <div class="stat-card">
    <div class="val" id="statBranches">—</div>
    <div class="lbl">Total Branches</div>
  </div>
  <div class="stat-card">
    <div class="val" id="statCalls">—</div>
    <div class="lbl">Recursive Calls</div>
  </div>
  <div class="stat-card">
    <div class="val" id="statFrames">—</div>
    <div class="lbl">Max Stack Depth</div>
