}

<span class="cm">// ✅ FIXED — sequential queue, delta-based</span>
<span class="kw">const</span> queue = [];
<span class="kw">let</span> processing = <span class="kw">false</span>;

<span class="kw">function</span> <span class="fn">fixedIncrement</span>() {
