  <span class="fn">processQueue</span>();
}

<span class="kw">async function</span> <span class="fn">processQueue</span>() {
  <span class="kw">if</span> (processing) <span class="kw">return</span>;      <span class="cm">// only one processor at a time</span>
  processing = <span class="kw">true</span>;
