<script>
// ─────────────────────────────────────────────
//  SHARED UTILITIES
// ─────────────────────────────────────────────
const DELAY_MS = 250;
function delay(ms) { return new Promise(r => setTimeout(r, ms)); }

let logEntries = [];
function log(msg, cls = 'info') {
  const box = document.getElementById('log-box');
  const ts = new Date().toLocaleTimeString('en-US', {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit', fractionalSecondDigits:2});
  const entry = document.createElement('div');
  entry.className = `log-entry ${cls}`;
  entry.textContent = `[${ts}] ${msg}`;
  box.appendChild(entry);
  box.scrollTop = box.scrollHeight;
  // keep max 200 entries
  while (box.children.length > 200) box.removeChild(box.firstChild);
}

function clearLog() {
  document.getElementById('log-box').innerHTML = '';
}

function bumpAnimation(el) {
  el.classList.remove('bump');
  void el.offsetWidth;
  el.classList.add('bump');
  setTimeout(() => el.classList.remove('bump'), 150);
}

// ─────────────────────────────────────────────
//  TIMELINE VISUALIZER
// ─────────────────────────────────────────────
const canvas = document.getElementById('timeline-canvas');
const ctx = canvas.getContext('2d');
const tlEvents = [];
const TL_WINDOW = 6000; // show last 6 seconds

function resizeCanvas() {
  canvas.width = canvas.offsetWidth * window.devicePixelRatio;
  canvas.height = canvas.offsetHeight * window.devicePixelRatio;
  ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
}
resizeCanvas();
window.addEventListener('resize', resizeCanvas);

function addTLEvent(type, value) {
  tlEvents.push({ t: Date.now(), type, value });
  if (tlEvents.length > 500) tlEvents.shift();
}

const TL_COLORS = {
  buggy_start:  '#ff6b6b',
  buggy_commit: '#ff8800',
  fixed_start:  '#6bcb77',
  fixed_commit: '#00aaff',
  race:         '#ffdd44',
};

function drawTimeline() {
  const W = canvas.offsetWidth;
  const H = canvas.offsetHeight;
  ctx.clearRect(0, 0, W, H);

  // background grid
  ctx.strokeStyle = '#1e1e3a';
  ctx.lineWidth = 1;
  for (let x = 0; x < W; x += 60) {
    ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
  }

  // center line
  ctx.strokeStyle = '#2a2a4a';
  ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(0, H/2); ctx.lineTo(W, H/2); ctx.stroke();

  // labels
  ctx.fillStyle = '#333';
  ctx.font = '10px monospace';
  ctx.fillText('BUGGY', 4, 14);
  ctx.fillText('FIXED', 4, H - 4);

  const now = Date.now();
  tlEvents.forEach(ev => {
    const age = now - ev.t;
    if (age > TL_WINDOW) return;
    const x = W - (age / TL_WINDOW) * W;
    const isBuggy = ev.type.startsWith('buggy') || ev.type === 'race';
    const y = isBuggy ? H * 0.28 : H * 0.72;
    const color = TL_COLORS[ev.type] || '#888';
    const r = ev.type === 'race' ? 7 : 5;

    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fillStyle = color;
    ctx.fill();

    if (ev.type === 'race') {
      ctx.strokeStyle = '#ffdd44';
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.fillStyle = '#ffdd44';
      ctx.font = 'bold 9px monospace';
      ctx.fillText('RACE!', x + 8, y - 4);
    }

    // value label
    ctx.fillStyle = color;
    ctx.font = '9px monospace';
    ctx.fillText(ev.value !== undefined ? ev.value : '', x - 6, y + 18);
  });

  requestAnimationFrame(drawTimeline);
}
drawTimeline();

// ─────────────────────────────────────────────
//  BUGGY COUNTER
// ─────────────────────────────────────────────
let buggyCount = 0;
let buggyExpected = 0;
let buggyLost = 0;
let buggyPendingOps = 0;

function updateBuggyDisplay() {
  const el = document.getElementById('buggy-count');
  el.textContent = buggyCount;
  bumpAnimation(el);
  document.getElementById('buggy-displayed').textContent = buggyCount;
  document.getElementById('buggy-expected').textContent = buggyExpected;
  document.getElementById('buggy-lost').textContent = buggyLost;
  document.getElementById('buggy-pending-count').textContent = buggyPendingOps;
  const badge = document.getElementById('buggy-pending');
  badge.classList.toggle('visible', buggyPendingOps > 0);
}

async function buggyUpdate(delta) {
  buggyPendingOps++;
  updateBuggyDisplay();

  // ❌ READ shared state right now (stale if other ops are in flight)
  const snapshot = buggyCount;
  const opId = Math.random().toString(36).slice(2,6);

  addTLEvent('buggy_start', snapshot);
  log(`[BUGGY #${opId}] READ count=${snapshot}, delta=${delta > 0 ? '+' : ''}${delta}`, 'buggy-log');

  await delay(DELAY_MS);

  // ❌ WRITE back stale value
  const newVal = snapshot + delta;
  const actualExpected = buggyCount + delta; // what it should be

  if (newVal !== actualExpected) {
    buggyLost++;
    addTLEvent('race', newVal);
    log(`[BUGGY #${opId}] ⚠️ RACE! Writing ${newVal} but count is now ${buggyCount} (expected ${actualExpected})`, 'race');
    console.warn(`Race condition detected! Wrote ${newVal}, should be ${actualExpected}`);
  } else {
    addTLEvent('buggy_commit', newVal);
    log(`[BUGGY #${opId}] WRITE count=${newVal}`, 'buggy-log');
  }

  buggyCount = newVal;
  buggyPendingOps--;
  updateBuggyDisplay();
}

function buggyIncrement() {
  buggyExpected++;
  buggyUpdate(+1);
  updateBuggyDisplay();
}

function buggyDecrement() {
  buggyExpected--;
  buggyUpdate(-1);
  updateBuggyDisplay();
}

function buggyReset() {
  buggyCount = 0;
  buggyExpected = 0;
  buggyLost = 0;
  buggyPendingOps = 0;
  updateBuggyDisplay();
  log('[BUGGY] Reset', 'info');
}

// ─────────────────────────────────────────────
//  FIXED COUNTER
// ─────────────────────────────────────────────
let fixedCount = 0;
let fixedExpected = 0;
let fixedLost = 0;
let fixedQueue = [];
let fixedProcessing = false;

function updateFixedDisplay() {
  const el = document.getElementById('fixed-count');
  el.textContent = fixedCount;
  bumpAnimation(el);
  document.getElementById('fixed-count-stat').textContent = fixedCount;
  document.getElementById('fixed-expected').textContent = fixedExpected;
  document.getElementById('fixed-lost').textContent = fixedLost;
  document.getElementById('fixed-pending-count').textContent = fixedQueue.length;
  const badge = document.getElementById('fixed-pending');
  badge.classList.toggle('visible', fixedQueue.length > 0 || fixedProcessing);
}

async function processFixedQueue() {
  if (fixedProcessing) return;
  fixedProcessing = true;

  while (fixedQueue.length > 0) {
    const { delta, opId } = fixedQueue.shift();
    updateFixedDisplay();

    // ✅ READ fresh state (no concurrent ops can run here)
    const before = fixedCount;
    addTLEvent('fixed_start', before);
    log(`[FIXED  #${opId}] READ count=${before}, delta=${delta > 0 ? '+' : ''}${delta}`, 'fixed-log');

    await delay(DELAY_MS);

    // ✅ WRITE — state is guaranteed fresh, no other op ran during wait
    fixedCount += delta;
    addTLEvent('fixed_commit', fixedCount);
    log(`[FIXED  #${opId}] WRITE count=${fixedCount} ✓`, 'fixed-log');
    updateFixedDisplay();
  }

  fixedProcessing = false;
  updateFixedDisplay();
}

function fixedIncrement() {
  fixedExpected++;
  const opId = Math.random().toString(36).slice(2,6);
  fixedQueue.push({ delta: +1, opId });
  updateFixedDisplay();
  processFixedQueue();
}

function fixedDecrement() {
  fixedExpected--;
  const opId = Math.random().toString(36).slice(2,6);
  fixedQueue.push({ delta: -1, opId });
  updateFixedDisplay();
  processFixedQueue();
}

function fixedReset() {
  fixedCount = 0;
  fixedExpected = 0;
  fixedLost = 0;
  fixedQueue = [];
  fixedProcessing = false;
  updateFixedDisplay();
  log('[FIXED] Reset', 'info');
}

// ─────────────────────────────────────────────
//  STRESS TEST
// ─────────────────────────────────────────────
async function stressTest() {
  log('═══ STRESS TEST START (20 increments on each) ═══', 'info');
  buggyReset();
  fixedReset();

  const clicks = 20;
  for (let i = 0; i < clicks; i++) {
    setTimeout(() => {
      buggyIncrement();
      fixedIncrement();
    }, i * 30); // 30ms apart — faster than DELAY_MS so they overlap
  }

  // Check results after all should be done
  setTimeout(() => {
    log(`═══ STRESS TEST RESULTS ═══`, 'info');
    log(`BUGGY: expected=${buggyExpected}, got=${buggyCount}, lost=${buggyLost}`, buggyLost > 0 ? 'race' : 'fixed-log');
    log(`FIXED: expected=${fixedExpected}, got=${fixedCount}, lost=${fixedLost}`, 'fixed-log');
  }, clicks * 30 + DELAY_MS * 3 + 500);
}

// ─────────────────────────────────────────────
//  INIT
// ─────────────────────────────────────────────
updateBuggyDisplay();
updateFixedDisplay();
log('Demo ready — click buttons rapidly to see the race condition!', 'info');
</script>
</body>
</html>
```

## How It Works

### The Race Condition (Buggy Side)
Each click immediately **captures a snapshot** of the count, waits 250ms, then writes `snapshot + 1` back. If you click 5 times before any write completes, all 5 reads capture the **same stale value** — say `3` — and all 5 write `4`. You lose 4 updates.

### The Fix (Fixed Side)
Each click **enqueues a delta** (`+1` or `-1`) instead of reading state. A single sequential processor dequeues one operation at a time, applies it, updates the display, then moves to the next. No two operations ever overlap, so every read sees fresh state.

### Key Features
- **Live operation log** shows exact read/write values and flags race conditions in yellow
- **Lost updates counter** tracks how many writes were silently discarded
- **Timeline canvas** visualizes concurrent vs sequential operations in real time
- **🔥 Stress Test button** fires 20 rapid clicks (30ms apart, faster than the 250ms delay) to reliably trigger the race
- **Code snippet** with syntax highlighting shows the exact buggy vs fixed pattern

