<script>
/* ═══════════════════════════════════════════════════════
   TASK DEFINITIONS — same work for both implementations
═══════════════════════════════════════════════════════ */
const TASK_DEFS = [
  { name: 'Loader A',   steps: 4, stepSize: 8,  delay: 80  },
  { name: 'Loader B',   steps: 3, stepSize: 12, delay: 60  },
  { name: 'Loader C',   steps: 5, stepSize: 5,  delay: 100 },
  { name: 'Loader D',   steps: 2, stepSize: 15, delay: 50  },
  { name: 'Loader E',   steps: 6, stepSize: 4,  delay: 70  },
  { name: 'Loader F',   steps: 3, stepSize: 10, delay: 90  },
];

/* ═══════════════════════════════════════════════════════
   SHARED HELPERS
═══════════════════════════════════════════════════════ */
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

function logEntry(boxId, text, type = 'info') {
  const box = document.getElementById(boxId);
  const el  = document.createElement('div');
  el.className = `log-entry ${type}`;
  const ts = new Date().toLocaleTimeString('en-US', { hour12: false, hour:'2-digit', minute:'2-digit', second:'2-digit', fractionalSecondDigits: 3 });
  el.textContent = `[${ts}] ${text}`;
  box.appendChild(el);
  box.scrollTop = box.scrollHeight;
}

function setTaskState(containerId, name, status, extra = '') {
  const container = document.getElementById(containerId);
  let card = container.querySelector(`[data-task="${name}"]`);
  if (!card) {
    card = document.createElement('div');
    card.className = 'task-card';
    card.dataset.task = name;
    card.innerHTML = `<div class="task-name">${name}</div><div class="task-status"></div>`;
    container.appendChild(card);
  }
  card.className = `task-card ${status}`;
  card.querySelector('.task-status').textContent = extra || status;
}

function buildTaskCards(containerId) {
  const c = document.getElementById(containerId);
  c.innerHTML = '';
  TASK_DEFS.forEach(t => {
    const card = document.createElement('div');
    card.className = 'task-card';
    card.dataset.task = t.name;
    card.innerHTML = `<div class="task-name">${t.name}</div><div class="task-status">waiting</div>`;
    c.appendChild(card);
  });
}

/* ═══════════════════════════════════════════════════════
   ██████  BUGGY IMPLEMENTATION  ██████
   Shared mutable variable — no synchronisation
═══════════════════════════════════════════════════════ */
let buggyRunning = false;
let buggyProgress = 0;
let buggyStats = { anomalies: 0, overflows: 0, skips: 0, lastValue: 0 };

function updateBuggyBar(value) {
  const pct  = Math.min(value, 150); // allow visual overflow up to 150%
  const disp = value;
  const fill = document.getElementById('buggyFill');
  const pctEl = document.getElementById('buggyPct');
  const overflow = document.getElementById('buggyOverflow');
  const track = document.getElementById('buggyTrack');

  fill.style.width = Math.min(pct, 100) + '%';
  pctEl.textContent = disp + '%';

  if (value > 100) {
    overflow.style.display = 'block';
    pctEl.style.color = '#ff4d6d';
    track.classList.add('anomaly-flash');
    setTimeout(() => track.classList.remove('anomaly-flash'), 500);
    buggyStats.overflows++;
    document.getElementById('buggyOverflows').textContent = buggyStats.overflows;
  } else {
    overflow.style.display = 'none';
    pctEl.style.color = '';
  }

  // Detect skip (jump > 20 in one update)
  if (value - buggyStats.lastValue > 20 && buggyStats.lastValue < value) {
    buggyStats.skips++;
    document.getElementById('buggySkips').textContent = buggyStats.skips;
  }

  buggyStats.lastValue = value;
  document.getElementById('buggyFinal').textContent = value + '%';
}

async function buggyTask(taskDef) {
  setTaskState('buggyTasks', taskDef.name, 'running', 'running…');
  logEntry('buggyLog', `${taskDef.name} started (${taskDef.steps} steps × ${taskDef.stepSize}%)`, 'info');

  for (let i = 0; i < taskDef.steps; i++) {
    await sleep(taskDef.delay + Math.random() * 40);

    // ⚠️ BUG: read-modify-write without any lock
    const snapshot = buggyProgress;          // READ  (stale snapshot possible)
    await sleep(Math.random() * 20);         // artificial yield — widens the race window
    buggyProgress = snapshot + taskDef.stepSize; // WRITE (may overwrite another task's update)

    const anomaly = buggyProgress > 100 || buggyProgress < snapshot;
    if (anomaly) {
      buggyStats.anomalies++;
      document.getElementById('buggyAnomalies').textContent = buggyStats.anomalies;
      logEntry('buggyLog', `⚠ ${taskDef.name} step ${i+1}: ${snapshot}% → ${buggyProgress}% (ANOMALY)`, 'error');
    } else {
      logEntry('buggyLog', `${taskDef.name} step ${i+1}: ${snapshot}% → ${buggyProgress}%`, 'warn');
    }

    updateBuggyBar(buggyProgress);
  }

  setTaskState('buggyTasks', taskDef.name, 'done', `done (${taskDef.steps * taskDef.stepSize}% added)`);
  logEntry('buggyLog', `${taskDef.name} finished`, 'ok');
}

async function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;
  document.getElementById('btnRunBuggy').disabled = true;

  logEntry('buggyLog', '═══ Starting buggy run ═══', 'highlight');

  // Launch ALL tasks concurrently — they all race on buggyProgress
  const promises = TASK_DEFS.map(t => buggyTask(t));
  await Promise.all(promises);

  logEntry('buggyLog', `═══ All done. Final progress: ${buggyProgress}% ═══`, 'highlight');
  if (buggyProgress !== 100) {
    logEntry('buggyLog', `Expected 100%, got ${buggyProgress}% — BUG CONFIRMED ✗`, 'error');
  }

  buggyRunning = false;
  document.getElementById('btnRunBuggy').disabled = false;
}

function resetBuggy() {
  buggyProgress = 0;
  buggyStats = { anomalies: 0, overflows: 0, skips: 0, lastValue: 0 };
  document.getElementById('buggyFill').style.width = '0%';
  document.getElementById('buggyPct').textContent = '0%';
  document.getElementById('buggyPct').style.color = '';
  document.getElementById('buggyOverflow').style.display = 'none';
  document.getElementById('buggyAnomalies').textContent = '0';
  document.getElementById('buggyOverflows').textContent = '0';
  document.getElementById('buggySkips').textContent = '0';
  document.getElementById('buggyFinal').textContent = '—';
  document.getElementById('buggyLog').innerHTML = '';
  buildTaskCards('buggyTasks');
  document.getElementById('btnRunBuggy').disabled = false;
  buggyRunning = false;
}

/* ═══════════════════════════════════════════════════════
   ██████  FIXED IMPLEMENTATION  ██████
   Async mutex queue — serialises all progress updates
═══════════════════════════════════════════════════════ */
let fixedRunning = false;
let fixedProgress = 0;
let fixedStats = { anomalies: 0, overflows: 0, skips: 0, lastValue: 0 };

// The mutex: a chain of Promises that ensures sequential execution
let fixedLock = Promise.resolve();

/**
 * Enqueue a critical-section callback.
 * Each call appends to the Promise chain, so updates run one-at-a-time.
 */
function withLock(fn) {
  // Chain: new work starts only after previous work resolves
  fixedLock = fixedLock.then(() => fn());
  return fixedLock;
}

function updateFixedBar(value) {
  const fill  = document.getElementById('fixedFill');
  const pctEl = document.getElementById('fixedPct');

  fill.style.width  = value + '%';
  pctEl.textContent = value + '%';
  document.getElementById('fixedFinal').textContent = value + '%';

  if (value - fixedStats.lastValue > 20) {
    fixedStats.skips++;
    document.getElementById('fixedSkips').textContent = fixedStats.skips;
  }
  fixedStats.lastValue = value;
}

async function fixedTask(taskDef) {
  setTaskState('fixedTasks', taskDef.name, 'running', 'running…');
  logEntry('fixedLog', `${taskDef.name} started (${taskDef.steps} steps × ${taskDef.stepSize}%)`, 'info');

  for (let i = 0; i < taskDef.steps; i++) {
    await sleep(taskDef.delay + Math.random() * 40);

    // ✅ FIX: wrap the read-modify-write in withLock()
    // The callback runs exclusively — no other update can interleave
    await withLock(async () => {
      const before = fixedProgress;

      await sleep(Math.random() * 20); // same artificial yield as buggy version

      // Clamp to [0, 100] as a safety net
      fixedProgress = Math.min(100, fixedProgress + taskDef.stepSize);

      const after = fixedProgress;
      logEntry('fixedLog', `${taskDef.name} step ${i+1}: ${before}% → ${after}%`, 'ok');
      updateFixedBar(fixedProgress);
    });
  }

  setTaskState('fixedTasks', taskDef.name, 'done', `done (${taskDef.steps * taskDef.stepSize}% added)`);
  logEntry('fixedLog', `${taskDef.name} finished`, 'ok');
}

async function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;
  document.getElementById('btnRunFixed').disabled = true;

  logEntry('fixedLog', '═══ Starting fixed run ═══', 'highlight');

  // Same concurrent launch — but updates are serialised by the lock
  const promises = TASK_DEFS.map(t => fixedTask(t));
  await Promise.all(promises);

  // Wait for any queued lock operations to drain
  await fixedLock;

  logEntry('fixedLog', `═══ All done. Final progress: ${fixedProgress}% ═══`, 'highlight');
  if (fixedProgress === 100) {
    logEntry('fixedLog', 'Progress reached exactly 100% — CORRECT ✓', 'ok');
  } else {
    logEntry('fixedLog', `Progress is ${fixedProgress}% (clamped at 100 due to excess work)`, 'info');
  }

  fixedRunning = false;
  document.getElementById('btnRunFixed').disabled = false;
}

function resetFixed() {
  fixedProgress = 0;
  fixedLock = Promise.resolve();
  fixedStats = { anomalies: 0, overflows: 0, skips: 0, lastValue: 0 };
  document.getElementById('fixedFill').style.width = '0%';
  document.getElementById('fixedPct').textContent = '0%';
  document.getElementById('fixedAnomalies').textContent = '0';
  document.getElementById('fixedOverflows').textContent = '0';
  document.getElementById('fixedSkips').textContent = '0';
  document.getElementById('fixedFinal').textContent = '—';
  document.getElementById('fixedLog').innerHTML = '';
  buildTaskCards('fixedTasks');
  document.getElementById('btnRunFixed').disabled = false;
  fixedRunning = false;
}

/* ═══════════════════════════════════════════════════════
   INIT
═══════════════════════════════════════════════════════ */
buildTaskCards('buggyTasks');
buildTaskCards('fixedTasks');
</script>
