        </div>
    </div>

</div>

<!-- EXPLANATION PANEL -->
<div class="explanation">
    <h2>📖 Understanding the Race Condition</h2>
    <div class="exp-grid">

        <div class="exp-card problem">
            <h3>🐛 The Problem: Read-Modify-Write Race</h3>
            <p>When multiple async tasks share a variable, each one performs three steps:</p>
            <ul>
                <li><strong>Read</strong> the current value of <code>sharedProgress</code></li>
                <li><strong>Compute</strong> the new value (add their increment)</li>
                <li><strong>Write</strong> the result back</li>
            </ul>
            <p style="margin-top:8px;">Because JavaScript is single-threaded but <em>interleaved</em> via the event loop,
            two tasks can both <strong>read the same stale value</strong> before either writes back.
            The second write overwrites the first, causing lost updates — or both add their full
            increment to the same base, causing overflow past 100%.</p>

            <div class="race-diagram">
<span class="timeline">Time →→→→→→→→→→→→→→→→→→→→→→→→→→→→</span>

<span class="task-a">Task A:  READ(30) → +25 → WRITE(55)</span>
<span class="task-b">Task B:       READ(30) → +30 → WRITE(60)</span>
<span class="bad-result">Result:  60  ← Task A's write was lost!</span>
<span class="bad-result">         OR both add to same base → 85+ → OVERFLOW</span>
            </div>

            <div class="code-block"><span class="cm">// ❌ BUGGY: no synchronization</span>
<span class="kw">let</span> sharedProgress = <span class="num">0</span>;

<span class="kw">async function</span> <span class="fn">buggyTask</span>(name, increment, delay) {
  <span class="kw">await</span> <span class="fn">sleep</span>(delay);
  <span class="cm">// Both tasks read 30 at the same time!</span>
  <span class="kw">const</span> current = sharedProgress; <span class="bad">// stale read</span>
  <span class="kw">await</span> <span class="fn">sleep</span>(<span class="num">50</span>); <span class="cm">// simulate work</span>
  sharedProgress = current + increment; <span class="bad">// overwrites!</span>
}</div>
        </div>

        <div class="exp-card solution">
            <h3>✅ The Fix: Serialized Promise Queue</h3>
            <p>The solution is to ensure that read-modify-write operations are <strong>atomic</strong>
            — no other task can interleave between the read and the write.</p>
            <ul>
                <li>A <strong>promise chain</strong> (<code>taskQueue</code>) acts as a mutex</li>
                <li>Each task appends itself to the chain with <code>.then()</code></li>
                <li>Tasks execute one at a time, in order — no interleaving</li>
                <li>A <strong>clamp</strong> guard caps the total at 100% as a safety net</li>
            </ul>

            <div class="race-diagram">
<span class="timeline">Time →→→→→→→→→→→→→→→→→→→→→→→→→→→→</span>

<span class="task-a">Task A:  READ(30) → +25 → WRITE(55) ✓</span>
<span class="task-b">Task B:                         READ(55) → +30 → WRITE(85) ✓</span>
<span class="result">Result:  85  ← Both updates preserved!</span>
<span class="result">         Sequential, no lost writes, no overflow</span>
            </div>

            <div class="code-block"><span class="cm">// ✅ FIXED: serialized via promise queue</span>
<span class="kw">let</span> sharedProgress = <span class="num">0</span>;
<span class="kw">let</span> taskQueue = Promise.<span class="fn">resolve</span>(); <span class="cm">// mutex</span>

<span class="kw">function</span> <span class="fn">fixedTask</span>(name, increment, delay) {
  taskQueue = taskQueue.<span class="fn">then</span>(<span class="kw">async</span> () => {
    <span class="kw">await</span> <span class="fn">sleep</span>(delay);
    <span class="cm">// Safe: only one task runs at a time</span>
    <span class="kw">const</span> next = sharedProgress + increment;
    sharedProgress = <span class="fn">Math.min</span>(next, <span class="num">100</span>); <span class="good">// clamp</span>
    <span class="fn">updateUI</span>(name, sharedProgress);
  });
  <span class="kw">return</span> taskQueue;
}</div>
        </div>

    </div>
</div>

<script>
    // ─────────────────────────────────────────────
    //  Shared helpers
    // ─────────────────────────────────────────────
    const sleep = ms => new Promise(resolve => setTimeout(resolve, ms));

    const TASKS = [
        { name: 'Task Alpha',   color: '#ff6b6b', increment: 28, delay: 100 },
        { name: 'Task Beta',    color: '#ffd32a', increment: 25, delay: 80  },
        { name: 'Task Gamma',   color: '#a29bfe', increment: 22, delay: 120 },
        { name: 'Task Delta',   color: '#fd79a8', increment: 20, delay: 60  },
        { name: 'Task Epsilon', color: '#74b9ff', increment: 18, delay: 90  },
    ];

    // ─────────────────────────────────────────────
    //  Build UI for both panels
    // ─────────────────────────────────────────────
    function buildTaskUI(containerId, prefix) {
        const container = document.getElementById(containerId);
        container.innerHTML = '';
        TASKS.forEach((t, i) => {
            container.innerHTML += `
                <div class="progress-section">
                    <div class="progress-label">
                        <span class="progress-name">${t.name} (+${t.increment}%)</span>
                        <span class="progress-value" id="${prefix}Val${i}" style="color:${t.color}">0%</span>
                    </div>
                    <div class="progress-track">
                        <div class="progress-fill" id="${prefix}Bar${i}"
                             style="width:0%; background: linear-gradient(90deg, ${t.color}99, ${t.color})">
                        </div>
                    </div>
                </div>`;
        });
    }

    buildTaskUI('buggyTasks', 'buggy');
    buildTaskUI('fixedTasks', 'fixed');

    // ─────────────────────────────────────────────
    //  Logging helpers
    // ─────────────────────────────────────────────
    function log(boxId, msg, type = 'info') {
        const box = document.getElementById(boxId);
        const entry = document.createElement('div');
        entry.className = `log-entry ${type}`;
        const time = new Date().toLocaleTimeString('en-US', { hour12: false,
            hour: '2-digit', minute: '2-digit', second: '2-digit',
            fractionalSecondDigits: 3 });
        entry.textContent = `[${time}] ${msg}`;
        box.appendChild(entry);
        box.scrollTop = box.scrollHeight;
    }

    function setStatus(prefix, state, msg) {
        const ind = document.getElementById(`${prefix}Indicator`);
        const txt = document.getElementById(`${prefix}Status`);
        ind.className = `status-indicator ${state}`;
        txt.textContent = msg;
    }

    // ─────────────────────────────────────────────
    //  BUGGY IMPLEMENTATION
    // ─────────────────────────────────────────────
    let buggySharedProgress = 0;
    let buggyRunning = false;

    function updateBuggyBar(index, value) {
        const clamped = Math.min(value, 100);
        const bar = document.getElementById(`buggyBar${index}`);
        const val = document.getElementById(`buggyVal${index}`);
        bar.style.width = Math.min(clamped, 100) + '%';

        // Color coding: normal / warning / overflow
        const color = TASKS[index].color;
        if (value > 100) {
            bar.className = 'progress-fill overflow';
            bar.style.background = 'linear-gradient(90deg, #ff0000, #8b0000)';
        } else if (value > 80) {
            bar.style.background = `linear-gradient(90deg, ${color}88, #ff9f43)`;
        } else {
            bar.style.background = `linear-gradient(90deg, ${color}99, ${color})`;
        }
        val.textContent = value.toFixed(1) + '%';
        val.style.color = value > 100 ? '#ff0000' : color;
    }

    function updateBuggyTotal(value) {
        const el = document.getElementById('buggyTotal');
        const warn = document.getElementById('buggyWarning');
        el.textContent = value.toFixed(1) + '%';
        if (value > 100) {
            el.style.color = '#ff0000';
            warn.style.display = 'block';
        } else {
            el.style.color = '#ff5050';
            warn.style.display = 'none';
        }
    }

    async function runBuggy() {
        if (buggyRunning) return;
        buggyRunning = true;
        buggySharedProgress = 0;
        document.getElementById('btnBuggy').disabled = true;
        document.getElementById('buggyLog').innerHTML = '';

        // Reset bars
        TASKS.forEach((_, i) => updateBuggyBar(i, 0));
        updateBuggyTotal(0);
        document.getElementById('buggyWarning').style.display = 'none';

        setStatus('buggy', 'running', 'Running with race condition...');
        log('buggyLog', 'Starting 5 concurrent tasks with SHARED mutable state', 'warn');
        log('buggyLog', `Initial sharedProgress = ${buggySharedProgress}`, 'info');

        // ── THE BUG: all tasks fire simultaneously, sharing one variable ──
        // Each task: read → delay → write (no synchronization!)
        const promises = TASKS.map((task, index) => {
            return (async () => {
                log('buggyLog', `${task.name} STARTED (delay=${task.delay}ms, +${task.increment}%)`, 'info');

                await sleep(task.delay);

                // ❌ STALE READ: reads the value at this moment
                const staleRead = buggySharedProgress;
                log('buggyLog',
                    `${task.name} READ staleProgress=${staleRead.toFixed(1)}%`,
                    'warn');

                // Simulate some async work (e.g., network, computation)
                await sleep(40 + Math.random() * 60);

                // ❌ WRITE BACK: other tasks may have written in the meantime
                const newValue = staleRead + task.increment;
                buggySharedProgress = newValue;

                log('buggyLog',
                    `${task.name} WROTE ${staleRead.toFixed(1)} + ${task.increment} = ${newValue.toFixed(1)}%` +
                    (newValue > 100 ? ' ⚠️ OVERFLOW!' : ''),
                    newValue > 100 ? 'error' : 'success');

                updateBuggyBar(index, newValue);
                updateBuggyTotal(buggySharedProgress);
            })();
        });

        await Promise.all(promises);

        const finalVal = buggySharedProgress;
        log('buggyLog', `─────────────────────────────────`, 'info');
        log('buggyLog',
            `FINAL sharedProgress = ${finalVal.toFixed(1)}% ` +
            (finalVal > 100 ? '❌ BUG: exceeded 100%!' : `(Expected: ${TASKS.reduce((s,t)=>s+t.increment,0)}%)`),
            finalVal > 100 ? 'error' : 'warn');

        if (finalVal <= 100) {
            log('buggyLog',
                `NOTE: Race didn't overflow this run — try again! Timing varies.`,
                'warn');
        }

        updateBuggyTotal(finalVal);
        setStatus('buggy', 'done-bug',
            finalVal > 100
                ? `⚠️ Bug triggered! Final: ${finalVal.toFixed(1)}%`
                : `Ran OK this time (${finalVal.toFixed(1)}%) — try again!`);

        buggyRunning = false;
        document.getElementById('btnBuggy').disabled = false;
    }

    function resetBuggy() {
        if (buggyRunning) return;
        buggySharedProgress = 0;
        TASKS.forEach((_, i) => updateBuggyBar(i, 0));
        updateBuggyTotal(0);
        document.getElementById('buggyWarning').style.display = 'none';
        document.getElementById('buggyLog').innerHTML =
            '<div class="log-entry info">// Buggy log will appear here...</div>';
        setStatus('buggy', 'idle', 'Ready to run');
    }

    // ─────────────────────────────────────────────
    //  FIXED IMPLEMENTATION
    // ─────────────────────────────────────────────
    let fixedSharedProgress = 0;
    let fixedTaskQueue = Promise.resolve();   // ← the "mutex"
    let fixedRunning = false;

    function updateFixedBar(index, value) {
        const bar = document.getElementById(`fixedBar${index}`);
        const val = document.getElementById(`fixedVal${index}`);
        const color = TASKS[index].color;
        bar.style.width = value + '%';
        bar.style.background = `linear-gradient(90deg, ${color}99, ${color})`;
        val.textContent = value.toFixed(1) + '%';
        val.style.color = color;
    }

    function updateFixedTotal(value) {
        document.getElementById('fixedTotal').textContent = value.toFixed(1) + '%';
    }

    // ✅ Each task serializes itself onto the shared queue
    function enqueueFixedTask(task, index) {
        fixedTaskQueue = fixedTaskQueue.then(async () => {
            log('fixedLog', `${task.name} STARTED — waiting in queue`, 'info');

            await sleep(task.delay);

            // ✅ SAFE READ: we are the only task running right now
            const before = fixedSharedProgress;
            log('fixedLog',
                `${task.name} READ safeProgress=${before.toFixed(1)}%`, 'info');

            await sleep(40 + Math.random() * 60);

            // ✅ SAFE WRITE + CLAMP
            const raw = before + task.increment;
            const clamped = Math.min(raw, 100);
            fixedSharedProgress = clamped;

            log('fixedLog',
                `${task.name} WROTE ${before.toFixed(1)} + ${task.increment} = ${raw.toFixed(1)}%` +
                (raw !== clamped ? ` → clamped to ${clamped.toFixed(1)}%` : ''),
                'success');

            updateFixedBar(index, clamped);
            updateFixedTotal(fixedSharedProgress);
        });
        return fixedTaskQueue;
    }

    async function runFixed() {
        if (fixedRunning) return;
        fixedRunning = true;
        fixedSharedProgress = 0;
        fixedTaskQueue = Promise.resolve();   // reset the queue
        document.getElementById('btnFixed').disabled = true;
        document.getElementById('fixedLog').innerHTML = '';

        TASKS.forEach((_, i) => updateFixedBar(i, 0));
        updateFixedTotal(0);

        setStatus('fixed', 'running', 'Running with synchronized queue...');
        log('fixedLog', 'Starting 5 tasks via serialized promise queue', 'success');
        log('fixedLog', `Initial sharedProgress = ${fixedSharedProgress}`, 'info');

        // Enqueue all tasks — they will run one at a time
        const allDone = TASKS.map((task, i) => enqueueFixedTask(task, i));

        await Promise.all(allDone);

        const finalVal = fixedSharedProgress;
        log('fixedLog', `─────────────────────────────────`, 'info');
        log('fixedLog',
            `FINAL sharedProgress = ${finalVal.toFixed(1)}% ✅ Always ≤ 100%`,
            'success');

        updateFixedTotal(finalVal);
        setStatus('fixed', 'done-fix', `✅ Complete! Final: ${finalVal.toFixed(1)}% (no overflow)`);

        fixedRunning = false;
        document.getElementById('btnFixed').disabled = false;
    }

    function resetFixed() {
        if (fixedRunning) return;
        fixedSharedProgress = 0;
        fixedTaskQueue = Promise.resolve();
        TASKS.forEach((_, i) => updateFixedBar(i, 0));
        updateFixedTotal(0);
        document.getElementById('fixedLog').innerHTML =
            '<div class="log-entry info">// Fixed log will appear here...</div>';
        setStatus('fixed', 'idle', 'Ready to run');
    }
</script>
</body>
