<script>
/* ═══════════════════════════════════════════════════════
   SHARED HELPERS
═══════════════════════════════════════════════════════ */
const TASK_NAMES = ['Fetch user data', 'Load assets', 'Parse config', 'Sync cache'];
const TASK_COUNT = TASK_NAMES.length;

function buildTaskRows(containerId, prefix) {
  const container = document.getElementById(containerId);
  container.innerHTML = '';
  TASK_NAMES.forEach((name, i) => {
    container.innerHTML += `
      <div class="task-row">
        <div class="task-label">
          <span>${name}</span>
          <span id="${prefix}-pct-${i}">0%</span>
        </div>
        <div class="bar-track">
          <div class="bar-fill" id="${prefix}-bar-${i}"></div>
        </div>
      </div>`;
  });
}

function setBar(prefix, index, pct) {
  const bar = document.getElementById(`${prefix}-bar-${index}`);
  const lbl = document.getElementById(`${prefix}-pct-${index}`);
  if (bar) bar.style.width = pct + '%';
  if (lbl) lbl.textContent = Math.round(pct) + '%';
}

function setOverall(prefix, pct) {
  const bar = document.getElementById(`${prefix}-overall-bar`);
  const lbl = document.getElementById(`${prefix}-overall-pct`);
  if (bar) bar.style.width = pct + '%';
  if (lbl) lbl.textContent = Math.round(pct) + '%';
}

function log(boxId, msg, cls = '') {
  const box = document.getElementById(boxId);
  const line = document.createElement('div');
  if (cls) line.className = cls;
  line.textContent = `[${new Date().toLocaleTimeString('en',{hour12:false,hour:'2-digit',minute:'2-digit',second:'2-digit'})}] ${msg}`;
  box.innerHTML = '';
  box.appendChild(line);
  // keep last few lines
  box._lines = box._lines || [];
  box._lines.push(line);
  if (box._lines.length > 6) box._lines.shift().remove();
}

/* ═══════════════════════════════════════════════════════
   BUGGY IMPLEMENTATION
   The problem: a shared `completedTasks` counter is
   updated by every async callback. When tasks finish
   close together, the recomputed overall% can be
   wrong because each callback also tries to own the
   "final" state write.
   We simulate the race by intentionally staggering
   two tasks to finish at the *same* scheduled tick and
   letting both increment the shared counter — showing
   the bar can skip or report wrong totals.
═══════════════════════════════════════════════════════ */

let buggyRunning = false;
let buggyTimers  = [];

// ⚠️  SHARED MUTABLE STATE — the root of all evil here
let sharedCompletedCount = 0;
let sharedTotalExpected  = 0;

function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;
  document.getElementById('btn-buggy').disabled = true;

  buildTaskRows('buggy-tasks', 'buggy');
  document.getElementById('buggy-log')._lines = [];

  // Reset shared state
  sharedCompletedCount = 0;
  sharedTotalExpected  = TASK_COUNT;

  log('buggy-log', `Starting ${TASK_COUNT} tasks… (shared counter = ${sharedCompletedCount})`, 'log-info');

  // Simulate tasks with individual progress ticks
  // Tasks 1 & 2 are deliberately scheduled to finish at the SAME timeout
  // so both read sharedCompletedCount before either writes back.
  const durations = [900, 1400, 1400, 2200]; // tasks 1&2 finish simultaneously

  TASK_NAMES.forEach((name, i) => {
    const steps = 8;
    const stepTime = durations[i] / steps;

    for (let s = 1; s <= steps; s++) {
      const t = setTimeout(() => {
        const pct = (s / steps) * 100;
        setBar('buggy', i, pct);

        // ══ THE BUG ══
        // When s === steps, this task is "done".
        // Tasks at index 1 & 2 finish at the same wall-clock time.
        // Both will read sharedCompletedCount = (whatever it is),
        // both will compute the SAME new overall%, and both will
        // write it — meaning one completion is silently lost from
        // the percentage calculation on that tick.
        if (s === steps) {
          // Simulate reading stale state before the other concurrent
          // task has written its increment (the real race in disguise)
          const staleRead = sharedCompletedCount; // read
          // ... imagine async work happens here in a real app ...
          sharedCompletedCount = staleRead + 1;  // write back stale+1

          const buggyOverall = (sharedCompletedCount / sharedTotalExpected) * 100;
          setOverall('buggy', buggyOverall);

          const isFinalExpected = sharedCompletedCount === sharedTotalExpected;

          if (i === 1 || i === 2) {
            // These two collide — expose the stale-read visually
            log('buggy-log',
              `"${name}" done. counter=${sharedCompletedCount} (stale read was ${staleRead}) → overall ${Math.round(buggyOverall)}%`,
              staleRead === sharedCompletedCount - 1 && (i === 2) ? 'log-warn' : 'log-warn'
            );
          } else {
            log('buggy-log',
              `"${name}" done. counter=${sharedCompletedCount} → overall ${Math.round(buggyOverall)}%`,
              isFinalExpected ? 'log-ok' : 'log-info'
            );
          }

          if (isFinalExpected) {
            log('buggy-log', '⚠ Done — but did the bar reach 100% smoothly? Check the jumps!', 'log-warn');
            buggyRunning = false;
            document.getElementById('btn-buggy').disabled = false;
          }
        }
      }, stepTime * s + (i * 2)); // tiny i*2 offset to make collision obvious
      buggyTimers.push(t);
    }
  });

  // Force the collision: tasks 1 & 2 share the exact same finish time.
  // We schedule a second "done" event for task 2 that fires BEFORE task 1's
  // write has propagated, so both see sharedCompletedCount at the same value.
  const collisionTime = durations[1] + 2;
  const t = setTimeout(() => {
    // Task 2 fires its completion handler here, reading stale state
    // because task 1's handler (scheduled for the same ms) hasn't run yet
    const staleRead = sharedCompletedCount;
    // Both tasks write staleRead+1 → counter ends up at staleRead+1 not staleRead+2
    sharedCompletedCount = staleRead + 1;
    const buggyOverall = (sharedCompletedCount / sharedTotalExpected) * 100;
    setOverall('buggy', buggyOverall);
    log('buggy-log',
      `⚠ COLLISION: task 1&2 both read stale=${staleRead}, wrote ${staleRead+1}. Overall=${Math.round(buggyOverall)}% (should be ${Math.round(((staleRead+2)/sharedTotalExpected)*100)}%)`,
      'log-err'
    );
  }, collisionTime);
  buggyTimers.push(t);
}

function resetBuggy() {
  buggyTimers.forEach(clearTimeout);
  buggyTimers = [];
  buggyRunning = false;
  sharedCompletedCount = 0;
  sharedTotalExpected  = 0;
  buildTaskRows('buggy-tasks', 'buggy');
  setOverall('buggy', 0);
  document.getElementById('buggy-log').innerHTML = 'Reset. Ready to run.';
  document.getElementById('buggy-log')._lines = [];
  document.getElementById('btn-buggy').disabled = false;
}

/* ═══════════════════════════════════════════════════════
   FIXED IMPLEMENTATION
   Each task owns its own slot in `progressSlots[]`.
   The overall% is always derived by summing the array —
   no shared write target, no race, always consistent.
═══════════════════════════════════════════════════════ */

let fixedRunning = false;
let fixedTimers  = [];

// ✅ ISOLATED STATE — each task writes only its own index
let progressSlots = new Array(TASK_COUNT).fill(0);

function computeOverall() {
  const sum = progressSlots.reduce((a, b) => a + b, 0);
  return sum / TASK_COUNT; // each slot goes 0→100, so avg is the overall%
}

function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;
  document.getElementById('btn-fixed').disabled = true;

  buildTaskRows('fixed-tasks', 'fixed');
  document.getElementById('fixed-log')._lines = [];

  progressSlots = new Array(TASK_COUNT).fill(0);

  log('fixed-log', `Starting ${TASK_COUNT} tasks… (isolated slots)`, 'log-info');

  let completedCount = 0; // local, only incremented in one place per task
  const durations = [900, 1400, 1400, 2200]; // same timings as buggy

  TASK_NAMES.forEach((name, i) => {
    const steps = 8;
    const stepTime = durations[i] / steps;

    for (let s = 1; s <= steps; s++) {
      const t = setTimeout(() => {
        const pct = (s / steps) * 100;

        // ══ THE FIX ══
        // Write ONLY to our own slot. No other task touches progressSlots[i].
        progressSlots[i] = pct;
        setBar('fixed', i, pct);

        // Derive overall from the full array — pure read, no write conflict
        const overall = computeOverall();
        setOverall('fixed', overall);

        if (s === steps) {
          completedCount++;
          log('fixed-log',
            `"${name}" done. slots=[${progressSlots.map(v=>Math.round(v)).join(',')}] → overall ${Math.round(overall)}%`,
            completedCount === TASK_COUNT ? 'log-ok' : 'log-info'
          );

          if (completedCount === TASK_COUNT) {
            log('fixed-log', '✅ All tasks complete — bar reached exactly 100%. No jumps, no lost updates.', 'log-ok');
            fixedRunning = false;
            document.getElementById('btn-fixed').disabled = false;
          }
        }
      }, stepTime * s + (i * 2)); // same tiny offset as buggy for fair comparison
      fixedTimers.push(t);
    }
  });
}

function resetFixed() {
  fixedTimers.forEach(clearTimeout);
  fixedTimers = [];
  fixedRunning = false;
  progressSlots = new Array(TASK_COUNT).fill(0);
  buildTaskRows('fixed-tasks', 'fixed');
  setOverall('fixed', 0);
  document.getElementById('fixed-log').innerHTML = 'Reset. Ready to run.';
  document.getElementById('fixed-log')._lines = [];
  document.getElementById('btn-fixed').disabled = false;
}

/* ── init ── */
buildTaskRows('buggy-tasks', 'buggy');
buildTaskRows('fixed-tasks', 'fixed');
</script>
