<script>
'use strict';

/* ─────────────────────────────────────────────
   1.  Fibonacci implementations
───────────────────────────────────────────── */

/** BUGGY: fib(1) wrongly returns 0 */
function fibBuggy(n) {
  if (n === 0) return 0;
  if (n === 1) return 0;          // ← THE BUG
  return fibBuggy(n - 1) + fibBuggy(n - 2);
}

/** FIXED: standard definition */
function fibFixed(n) {
  if (n === 0) return 0;
  if (n === 1) return 1;          // ← CORRECT
  return fibFixed(n - 1) + fibFixed(n - 2);
}

/** Iterative helper — builds an array of n terms */
function buildSequence(fibFn, count) {
  return Array.from({ length: count }, (_, i) => fibFn(i));
}

/* ─────────────────────────────────────────────
   2.  Colour palette for arcs
───────────────────────────────────────────── */
const PALETTE = [
  '#f43f5e','#fb923c','#facc15','#4ade80',
  '#22d3ee','#818cf8','#c084fc','#f472b6',
  '#34d399','#38bdf8'
];

/* ─────────────────────────────────────────────
   3.  Core spiral drawing function

   A Fibonacci spiral is constructed by placing
   squares whose side = fib(n), then drawing a
   quarter-circle arc inside each square.

   Arc rotation sequence (quarter turns, CCW):
     0 → arc from 0   to π/2
     1 → arc from π/2 to π
     2 → arc from π   to 3π/2
     3 → arc from 3π/2 to 2π

   The pivot (arc centre) shifts after each arc
   so the next arc starts exactly where the last
   one ended.
───────────────────────────────────────────── */
function drawSpiral(canvas, fibFn, label) {
  const ctx  = canvas.getContext('2d');
  const W    = canvas.width;
  const H    = canvas.height;
  const TERMS = 10;          // how many Fibonacci squares
  const SCALE = 14;          // pixels per Fibonacci unit

  ctx.clearRect(0, 0, W, H);

  const seq = buildSequence(fibFn, TERMS + 1);

  /* Find the total bounding box so we can centre the spiral */
  // We do a dry-run to track extent
  let dryX = 0, dryY = 0;
  let minX = 0, minY = 0, maxX = 0, maxY = 0;
  const dirs = [
    [ 1,  0], [ 0,  1], [-1,  0], [ 0, -1]   // right, down, left, up
  ];
  for (let i = 1; i <= TERMS; i++) {
    const r   = seq[i] * SCALE;
    const dir = (i - 1) % 4;
    dryX += dirs[dir][0] * r;
    dryY += dirs[dir][1] * r;
    minX = Math.min(minX, dryX);
    minY = Math.min(minY, dryY);
    maxX = Math.max(maxX, dryX);
    maxY = Math.max(maxY, dryY);
  }
  const offsetX = W / 2 - (minX + maxX) / 2;
  const offsetY = H / 2 - (minY + maxY) / 2;

  /* ── Draw squares first (background layer) ── */
  let sx = offsetX, sy = offsetY;
  for (let i = 1; i <= TERMS; i++) {
    const r   = seq[i] * SCALE;
    const dir = (i - 1) % 4;
    const col = PALETTE[(i - 1) % PALETTE.length];

    // Square top-left corner depends on direction
    let sqX, sqY;
    if      (dir === 0) { sqX = sx;     sqY = sy - r; }
    else if (dir === 1) { sqX = sx;     sqY = sy;     }
    else if (dir === 2) { sqX = sx - r; sqY = sy;     }
    else                { sqX = sx - r; sqY = sy - r; }

    // Faint square fill
    ctx.fillStyle = col + '18';
    ctx.strokeStyle = col + '55';
    ctx.lineWidth = 1;
    ctx.fillRect(sqX, sqY, r, r);
    ctx.strokeRect(sqX, sqY, r, r);

    sx += dirs[dir][0] * r;
    sy += dirs[dir][1] * r;
  }

  /* ── Draw arcs (spiral layer) ── */
  /*
    Arc centre placement:
    direction 0 (right): centre is at (startX,       startY)
    direction 1 (down):  centre is at (startX + r,   startY)
    direction 2 (left):  centre is at (startX + r,   startY + r)  — wait, let's
    direction 3 (up):    centre is at (startX,        startY + r)  — track carefully

    Actually we track the "pivot corner" of each square.
    Each quarter arc sweeps 90° and the centre is the inner corner of the square.
  */

  // Arc angle ranges per direction (CCW = false means clockwise in canvas coords)
  const arcAngles = [
    { start: Math.PI,       end: Math.PI * 1.5 },  // dir 0: right
    { start: Math.PI * 1.5, end: Math.PI * 2   },  // dir 1: down
    { start: 0,             end: Math.PI * 0.5 },  // dir 2: left
    { start: Math.PI * 0.5, end: Math.PI       },  // dir 3: up
  ];

  // Pivot offset from square top-left
  const pivotOffset = [
    (r) => ({ px: 0, py: r }),   // dir 0
    (r) => ({ px: 0, py: 0 }),   // dir 1
    (r) => ({ px: r, py: 0 }),   // dir 2
    (r) => ({ px: r, py: r }),   // dir 3
  ];

  let ax = offsetX, ay = offsetY;

  for (let i = 1; i <= TERMS; i++) {
    const r   = seq[i] * SCALE;
    const dir = (i - 1) % 4;
    const col = PALETTE[(i - 1) % PALETTE.length];
    const aa  = arcAngles[dir];

    // Square top-left
    let sqX, sqY;
    if      (dir === 0) { sqX = ax;     sqY = ay - r; }
    else if (dir === 1) { sqX = ax;     sqY = ay;     }
    else if (dir === 2) { sqX = ax - r; sqY = ay;     }
    else                { sqX = ax - r; sqY = ay - r; }

    const { px, py } = pivotOffset[dir](r);
    const cx = sqX + px;
    const cy = sqY + py;

    // Draw the arc
    ctx.beginPath();
    ctx.arc(cx, cy, r, aa.start, aa.end, false);
    ctx.strokeStyle = col;
    ctx.lineWidth   = r > 0 ? Math.max(1.5, r * 0.04) : 1.5;
    ctx.lineCap     = 'round';
    ctx.stroke();

    // Tiny circle at arc centre
    if (r > 4) {
      ctx.beginPath();
      ctx.arc(cx, cy, 2.5, 0, Math.PI * 2);
      ctx.fillStyle = col + 'cc';
      ctx.fill();
    }

    // Advance position
    ax += dirs[dir][0] * r;
    ay += dirs[dir][1] * r;
  }

  /* ── Watermark label ── */
  ctx.font = 'bold 13px monospace';
  ctx.fillStyle = '#ffffff22';
  ctx.textAlign = 'right';
  ctx.fillText(label, W - 12, H - 10);

  /* ── "Nothing drawn" notice for buggy version ── */
  const allZero = seq.slice(1).every(v => v === 0);
  if (allZero) {
    ctx.font = 'bold 18px sans-serif';
    ctx.fillStyle = '#ef4444cc';
    ctx.textAlign = 'center';
    ctx.fillText('⚠ All arc radii = 0 — nothing visible!', W / 2, H / 2 - 12);
    ctx.font = '13px monospace';
    ctx.fillStyle = '#fca5a5aa';
    ctx.fillText('fib(0)=0, fib(1)=0 → every term = 0', W / 2, H / 2 + 14);
    ctx.fillText('Canvas API is fine; the sequence is broken.', W / 2, H / 2 + 34);
  }
}

/* ─────────────────────────────────────────────
   4.  Build colour legend
───────────────────────────────────────────── */
function buildLegend(containerId, fibFn, terms = 10) {
  const container = document.getElementById(containerId);
  const seq = buildSequence(fibFn, terms + 1);
  for (let i = 1; i <= terms; i++) {
    const col  = PALETTE[(i - 1) % PALETTE.length];
    const item = document.createElement('div');
    item.className = 'legend-item';
    item.innerHTML = `
      <div class="legend-swatch" style="background:${col}"></div>
      <span style="color:${col}">fib(${i})=${seq[i]}</span>
    `;
    container.appendChild(item);
  }
}

/* ─────────────────────────────────────────────
   5.  Build sequence comparison table
───────────────────────────────────────────── */
function buildTable(terms = 10) {
  const tbody = document.getElementById('seqTableBody');
  const SCALE = 14;
  for (let i = 0; i <= terms; i++) {
    const bad  = fibBuggy(i);
    const good = fibFixed(i);
    const tr   = document.createElement('tr');
    tr.innerHTML = `
      <td>${i}</td>
      <td class="bad-val">${bad}</td>
      <td class="good-val">${good}</td>
      <td class="good-val">${good * SCALE}px</td>
    `;
    tbody.appendChild(tr);
  }
}

/* ─────────────────────────────────────────────
   6.  Initialise everything
───────────────────────────────────────────── */
(function init() {
  const buggyCanvas = document.getElementById('buggyCanvas');
  const fixedCanvas = document.getElementById('fixedCanvas');

  drawSpiral(buggyCanvas, fibBuggy, 'BUGGY — fib(1)=0');
  drawSpiral(fixedCanvas, fibFixed, 'FIXED — fib(1)=1');

  buildLegend('buggyLegend', fibBuggy);
  buildLegend('fixedLegend', fibFixed);
  buildTable(10);
})();
</script>
</body>
