<script>
/* ═══════════════════════════════════════════════════════
   CONFIG
═══════════════════════════════════════════════════════ */
const SCALE       = 18;      // pixels per Fibonacci unit
const MAX_ARCS    = 10;      // how many arcs to draw
const ANIM_DELAY  = 700;     // ms between arcs

/* ═══════════════════════════════════════════════════════
   STATE
═══════════════════════════════════════════════════════ */
let animating    = true;
let currentStep  = 0;
let animTimer    = null;
let showGrid     = false;
let showLabels   = true;

/* ═══════════════════════════════════════════════════════
   FIBONACCI — BUGGY (base case n===1 returns 0)
═══════════════════════════════════════════════════════ */
function fibBuggy(n) {
    if (n <= 0) return 0;
    if (n === 1) return 0;          // ← THE BUG
    return fibBuggy(n - 1) + fibBuggy(n - 2);
}

/* ═══════════════════════════════════════════════════════
   FIBONACCI — FIXED
═══════════════════════════════════════════════════════ */
function fibFixed(n) {
    if (n <= 0) return 0;
    if (n === 1) return 1;          // ← THE FIX
    return fibFixed(n - 1) + fibFixed(n - 2);
}

/* ═══════════════════════════════════════════════════════
   BUILD SEQUENCE ARRAYS
═══════════════════════════════════════════════════════ */
function buildSequence(fibFn, count) {
    const seq = [];
    for (let i = 1; i <= count; i++) seq.push(fibFn(i));
    return seq;
}

/* ═══════════════════════════════════════════════════════
   PIVOT DIRECTION TABLE
   Each quarter-arc turns 90° clockwise.
   The pivot for arc[i+1] is offset from pivot[i] by
   the current radius in the direction of travel.

   Direction cycle (index % 4):
     0 → right  (+x)
     1 → down   (+y)
     2 → left   (−x)
     3 → up     (−y)

   Arc start/end angles (canvas coords, 0=right):
     0 → π   to  3π/2   (bottom-left quadrant)
     1 → 3π/2 to 2π     (bottom-right quadrant)
     2 → 0   to  π/2    (top-right quadrant)
     3 → π/2 to  π      (top-left quadrant)
═══════════════════════════════════════════════════════ */
const ARC_ANGLES = [
    { start: Math.PI,           end: 3 * Math.PI / 2 },
    { start: 3 * Math.PI / 2,  end: 2 * Math.PI      },
    { start: 0,                 end: Math.PI / 2      },
    { start: Math.PI / 2,       end: Math.PI          },
];

// After drawing arc i, move pivot by:
const PIVOT_DELTA = [
    (r) => ({ dx:  r, dy:  0 }),   // 0: move right
    (r) => ({ dx:  0, dy:  r }),   // 1: move down
    (r) => ({ dx: -r, dy:  0 }),   // 2: move left
    (r) => ({ dx:  0, dy: -r }),   // 3: move up
];

/* ═══════════════════════════════════════════════════════
   COMPUTE ARC DATA  (pivot list + scaled radii)
═══════════════════════════════════════════════════════ */
function computeArcs(seq, canvasW, canvasH) {
    // Find a good starting pivot so spiral is centred
    // We'll centre it after computing all pivots
    const pivots = [];
    let px = 0, py = 0;
    for (let i = 0; i < seq.length; i++) {
        pivots.push({ x: px, y: py });
        const r = seq[i] * SCALE;
        const delta = PIVOT_DELTA[i % 4](r);
        px += delta.dx;
        py += delta.dy;
    }

    // Bounding box of all arcs
    let minX = Infinity, maxX = -Infinity;
    let minY = Infinity, maxY = -Infinity;
    for (let i = 0; i < pivots.length; i++) {
        const r = seq[i] * SCALE;
        minX = Math.min(minX, pivots[i].x - r);
        maxX = Math.max(maxX, pivots[i].x + r);
        minY = Math.min(minY, pivots[i].y - r);
        maxY = Math.max(maxY, pivots[i].y + r);
    }

    // Offset to centre
    const offX = (canvasW - (maxX + minX)) / 2;
    const offY = (canvasH - (maxY + minY)) / 2;

    return pivots.map((p, i) => ({
        x:     p.x + offX,
        y:     p.y + offY,
        r:     seq[i] * SCALE,
        fib:   seq[i],
        start: ARC_ANGLES[i % 4].start,
        end:   ARC_ANGLES[i % 4].end,
        index: i,
    }));
}

/* ═══════════════════════════════════════════════════════
   COLOUR PALETTE  (hue cycles through arcs)
═══════════════════════════════════════════════════════ */
function arcColor(index, alpha = 1) {
    const hue = (index * 36) % 360;
    return `hsla(${hue}, 80%, 65%, ${alpha})`;
}

/* ═══════════════════════════════════════════════════════
   DRAW GRID
═══════════════════════════════════════════════════════ */
function drawGrid(ctx, w, h) {
    ctx.save();
    ctx.strokeStyle = '#ffffff08';
    ctx.lineWidth   = 0.5;
    const step = SCALE;
    for (let x = 0; x < w; x += step) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, h); ctx.stroke();
    }
    for (let y = 0; y < h; y += step) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(w, y); ctx.stroke();
    }
    ctx.restore();
}

/* ═══════════════════════════════════════════════════════
   DRAW ONE VERSION  (buggy or fixed)
═══════════════════════════════════════════════════════ */
function drawSpiral(canvasId, arcs, stepCount, isBuggy) {
    const canvas = document.getElementById(canvasId);
    const ctx    = canvas.getContext('2d');
    const W = canvas.width, H = canvas.height;

    ctx.clearRect(0, 0, W, H);

    if (showGrid) drawGrid(ctx, W, H);

    // Draw squares first (background)
    for (let i = 0; i < Math.min(stepCount, arcs.length); i++) {
        const a = arcs[i];
        if (a.r <= 0) continue;

        ctx.save();
        ctx.fillStyle = arcColor(i, 0.06);
        ctx.strokeStyle = arcColor(i, 0.25);
        ctx.lineWidth = 0.5;
        ctx.strokeRect(a.x - a.r, a.y - a.r, a.r * 2, a.r * 2);
        ctx.restore();
    }

    // Draw arcs
    for (let i = 0; i < Math.min(stepCount, arcs.length); i++) {
        const a = arcs[i];
        const isLast = (i === stepCount - 1);

        ctx.save();
        ctx.beginPath();
        ctx.arc(a.x, a.y, Math.max(a.r, 0.1), a.start, a.end);
        ctx.strokeStyle = isLast
            ? (isBuggy ? '#ff6b6b' : '#4fff90')
            : arcColor(i, 0.85);
        ctx.lineWidth   = isLast ? 3 : 1.5;
        ctx.shadowColor = ctx.strokeStyle;
        ctx.shadowBlur  = isLast ? 12 : 4;
        ctx.stroke();
        ctx.restore();

        // Pivot dot
        ctx.save();
        ctx.beginPath();
        ctx.arc(a.x, a.y, isLast ? 4 : 2.5, 0, Math.PI * 2);
        ctx.fillStyle = arcColor(i, isLast ? 1 : 0.6);
        ctx.shadowColor = ctx.fillStyle;
        ctx.shadowBlur  = 6;
        ctx.fill();
        ctx.restore();

        // Label
        if (showLabels && a.r > 5) {
            ctx.save();
            ctx.font      = `${Math.min(11, Math.max(7, a.r * 0.22))}px Courier New`;
            ctx.fillStyle = arcColor(i, 0.9);
            ctx.textAlign = 'center';
            ctx.fillText(`F${i + 1}=${a.fib}`, a.x, a.y - 5);
            ctx.restore();
        }
    }

    // "No spiral" overlay for buggy when all radii are 0
    if (isBuggy && arcs.every(a => a.r === 0)) {
        ctx.save();
        ctx.font      = 'bold 14px Courier New';
        ctx.fillStyle = '#ff6b6b88';
        ctx.textAlign = 'center';
        ctx.fillText('⚠ All radii = 0 (invisible spiral)', W / 2, H / 2 + 20);
        ctx.restore();
    }

    // Buggy: show big warning if arcs are zero-size
    if (isBuggy && stepCount > 0) {
        const zeroCount = arcs.slice(0, stepCount).filter(a => a.r === 0).length;
        if (zeroCount > 0) {
            ctx.save();
            ctx.font      = '11px Courier New';
            ctx.fillStyle = '#ff6b6b99';
            ctx.textAlign = 'left';
            ctx.fillText(`⚠ ${zeroCount} arc(s) with radius 0`, 10, H - 12);
            ctx.restore();
        }
    }
}

/* ═══════════════════════════════════════════════════════
   UPDATE SEQUENCE LABELS
═══════════════════════════════════════════════════════ */
function updateSeqLabel(elId, seq, stepCount) {
    const el = document.getElementById(elId);
    const parts = seq.map((v, i) => {
        const active = i < stepCount;
        const cls    = active ? 'highlight' : '';
        return `<span class="${cls}">F${i + 1}=${v}</span>`;
    });
    el.innerHTML = 'Sequence: ' + parts.join(', ');
}

/* ═══════════════════════════════════════════════════════
   LOGGING
═══════════════════════════════════════════════════════ */
function log(msg, type = 'info') {
    const el   = document.getElementById('logEntries');
    const line = document.createElement('div');
    line.className = `log-${type}`;
    line.textContent = `[${new Date().toLocaleTimeString()}] ${msg}`;
    el.prepend(line);
    // Keep max 60 lines
    while (el.children.length > 60) el.removeChild(el.lastChild);
}

/* ═══════════════════════════════════════════════════════
   MAIN RENDER CALL
═══════════════════════════════════════════════════════ */
let buggyArcs = [];
let fixedArcs = [];
let buggySeq  = [];
let fixedSeq  = [];

function init() {
    const W = 460, H = 460;

    buggySeq  = buildSequence(fibBuggy, MAX_ARCS);
    fixedSeq  = buildSequence(fibFixed,  MAX_ARCS);
    buggyArcs = computeArcs(buggySeq, W, H);
    fixedArcs = computeArcs(fixedSeq,  W, H);

    log(`Buggy sequence: [${buggySeq.join(', ')}]`, 'err');
    log(`Fixed sequence: [${fixedSeq.join(', ')}]`, 'ok');
    log('Initialised both spirals.', 'info');
}

function render() {
    const step = currentStep === 0 ? MAX_ARCS : currentStep;

    drawSpiral('buggyCanvas', buggyArcs, step, true);
    drawSpiral('fixedCanvas', fixedArcs, step, false);
    updateSeqLabel('buggySeq', buggySeq, step);
    updateSeqLabel('fixedSeq', fixedSeq, step);

    const arcLabel = currentStep === 0
        ? `Showing all ${MAX_ARCS} arcs`
        : `Drawing arc ${currentStep} of ${MAX_ARCS}`;
    document.getElementById('stepInfo').textContent = arcLabel;
}

/* ═══════════════════════════════════════════════════════
   ANIMATION LOOP
═══════════════════════════════════════════════════════ */
function startAnimation() {
    currentStep = 1;
    animTimer = setInterval(() => {
        render();
        log(
            `Arc ${currentStep}: buggy r=${buggyArcs[currentStep-1]?.r.toFixed(0)}px  ` +
            `fixed r=${fixedArcs[currentStep-1]?.r.toFixed(0)}px`,
            buggyArcs[currentStep-1]?.r === 0 ? 'warn' : 'info'
        );
        currentStep++;
        if (currentStep > MAX_ARCS) {
            clearInterval(animTimer);
            animTimer = null;
            animating = false;
            currentStep = 0;
            render();
            document.getElementById('btnAnimate').textContent = '▶ Replay';
            document.getElementById('btnAnimate').classList.remove('active');
            log('Animation complete.', 'ok');
        }
    }, ANIM_DELAY);
}

function stopAnimation() {
    clearInterval(animTimer);
    animTimer = null;
}

/* ═══════════════════════════════════════════════════════
   CONTROL HANDLERS
═══════════════════════════════════════════════════════ */
function toggleAnimation() {
    const btn = document.getElementById('btnAnimate');
    if (!animating) {
        // Replay
        animating = true;
        btn.textContent = '⏸ Pause Animation';
        btn.classList.add('active');
        log('Animation started.', 'info');
        startAnimation();
    } else {
        if (animTimer) {
            stopAnimation();
            btn.textContent = '▶ Resume';
            btn.classList.remove('active');
            log('Animation paused.', 'warn');
        } else {
            startAnimation();
            btn.textContent = '⏸ Pause Animation';
            btn.classList.add('active');
            log('Animation resumed.', 'info');
        }
    }
}

function stepForward() {
    stopAnimation();
    animating = false;
    document.getElementById('btnAnimate').textContent = '▶ Resume';
    document.getElementById('btnAnimate').classList.remove('active');
    if (currentStep === 0) currentStep = 1;
    else currentStep = Math.min(currentStep + 1, MAX_ARCS);
    log(
        `Step ${currentStep}: buggy r=${buggyArcs[currentStep-1]?.r.toFixed(0)}px  ` +
        `fixed r=${fixedArcs[currentStep-1]?.r.toFixed(0)}px`,
        buggyArcs[currentStep-1]?.r === 0 ? 'warn' : 'ok'
    );
    render();
}

function resetAll() {
    stopAnimation();
    animating = true;
    currentStep = 0;
    const btn = document.getElementById('btnAnimate');
    btn.textContent = '⏸ Pause Animation';
    btn.classList.add('active');
    log('Reset. Replaying…', 'info');
    render();
    startAnimation();
}

function toggleGrid() {
    showGrid = !showGrid;
    log(`Grid ${showGrid ? 'on' : 'off'}.`, 'info');
    render();
}

function toggleLabels() {
    showLabels = !showLabels;
    log(`Labels ${showLabels ? 'on' : 'off'}.`, 'info');
    render();
}

/* ═══════════════════════════════════════════════════════
   BOOT
═══════════════════════════════════════════════════════ */
init();
render();
startAnimation();
</script>
</body>
</html>
