  </div>

  <!-- ============================================================ FIXED PANEL -->
  <div class="panel fixed" id="fixedPanel">
    <h2>✅ FIXED VERSION <span class="status-badge badge-idle" id="fixedBadge">IDLE</span></h2>
    <p class="tagline">Tasks own their slice; master reads derived state only — no races</p>

    <div class="bar-wrap">
      <div class="bar" id="fixedBar"></div>
    </div>
    <div class="pct-label" id="fixedPct">0% — waiting</div>

    <div class="task-list" id="fixedTasks"></div>

    <div class="log" id="fixedLog"></div>

    <button class="btn btn-run-fixed" id="btnRunFixed" onclick="runFixed()">▶ RUN FIXED</button>
    <button class="btn btn-reset"     id="btnResetFixed" onclick="resetFixed()">↺ RESET</button>
  </div>

