  { name: 'Parser',  color: '#ff8800', duration: 2200, tick: 60  },
  { name: 'Fetcher', color: '#ffcc00', duration: 4500, tick: 120 },
  { name: 'Writer',  color: '#44ff88', duration: 1800, tick: 50  },
  { name: 'Indexer', color: '#5599ff', duration: 5000, tick: 150 },
];

// ─────────────────────────────────────────────────────────────────────────────
// UTILITIES
// ─────────────────────────────────────────────────────────────────────────────
function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }
function now() { return performance.now(); }
function fmtMs(ms) { return ms.toFixed(0) + 'ms'; }

function appendLog(logEl, msg, cls) {
  const d = document.createElement('div');
  d.className = 'entry ' + (cls || '');
  d.textContent = '[' + (performance.now() / 1000).toFixed(3) + 's] ' + msg;
  logEl.appendChild(d);
  logEl.scrollTop = logEl.scrollHeight;
}

function buildTaskRows(containerEl, defs, idPrefix) {
  containerEl.innerHTML = '';
  defs.forEach((def, i) => {
    const row = document.createElement('div');
    row.className = 'task-row';
    row.innerHTML = `
      <span class="task-name">${def.name}</span>
      <div class="task-bar-wrap">
        <div class="task-bar" id="${idPrefix}TaskBar${i}" style="background:${def.color}"></div>
      </div>
      <span class="task-pct" id="${idPrefix}TaskPct${i}">0%</span>
    `;
    containerEl.appendChild(row);
  });
}

function setTaskUI(idPrefix, i, pct) {
  const bar = document.getElementById(idPrefix + 'TaskBar' + i);
  const lbl = document.getElementById(idPrefix + 'TaskPct' + i);
  if (bar) bar.style.width = clamp(pct, 0, 100) + '%';
  if (lbl) lbl.textContent = clamp(pct, 0, 100).toFixed(0) + '%';
}

function setMasterUI(barId, pctId, pct, suffix) {
  const bar = document.getElementById(barId);
  const lbl = document.getElementById(pctId);
  // Allow buggy bar to go out of bounds visually — that's the point
  if (bar) bar.style.width = clamp(pct, 0, 120) + '%';
  if (lbl) lbl.textContent = pct.toFixed(1) + '% — ' + (suffix || '');
}

function setBadge(id, text, cls) {
  const el = document.getElementById(id);
  if (!el) return;
  el.textContent = text;
  el.className = 'status-badge ' + cls;
}

// ─────────────────────────────────────────────────────────────────────────────
//  ██████  ██    ██  ██████   ██████  ██    ██
//  ██   ██ ██    ██ ██       ██       ██    ██
//  ██████  ██    ██ ██   ███ ██   ███ ████████
//  ██   ██ ██    ██ ██    ██ ██    ██ ██    ██
//  ██████   ██████   ██████   ██████  ██    ██
//
// THE BUGGY VERSION
// Bugs planted:
//   1. sharedProgress is a single number mutated by all tasks
//   2. Each task adds increments to sharedProgress — deltas accumulate wrongly
//      because other tasks also mutated it between ticks (logical race)
//   3. Tasks use a local `accumulated` that drifts from sharedProgress
//   4. No proper completion guard — timer fires one extra tick past 100%
//   5. Master bar is driven by sharedProgress directly (mutable shared state)
// ─────────────────────────────────────────────────────────────────────────────
let buggyRunning = false;
let buggyTimers  = [];
// THE SHARED MUTABLE STATE — this is the bug source
let sharedProgress = 0;
// Per-task "local" progress — but tasks also write to sharedProgress
let buggyTaskProgress = [];

function resetBuggy() {
  buggyTimers.forEach(t => clearTimeout(t));
  buggyTimers = [];
  buggyRunning = false;
  sharedProgress = 0;
  buggyTaskProgress = [];
  setMasterUI('buggyBar', 'buggyPct', 0, 'waiting');
  setBadge('buggyBadge', 'IDLE', 'badge-idle');
  buildTaskRows(document.getElementById('buggyTasks'), TASK_DEFS, 'buggy');
  document.getElementById('buggyLog').innerHTML = '';
  document.getElementById('btnRunBuggy').disabled = false;
}

function runBuggy() {
  if (buggyRunning) return;
  buggyRunning = true;
  sharedProgress = 0;
  buggyTaskProgress = new Array(TASK_DEFS.length).fill(0);
  document.getElementById('btnRunBuggy').disabled = true;
  setBadge('buggyBadge', 'RUNNING', 'badge-running');
  buildTaskRows(document.getElementById('buggyTasks'), TASK_DEFS, 'buggy');
  const log = document.getElementById('buggyLog');
  appendLog(log, 'Starting ' + TASK_DEFS.length + ' concurrent tasks on SHARED state', 'info');

  let completedCount = 0;
  const startTime = now();

  TASK_DEFS.forEach((def, i) => {
    const totalTicks = Math.ceil(def.duration / def.tick);
    let ticksFired = 0;

    // ── BUG: `myShare` is computed once at start.
    //    But sharedProgress will be mutated by OTHER tasks between our ticks,
    //    so our delta additions pile on top of already-corrupted state.
    const myShare = 100 / TASK_DEFS.length;  // each task "owns" 20% of master

    function tick() {
      ticksFired++;

      // ── BUG #1: We read sharedProgress here. Another task may have JUST
      //    written to it. We don't know. We add our delta anyway.
      //    If two tasks fire within the same event loop turn boundary,
      //    they both read the same stale value and both add — one is lost.
      //    Over hundreds of ticks this creates significant drift.
      const rawPct = (ticksFired / totalTicks) * 100;
      const delta  = rawPct - buggyTaskProgress[i];  // how much WE progressed

      // ── BUG #2: We store our local progress, but then add delta to SHARED.
      //    The shared value is now: previous_shared + OUR_delta
      //    But previous_shared already includes OTHER tasks' deltas that
      //    may have been applied multiple times or missed entirely.
      buggyTaskProgress[i] = rawPct;
      sharedProgress += delta;  // ← THE RACE: multiple writers, no coordination

      // ── BUG #3: sharedProgress can exceed 100 because deltas from fast tasks
      //    keep accumulating even after they "finish" (off-by-one on guard)
      setTaskUI('buggy', i, buggyTaskProgress[i]);
      setMasterUI('buggyBar', 'buggyPct', sharedProgress,
        sharedProgress > 100 ? '🔴 OVERFLOW!' : sharedProgress < 0 ? '🔴 UNDERFLOW!' : 'running');

      if (sharedProgress > 102 || sharedProgress < -2) {
        appendLog(log, `CORRUPTION: sharedProgress=${sharedProgress.toFixed(2)}% (task ${def.name})`, 'err');
      }

      // ── BUG #4: Completion check is AFTER the write. The final tick fires,
      //    writes past 100, THEN we check. One phantom update always leaks.
      if (ticksFired >= totalTicks) {
        // We're done — but sharedProgress is already corrupted by this point
        appendLog(log, `${def.name} done. sharedProgress=${sharedProgress.toFixed(1)}%`, 'warn');
        completedCount++;
        if (completedCount === TASK_DEFS.length) {
          appendLog(log, `ALL DONE. Final sharedProgress=${sharedProgress.toFixed(2)}% ← should be 100!`, 
            Math.abs(sharedProgress - 100) > 1 ? 'err' : 'ok');
          setBadge('buggyBadge', sharedProgress.toFixed(1) + '%', 
            Math.abs(sharedProgress - 100) > 1 ? 'badge-broken' : 'badge-done');
        }
        return; // don't schedule next tick
      }

      const tid = setTimeout(tick, def.tick);
      buggyTimers.push(tid);
    }

    // Stagger starts slightly — this makes races MORE visible, not less.
    // In real systems tasks start at unpredictable times.
    const startDelay = Math.random() * 200;
    const tid = setTimeout(tick, startDelay);
    buggyTimers.push(tid);
    appendLog(log, `${def.name} scheduled (dur=${fmtMs(def.duration)}, tick=${fmtMs(def.tick)})`, 'info');
  });
}


// ─────────────────────────────────────────────────────────────────────────────
//  ███████ ██ ██   ██ ███████ ██████
//  ██      ██  ██ ██  ██      ██   ██
//  █████   ██   ███   █████   ██   ██
//  ██      ██  ██ ██  ██      ██   ██
//  ██      ██ ██   ██ ███████ ██████
//
// THE FIXED VERSION
// Fixes applied:
//   1. No shared mutable state. Each task writes ONLY to taskState[i].progress
//   2. Master progress is DERIVED (computed) from taskState[] — never stored
//   3. Tasks use absolute values, not deltas — no accumulation drift
//   4. Each task owns its timer ID and cancels it cleanly on completion
//   5. Completion guard fires BEFORE the write — no phantom ticks
// ─────────────────────────────────────────────────────────────────────────────
let fixedRunning = false;
// Per-task isolated state — no task touches another task's entry
let fixedTaskState = [];
// Timer IDs owned by each task — for clean cancellation
let fixedTaskTimers = [];

function deriveMasterProgress() {
  // Pure function — reads isolated state, computes result, touches nothing
  if (fixedTaskState.length === 0) return 0;
  const sum = fixedTaskState.reduce((acc, t) => acc + t.progress, 0);
  return sum / fixedTaskState.length;
}

function resetFixed() {
  fixedTaskTimers.forEach(t => clearTimeout(t));
  fixedTaskTimers = [];
  fixedRunning = false;
  fixedTaskState = [];
  setMasterUI('fixedBar', 'fixedPct', 0, 'waiting');
  setBadge('fixedBadge', 'IDLE', 'badge-idle');
  buildTaskRows(document.getElementById('fixedTasks'), TASK_DEFS, 'fixed');
  document.getElementById('fixedLog').innerHTML = '';
  document.getElementById('btnRunFixed').disabled = false;
}

function runFixed() {
  if (fixedRunning) return;
  fixedRunning = true;
  fixedTaskTimers = new Array(TASK_DEFS.length).fill(null);
  fixedTaskState  = TASK_DEFS.map(() => ({ progress: 0, done: false }));
  document.getElementById('btnRunFixed').disabled = true;
  setBadge('fixedBadge', 'RUNNING', 'badge-running');
  buildTaskRows(document.getElementById('fixedTasks'), TASK_DEFS, 'fixed');
  const log = document.getElementById('fixedLog');
  appendLog(log, 'Starting ' + TASK_DEFS.length + ' concurrent tasks with ISOLATED state', 'info');

  let completedCount = 0;

  TASK_DEFS.forEach((def, i) => {
    const totalTicks = Math.ceil(def.duration / def.tick);
    let ticksFired = 0;

    function tick() {
      // ── FIX #1: Completion guard BEFORE any write or reschedule
      if (fixedTaskState[i].done) return;

      ticksFired++;

      // ── FIX #2: Absolute value, not delta. No accumulation, no drift.
      //    This task ONLY writes to its own slot. Period.
      const absolutePct = clamp((ticksFired / totalTicks) * 100, 0, 100);
      fixedTaskState[i].progress = absolutePct;  // ← isolated write

      // ── FIX #3: Master progress is DERIVED here, not stored anywhere.
      //    It's computed fresh from the current snapshot of all task states.
      //    No task can corrupt it because it's never mutated — only computed.
      const master = deriveMasterProgress();

      setTaskUI('fixed', i, absolutePct);
      setMasterUI('fixedBar', 'fixedPct', master, 'running');

      if (ticksFired >= totalTicks) {
        // ── FIX #4: Mark done BEFORE clearing timer — no phantom ticks
        fixedTaskState[i].done = true;
        fixedTaskState[i].progress = 100;
        clearTimeout(fixedTaskTimers[i]);
        fixedTaskTimers[i] = null;

        const finalMaster = deriveMasterProgress();
        setTaskUI('fixed', i, 100);
        setMasterUI('fixedBar', 'fixedPct', finalMaster, 'running');
        appendLog(log, `${def.name} done. master=${finalMaster.toFixed(1)}%`, 'ok');

        completedCount++;
        if (completedCount === TASK_DEFS.length) {
          const trueFinal = deriveMasterProgress();
          appendLog(log, `ALL DONE. master=${trueFinal.toFixed(2)}% ← exactly 100!`, 'ok');
          setMasterUI('fixedBar', 'fixedPct', 100, 'complete ✓');
          setBadge('fixedBadge', '100.0%', 'badge-done');
        }
        return;
      }

      // ── FIX #5: Store timer ID so we can cancel it cleanly
      fixedTaskTimers[i] = setTimeout(tick, def.tick);
    }

    const startDelay = Math.random() * 200;
    fixedTaskTimers[i] = setTimeout(tick, startDelay);
    appendLog(log, `${def.name} scheduled (dur=${fmtMs(def.duration)}, tick=${fmtMs(def.tick)})`, 'info');
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// INIT
// ─────────────────────────────────────────────────────────────────────────────
resetBuggy();
resetFixed();
</script>
