// ─────────────────────────────────────────────────────────────────────────────
// Shared: build the Fibonacci square layout
// Each square records its grid position and size (= Fibonacci number × scale).
// The spiral grows by appending a new square whose side equals the sum of the
// two previous sides, placed on the appropriate edge of the current rectangle.
// ─────────────────────────────────────────────────────────────────────────────
function buildSquares(count, scale) {
  // Fibonacci numbers
  const fibs = [1, 1];
  for (let i = 2; i < count; i++) fibs.push(fibs[i-1] + fibs[i-2]);

  // placement direction cycles: right, up, left, down
  // relative to the bounding box's corner each time
  const squares = [];

  // bounding box of all placed squares so far (in grid units)
  let bx = 0, by = 0, bw = 1, bh = 1; // starts with first 1×1 square

  // first square
  squares.push({ x: 0, y: 0, size: fibs[0] * scale });

  // second square (place to the right of first)
  squares.push({ x: fibs[0] * scale, y: 0, size: fibs[1] * scale });
  bw = fibs[0] + fibs[1]; // bounding box in fib units

  for (let i = 2; i < count; i++) {
    const s = fibs[i] * scale;
    const dir = i % 4; // 2→top, 3→left, 0→bottom, 1→right  (after first two)
    // Remap: step index for placement direction (first two squares already placed)
    // Pattern after index 1: place on top, left, bottom, right, top, left ...
    // i=2 → top, i=3 → left, i=4 → bottom, i=5 → right, i=6 → top ...
    const placement = (i - 2) % 4; // 0=top,1=left,2=bottom,3=right
    let nx, ny;
    const curW = bw * scale;
    const curH = bh * scale;

    if (placement === 0) {        // place on top
      nx = bx * scale;
      ny = by * scale - s;
    } else if (placement === 1) { // place on left
      nx = bx * scale - s;
      ny = by * scale - (s - bh * scale); // align bottom edges
    } else if (placement === 2) { // place on bottom
      nx = bx * scale;
      ny = (by + bh) * scale;
    } else {                      // place on right
      nx = (bx + bw) * scale;
      ny = by * scale;
    }
    squares.push({ x: nx, y: ny, size: s });

    // update bounding box (in fib units)
    if (placement === 0) { by -= fibs[i]; bh += fibs[i]; }
    else if (placement === 1) { bx -= fibs[i]; bw += fibs[i]; }
    else if (placement === 2) { bh += fibs[i]; }
    else                      { bw += fibs[i]; }
  }

  return squares;
}

// ─────────────────────────────────────────────────────────────────────────────
// Shared drawing helper: draw the grid of squares
// ─────────────────────────────────────────────────────────────────────────────
function drawSquares(ctx, squares, ox, oy, palette) {
  squares.forEach((sq, i) => {
    ctx.strokeStyle = palette[i % palette.length];
    ctx.lineWidth = 1;
    ctx.strokeRect(ox + sq.x, oy + sq.y, sq.size, sq.size);

    // faint fill
    ctx.fillStyle = palette[i % palette.length] + '18';
    ctx.fillRect(ox + sq.x + 1, oy + sq.y + 1, sq.size - 2, sq.size - 2);
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Pivot tables for the FIXED version
// For step i, the arc center is at a specific corner of squares[i].
// The spiral winds: after placing squares right, top, left, bottom, right...
// the arc for square[i] sweeps from startAngle to startAngle + π/2.
//
// Verified by tracing:
//   sq[0] (right of origin): arc center = its bottom-left  = (x,      y+size)
//   sq[1] (right of sq[0]):  arc center = its bottom-left  = (x,      y+size)
//   sq[2] (above both):      arc center = its bottom-right = (x+size, y+size)
//   sq[3] (left of all):     arc center = its top-right    = (x+size, y)
//   sq[4] (below all):       arc center = its top-left     = (x,      y)
//   then repeats mod 4 from sq[1] onward
// ─────────────────────────────────────────────────────────────────────────────
//  pivotX/Y are fractions of sq.size added to sq.x / sq.y
const PIVOT_X = [0,   0,   1,   1]; // for step%4 = 0,1,2,3
const PIVOT_Y = [1,   1,   1,   0];
// start angles (radians) for each step%4
const START_ANGLE = [Math.PI, Math.PI * 1.5, 0, Math.PI * 0.5];

// ─────────────────────────────────────────────────────────────────────────────
// BUGGY spiral renderer
// Bug: always uses sq.x, sq.y (top-left) as arc center regardless of step
// ─────────────────────────────────────────────────────────────────────────────
function drawBuggySpiral(ctx, squares, ox, oy) {
  ctx.beginPath();
  ctx.strokeStyle = '#f77e7e';
  ctx.lineWidth = 2.5;
  ctx.shadowColor = '#f77e7e';
  ctx.shadowBlur = 8;

