/* ═══════════════════════════════════════════════════════════════
   SHARED UTILITIES
═══════════════════════════════════════════════════════════════ */

const WIDGET_NAMES = ['CPU','RAM','Disk','Net','GPU','Temp','FPS','Ping','Load','Cache'];
const KB_PER_WIDGET = 48; // simulated retained size per leaked widget

let chartHistory = { buggy: [], fixed: [], labels: [] };
let actionCount = 0;

function randomMetric() {
  return (Math.random() * 99 + 1).toFixed(1);
}

function log(msg, type = 'info') {
