   SHARED INFRASTRUCTURE
═══════════════════════════════════════════════════════════════ */

/** Minimal EventEmitter — simulates a global app event bus */
class EventEmitter {
  constructor() { this._listeners = {}; }

  on(event, fn) {
    if (!this._listeners[event]) this._listeners[event] = [];
    this._listeners[event].push(fn);
  }

  off(event, fn) {
    if (!this._listeners[event]) return;
    this._listeners[event] = this._listeners[event].filter(f => f !== fn);
  }

  emit(event, data) {
    (this._listeners[event] || []).forEach(fn => fn(data));
  }

  listenerCount(event) {
    return (this._listeners[event] || []).length;
  }
}

const ICONS = ['📊','📈','🌡️','🔋','📡','🛰️','⚙️','🖥️','📦','🔬'];
const NAMES = [
  'CPU Monitor','RAM Graph','Temp Sensor','Battery','Network',
  'Satellite','Config','System','Storage','Lab Data'
];

let globalIdCounter = 0;

/* ═══════════════════════════════════════════════════════════════
   BUGGY DASHBOARD
═══════════════════════════════════════════════════════════════ */
const buggy = (() => {
  /* Shared bus — listeners accumulate here */
  const bus = new EventEmitter();

  /* Registry that is NEVER cleaned up */
  const registry = { all: [] };

  let created  = 0;
  let widgetMap = {};   // id → { el }  — never pruned

  /* Tick the bus every second (simulates app-wide events) */
  setInterval(() => bus.emit('tick', Date.now()), 1000);

  function log(msg, type = 'info') {
    const div = document.getElementById('buggy-log');
    const line = document.createElement('div');
    line.className = `log-line ${type}`;
    const ts = new Date().toLocaleTimeString();
    line.textContent = `[${ts}] ${msg}`;
    div.appendChild(line);
    div.scrollTop = div.scrollHeight;
    // Keep log from growing infinitely in the demo UI
    while (div.children.length > 60) div.removeChild(div.firstChild);
  }

  function updateStats() {
    const active    = Object.keys(widgetMap).length;
    const listeners = bus.listenerCount('tick');
    const refs      = registry.all.length;

    document.getElementById('buggy-active').textContent    = active;
    document.getElementById('buggy-created').textContent   = created;
    document.getElementById('buggy-listeners').textContent = listeners;
    document.getElementById('buggy-refs').textContent      = refs;
  }

  function addWidget() {
    const id   = ++globalIdCounter;
    const icon = ICONS[id % ICONS.length];
    const name = NAMES[id % NAMES.length];

    /* Build DOM element */
    const el = document.createElement('div');
    el.className  = 'widget';
    el.id         = `buggy-w-${id}`;
    el.dataset.count = 0;
    el.innerHTML  = `
      <span class="widget-icon">${icon}</span>
      <span class="widget-name">${name} #${id}</span>
      <span class="widget-counter" id="buggy-cnt-${id}">tick: 0</span>
      <button class="widget-remove-btn" onclick="buggy.removeWidget(${id})">✕</button>`;

    /* ❌ LEAK 1: push into registry — never removed */
    registry.all.push({ id, el, name });

    /* ❌ LEAK 2: subscribe to bus — handler captures `el`, never unsubscribed */
    const handler = () => {
      el.dataset.count = parseInt(el.dataset.count || 0) + 1;
      const cnt = document.getElementById(`buggy-cnt-${id}`);
      if (cnt) cnt.textContent = `tick: ${el.dataset.count}`;
    };
    bus.on('tick', handler);

    /* ❌ LEAK 3: interval never cleared */
    el._interval = setInterval(() => {
      // Simulates extra work keeping el alive
      el.dataset.ts = Date.now();
    }, 500);

    /* Store in widgetMap — but widgetMap entry is removed on removeWidget,
       so the map itself is fine. The leaks are the bus listener + registry. */
    widgetMap[id] = { el };

    document.getElementById('buggy-list').appendChild(el);
    created++;
    updateStats();
    log(`Widget #${id} "${name}" created. Bus listeners: ${bus.listenerCount('tick')}`, 'warn');
  }

  function removeWidget(id) {
    const entry = widgetMap[id];
    if (!entry) return;

    const el = entry.el;

    /* ❌ NOT calling bus.off() — listener stays forever */
    /* ❌ NOT calling clearInterval — timer keeps running */
    /* ❌ NOT splicing registry.all */

    el.remove();
    delete widgetMap[id];

    updateStats();
    log(
      `Widget #${id} DOM removed — but ${bus.listenerCount('tick')} listeners remain on bus! ` +
      `Registry still holds ${registry.all.length} refs.`,
      'error'
    );
  }

  function stress() {
    for (let i = 0; i < 10; i++) addWidget();
    // Remove half immediately to demonstrate accumulating leaks
    const ids = Object.keys(widgetMap);
    ids.slice(0, Math.floor(ids.length / 2)).forEach(id => removeWidget(Number(id)));
  }

  function reset() {
    Object.keys(widgetMap).forEach(id => {
      // Even in reset, we don't clean up properly (staying true to the bug)
      widgetMap[id].el.remove();
    });
    widgetMap  = {};
    created    = 0;
    // NOTE: registry.all is NOT cleared — intentional leak demonstration
    // NOTE: bus listeners are NOT removed
    document.getElementById('buggy-list').innerHTML = '';
    updateStats();
    log('Reset — but bus still has ' + bus.listenerCount('tick') + ' ghost listeners!', 'error');
  }

  updateStats();
  return { addWidget, removeWidget, stress, reset,
           getBusCount: () => bus.listenerCount('tick'),
           getRegistryCount: () => registry.all.length };
})();


/* ═══════════════════════════════════════════════════════════════
   FIXED DASHBOARD
═══════════════════════════════════════════════════════════════ */
const fixed = (() => {
  const bus = new EventEmitter();
  const registry = { all: [] };   // properly maintained

  let created   = 0;
  let widgetMap = {};

  setInterval(() => bus.emit('tick', Date.now()), 1000);

  function log(msg, type = 'info') {
    const div = document.getElementById('fixed-log');
    const line = document.createElement('div');
    line.className = `log-line ${type}`;
    const ts = new Date().toLocaleTimeString();
    line.textContent = `[${ts}] ${msg}`;
    div.appendChild(line);
    div.scrollTop = div.scrollHeight;
    while (div.children.length > 60) div.removeChild(div.firstChild);
  }

  function updateStats() {
    const active    = Object.keys(widgetMap).length;
    const listeners = bus.listenerCount('tick');
    const refs      = registry.all.length;

    document.getElementById('fixed-active').textContent    = active;
    document.getElementById('fixed-created').textContent   = created;
    document.getElementById('fixed-listeners').textContent = listeners;
    document.getElementById('fixed-refs').textContent      = refs;
  }

  function addWidget() {
    const id   = ++globalIdCounter;
    const icon = ICONS[id % ICONS.length];
    const name = NAMES[id % NAMES.length];

    const el = document.createElement('div');
    el.className  = 'widget';
    el.id         = `fixed-w-${id}`;
    el.dataset.count = 0;
    el.innerHTML  = `
      <span class="widget-icon">${icon}</span>
      <span class="widget-name">${name} #${id}</span>
      <span class="widget-counter" id="fixed-cnt-${id}">tick: 0</span>
      <button class="widget-remove-btn" onclick="fixed.removeWidget(${id})">✕</button>`;

    /* ✅ Push into registry with index tracking */
    const registryIdx = registry.all.length;
    registry.all.push({ id, el, name });

    /* ✅ Store handler reference so we can remove it later */
    const handler = () => {
      el.dataset.count = parseInt(el.dataset.count || 0) + 1;
      const cnt = document.getElementById(`fixed-cnt-${id}`);
      if (cnt) cnt.textContent = `tick: ${el.dataset.count}`;
    };
    bus.on('tick', handler);

    /* ✅ Store interval ID for cleanup */
    const intervalId = setInterval(() => {
      el.dataset.ts = Date.now();
    }, 500);

    /* ✅ Store all cleanup data on the widget entry */
    widgetMap[id] = { el, handler, intervalId, registryIdx };

    document.getElementById('fixed-list').appendChild(el);
    created++;
    updateStats();
    log(`Widget #${id} "${name}" created. Bus listeners: ${bus.listenerCount('tick')}`, 'ok');
  }

  function removeWidget(id) {
    const entry = widgetMap[id];
    if (!entry) return;

    const { el, handler, intervalId } = entry;

    /* ✅ Unsubscribe from bus — handler + closure can now be GC'd */
    bus.off('tick', handler);

    /* ✅ Clear interval — timer stops, closure released */
    clearInterval(intervalId);

    /* ✅ Remove from registry — registry no longer holds reference */
    registry.all = registry.all.filter(w => w.id !== id);

    /* ✅ Remove DOM element */
    el.remove();
    delete widgetMap[id];

    updateStats();
    log(
      `Widget #${id} fully cleaned up. Bus listeners: ${bus.listenerCount('tick')}. ` +
      `Registry size: ${registry.all.length}.`,
      'ok'
    );
  }

  function stress() {
    for (let i = 0; i < 10; i++) addWidget();
    const ids = Object.keys(widgetMap);
    ids.slice(0, Math.floor(ids.length / 2)).forEach(id => removeWidget(Number(id)));
  }

  function reset() {
    Object.keys(widgetMap).forEach(id => removeWidget(Number(id)));
    created = 0;
    document.getElementById('fixed-list').innerHTML = '';
    updateStats();
    log('Full reset — all listeners removed, registry empty, intervals cleared.', 'ok');
  }

  updateStats();
  return { addWidget, removeWidget, stress, reset,
           getBusCount: () => bus.listenerCount('tick'),
           getRegistryCount: () => registry.all.length };
})();


/* ═══════════════════════════════════════════════════════════════
   MEMORY CHART
   Simulates memory pressure based on leaked listener/ref counts.
   Not real heap data — illustrates the growth pattern.
═══════════════════════════════════════════════════════════════ */
(() => {
  const canvas  = document.getElementById('memChart');
  const ctx     = canvas.getContext('2d');
  const history = { buggy: [], fixed: [] };
  const MAX_PTS = 80;

  function resize() {
    canvas.width  = canvas.offsetWidth  * devicePixelRatio;
    canvas.height = canvas.offsetHeight * devicePixelRatio;
  }
  resize();
  window.addEventListener('resize', resize);

  function sample() {
    // Simulate memory in arbitrary units:
    // Buggy  = base + (listeners * 12) + (registryRefs * 8) + noise
    // Fixed  = base + (active widgets * 4) + noise
    const noise = () => (Math.random() - 0.5) * 4;

    const buggyMem = 20
      + buggy.getBusCount()    * 12
      + buggy.getRegistryCount() * 8
      + noise();

    const fixedMem = 20
      + fixed.getBusCount()    * 4
      + noise();

    history.buggy.push(Math.max(0, buggyMem));
    history.fixed.push(Math.max(0, fixedMem));

    if (history.buggy.length > MAX_PTS) history.buggy.shift();
    if (history.fixed.length > MAX_PTS) history.fixed.shift();
  }

  function draw() {
    const W = canvas.width;
    const H = canvas.height;
    const dpr = devicePixelRatio;

    ctx.clearRect(0, 0, W, H);

    // Background grid
    ctx.strokeStyle = '#1f2937';
    ctx.lineWidth   = 1 * dpr;
    for (let y = 0; y <= 4; y++) {
      const yy = (y / 4) * H;
      ctx.beginPath();
      ctx.moveTo(0, yy);
      ctx.lineTo(W, yy);
      ctx.stroke();
    }

    const allVals = [...history.buggy, ...history.fixed];
    const maxVal  = Math.max(...allVals, 60);

    function plotLine(data, color) {
      if (data.length < 2) return;
      ctx.beginPath();
      ctx.strokeStyle = color;
      ctx.lineWidth   = 2 * dpr;
      ctx.lineJoin    = 'round';
      data.forEach((v, i) => {
        const x = (i / (MAX_PTS - 1)) * W;
        const y = H - (v / maxVal) * H * 0.9 - H * 0.05;
        i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
      });
      ctx.stroke();

      // Fill under line
      ctx.lineTo((data.length - 1) / (MAX_PTS - 1) * W, H);
      ctx.lineTo(0, H);
      ctx.closePath();
      ctx.fillStyle = color + '22';
      ctx.fill();
    }

    plotLine(history.buggy, '#f87171');
    plotLine(history.fixed, '#4ade80');

    // Y-axis labels
    ctx.fillStyle  = '#4b5563';
    ctx.font       = `${10 * dpr}px sans-serif`;
    ctx.textAlign  = 'left';
    ctx.fillText(`${Math.round(maxVal)} units`, 4 * dpr, 14 * dpr);
    ctx.fillText('0', 4 * dpr, H - 4 * dpr);
  }

  setInterval(() => { sample(); draw(); }, 1000);
  sample(); draw();
})();
</script>
</body>
</html>
