<script>
// ─── Catalog (prices in CENTS — the only sane representation) ───────────────
const CATALOG = [
  { id: 1, name: 'Wireless Mouse',    centsPrice: 499 },  // $4.99
  { id: 2, name: 'USB-C Cable',       centsPrice: 399 },  // $3.99
  { id: 3, name: 'Screen Wipe Kit',   centsPrice: 299 },  // $2.99
  { id: 4, name: 'Cable Organizer',   centsPrice: 149 },  // $1.49
  { id: 5, name: 'Webcam Cover',      centsPrice: 199 },  // $1.99
];

// Quantities — shared state, both panels read the same qtys
const qtys = { 1: 1, 2: 1, 3: 1, 4: 1, 5: 1 };

// ─── Broken helpers (float arithmetic) ──────────────────────────────────────
function brokenPrice(item) {
  // Intentionally using float division — this is the mistake
  return item.centsPrice / 100;
}

function brokenLineTotal(item) {
  return brokenPrice(item) * qtys[item.id];   // float × int = float chaos
}

function brokenCartTotal() {
  return CATALOG.reduce((sum, item) => sum + brokenLineTotal(item), 0);
}

// ─── Fixed helpers (integer cents throughout) ────────────────────────────────
function fixedLineTotal(item) {
  return item.centsPrice * qtys[item.id];     // int × int = exact
}

function fixedCartTotal() {
  return CATALOG.reduce((sum, item) => sum + fixedLineTotal(item), 0);
}

function centsToDisplay(cents) {
  return '$' + (cents / 100).toFixed(2);      // divide ONLY for display
}

// ─── Render cart items (shared layout, different price display) ──────────────
function renderItems(containerId, priceGetter, lineTotalGetter, isFixed) {
  const el = document.getElementById(containerId);
  el.innerHTML = CATALOG.map(item => {
    const lineRaw    = lineTotalGetter(item);
    const lineDisplay = isFixed
      ? centsToDisplay(lineRaw)
      : '$' + lineRaw.toFixed(2);
    const unitDisplay = isFixed
      ? centsToDisplay(item.centsPrice)
      : '$' + brokenPrice(item).toFixed(2);

    return `
      <div class="cart-item">
        <div>
          <div class="item-name">${item.name}</div>
          <div class="item-price">${unitDisplay} each</div>
        </div>
        <div class="item-qty">
          <button class="qty-btn" onclick="changeQty(${item.id}, -1)">−</button>
          <span class="qty-display">${qtys[item.id]}</span>
          <button class="qty-btn" onclick="changeQty(${item.id}, +1)">+</button>
        </div>
        <div style="min-width:60px;text-align:right;font-size:0.85em">${lineDisplay}</div>
      </div>`;
  }).join('');
}

// ─── Render broken totals ────────────────────────────────────────────────────
function renderBrokenTotals() {
  const el     = document.getElementById('broken-totals');
  const total  = brokenCartTotal();
  const tax    = total * 0.08;
  const grand  = total + tax;

  // Show the raw float values — the smoking gun
  const rows = CATALOG.map(item => {
    const raw = brokenLineTotal(item);
    const isExact = raw.toString() === (Math.round(raw * 100) / 100).toString();
    return `
      <div class="totals-row">
        <span>${item.name} ×${qtys[item.id]}</span>
        <span>
          $${raw.toFixed(2)}
          ${!isExact ? `<span class="raw-value">[raw: ${raw}]</span>` : ''}
        </span>
      </div>`;
  }).join('');

  el.innerHTML = rows + `
    <div class="totals-row highlight">
      <span>Subtotal</span>
      <span>
        $${total.toFixed(2)}
        <span class="raw-value">[raw: ${total}]</span>
      </span>
    </div>
    <div class="totals-row">
      <span>Tax (8%)</span>
