═══════════════════════════════════════════ */
function removeItem(mode, index) {
  state[mode].splice(index, 1);
  renderCart(mode);
}

/* ═══════════════════════════════════════════
   CLEAR CART
═══════════════════════════════════════════ */
function clearCart(mode) {
  state[mode] = [];
  renderCart(mode);
}

/* ═══════════════════════════════════════════
   RENDER CART
═══════════════════════════════════════════ */
function renderCart(mode) {
  const items    = state[mode];
  const listEl   = document.getElementById(`${mode}-cart`);

  listEl.innerHTML = '';

  if (items.length === 0) {
    listEl.innerHTML =
      '<li class="empty-msg">Cart is empty — add some items above</li>';
    resetTotals(mode);
    return;
  }

  items.forEach((item, i) => {
    const li = document.createElement('li');
    li.className = 'cart-item';
    const priceStr = mode === 'broken'
      ? `$${item.dollars.toFixed(2)}`
      : `$${(item.cents / 100).toFixed(2)}`;
    li.innerHTML = `
      <span>${item.name}</span>
      <span class="item-price">${priceStr}</span>
      <button class="remove-btn" title="Remove" onclick="removeItem('${mode}',${i})">✕</button>
    `;
    listEl.appendChild(li);
  });

  if (mode === 'broken') renderBrokenTotals(items);
  else                    renderFixedTotals(items);
}

/* ═══════════════════════════════════════════
   BROKEN TOTALS  (raw float addition)
═══════════════════════════════════════════ */
function renderBrokenTotals(items) {
  // Naive float sum — exactly what the developer would write
  let total = 0;
  items.forEach(item => { total += item.dollars; });

  const rawEl     = document.getElementById('broken-raw');
  const displayEl = document.getElementById('broken-display');
  const exactEl   = document.getElementById('broken-exact');

  rawEl.textContent     = total;                          // full precision
  displayEl.textContent = `$${total.toFixed(2)}`;        // rounded display
  exactEl.textContent   = total.toPrecision(20);         // expose the ugliness

  // Colour the exact value red if it's not a clean decimal
  const isClean = Number(total.toPrecision(10)) === Math.round(total * 100) / 100;
  exactEl.className = isClean ? 'raw-value ok' : 'raw-value';

  renderBrokenComparisons(total);
  renderBrokenDiscount(total);
}

/* ═══════════════════════════════════════════
   BROKEN COMPARISON TESTS
═══════════════════════════════════════════ */
function renderBrokenComparisons(total) {
  const el = document.getElementById('broken-comparison');

  // Build a set of expected values to test against
  const rounded2 = Math.round(total * 100) / 100;
  const tests = [
    {
      expr: `total === ${rounded2}`,
      result: total === rounded2,
      explanation: 'Exact match test'
    },
    {
      expr: `total === ${total.toFixed(2)}`,
      result: total === parseFloat(total.toFixed(2)),
      explanation: 'toFixed round-trip'
    },
    {
      expr: `total >= 10.00  (free shipping)`,
      result: total >= 10.00,
      explanation: 'Threshold check'
    },
    {
      expr: `total === 10.00`,
      result: total === 10.00,
      explanation: 'Exact threshold'
    },
  ];

  let html = '<h3>🔍 === Comparison Tests</h3>';
  tests.forEach(t => {
    const cls    = t.result ? 'pass' : 'fail';
    const symbol = t.result ? '✓ true' : '✗ false';
    html += `
      <div class="test-row">
        <span class="expression">${t.expr}</span>
        <span>
          <span class="result-pill ${cls}">${symbol}</span>
          <span style="color:#64748b;font-size:0.78rem;margin-left:6px">${t.explanation}</span>
        </span>
      </div>`;
  });

  el.innerHTML = html;
}

/* ═══════════════════════════════════════════
   BROKEN DISCOUNT (shows === failure)
═══════════════════════════════════════════ */
function renderBrokenDiscount(total) {
  const el = document.getElementById('broken-discount');

  // Try to detect a "magic" total that should be a round number but isn't
  const expected = Math.round(total * 100) / 100;
  const passes   = total === expected;

  el.style.display = 'block';
  if (passes) {
    el.className = 'discount-warn success';
    el.textContent =
      `✓ This total happens to compare equal — but add more items and it will break!`;
  } else {
    el.className = 'discount-warn fail';
    el.textContent =
      `✗ DISCOUNT BUG: total (${total.toPrecision(17)}) !== ${expected} ` +
      `— discount logic using === would silently FAIL here!`;
  }
}

/* ═══════════════════════════════════════════
   FIXED TOTALS  (integer cents)
═══════════════════════════════════════════ */
function renderFixedTotals(items) {
  // All arithmetic in whole-number cents — always exact
  let totalCents = 0;
  items.forEach(item => { totalCents += item.cents; });

  const centsEl   = document.getElementById('fixed-cents');
  const displayEl = document.getElementById('fixed-display');
  const exactEl   = document.getElementById('fixed-exact');

  centsEl.textContent   = `${totalCents}¢`;
  displayEl.textContent = `$${(totalCents / 100).toFixed(2)}`;
  exactEl.textContent   = `${totalCents} (exact integer)`;

  renderFixedComparisons(totalCents);
  renderFixedDiscount(totalCents);
}

/* ═══════════════════════════════════════════
   FIXED COMPARISON TESTS
═══════════════════════════════════════════ */
function renderFixedComparisons(totalCents) {
  const el = document.getElementById('fixed-comparison');

  const tests = [
    {
      expr: `totalCents === ${totalCents}`,
      result: totalCents === totalCents,
      explanation: 'Exact integer match'
    },
    {
      expr: `totalCents >= 1000  (free shipping $10)`,
      result: totalCents >= 1000,
      explanation: 'Threshold check'
    },
    {
      expr: `totalCents === 1000`,
      result: totalCents === 1000,
      explanation: 'Exact $10.00 check'
    },
    {
      expr: `totalCents % 100 === 0  (whole dollars?)`,
      result: totalCents % 100 === 0,
      explanation: 'Divisibility check'
    },
  ];

  let html = '<h3>🔍 Comparison Tests (cents)</h3>';
  tests.forEach(t => {
    const cls    = t.result ? 'pass' : 'fail';
    const symbol = t.result ? '✓ true' : '✗ false';
    html += `
      <div class="test-row">
        <span class="expression">${t.expr}</span>
        <span>
          <span class="result-pill ${cls}">${symbol}</span>
          <span style="color:#64748b;font-size:0.78rem;margin-left:6px">${t.explanation}</span>
        </span>
      </div>`;
  });

  el.innerHTML = html;
}

/* ═══════════════════════════════════════════
   FIXED DISCOUNT
═══════════════════════════════════════════ */
function renderFixedDiscount(totalCents) {
  const el = document.getElementById('fixed-discount');
  el.style.display = 'block';

  if (totalCents >= 1000) {
    el.className = 'discount-warn success';
    el.textContent =
      `✓ FREE SHIPPING unlocked! totalCents (${totalCents}) >= 1000 — always exact.`;
  } else {
    const remaining = 1000 - totalCents;
    el.className = 'discount-warn fail';
    el.textContent =
      `Add $${(remaining / 100).toFixed(2)} more for free shipping ` +
      `(${remaining}¢ remaining) — comparison is always reliable.`;
  }
}

/* ═══════════════════════════════════════════
   RESET TOTALS (empty cart)
═══════════════════════════════════════════ */
function resetTotals(mode) {
  if (mode === 'broken') {
    document.getElementById('broken-raw').textContent     = '—';
    document.getElementById('broken-display').textContent = '$0.00';
    document.getElementById('broken-exact').textContent   = '—';
    document.getElementById('broken-comparison').innerHTML =
      '<h3>🔍 === Comparison Tests</h3>' +
      '<p style="color:#475569;font-size:0.82rem;font-style:italic">Add items to see comparison tests</p>';
    document.getElementById('broken-discount').style.display = 'none';
  } else {
    document.getElementById('fixed-cents').textContent   = '—';
    document.getElementById('fixed-display').textContent = '$0.00';
    document.getElementById('fixed-exact').textContent   = '—';
    document.getElementById('fixed-comparison').innerHTML =
      '<h3>🔍 Comparison Tests (cents)</h3>' +
      '<p style="color:#475569;font-size:0.82rem;font-style:italic">Add items to see comparison tests</p>';
    document.getElementById('fixed-discount').style.display = 'none';
  }
}

/* ═══════════════════════════════════════════
   LIVE PROOF PANEL
   Evaluate classic float gotchas right here
═══════════════════════════════════════════ */
function renderProof() {
  const proofs = [
    { expr: '0.1 + 0.2',           expected: 0.3   },
    { expr: '0.1 + 0.2 === 0.3',   expected: true  },
    { expr: '4.99 + 2.50 + 1.99',  expected: 9.48  },
    { expr: '(4.99+2.50+1.99) === 9.48', expected: true },
    { expr: '1.005.toFixed(2)',     expected: '"1.01"' },
    { expr: '0.3 - 0.1',           expected: 0.2   },
    { expr: '0.7 + 0.1',           expected: 0.8   },
    { expr: '0.1 * 3',             expected: 0.3   },
    { expr: '1.1 + 2.2',           expected: 3.3   },
    { expr: '0.2 + 0.4',           expected: 0.6   },
    { expr: '0.1 + 0.7',           expected: 0.8   },
    { expr: '3 * 0.1',             expected: 0.3   },
  ];

  // Safe evaluator
  function safeEval(expr) {
    try {
      // We only evaluate simple arithmetic expressions — safe here
      // eslint-disable-next-line no-new-func
      return Function(`"use strict"; return (${expr})`)();
    } catch(e) {
      return 'ERROR';
    }
  }

  const grid = document.getElementById('proof-grid');
  grid.innerHTML = '';

  proofs.forEach(p => {
    const actual   = safeEval(p.expr);
    const expected = p.expected;

    // Determine if the result matches what a naive developer would expect
    let matches;
    if (typeof expected === 'boolean') {
      matches = actual === expected;
    } else if (typeof expected === 'string') {
      matches = String(actual) === expected.replace(/"/g, '');
    } else {
      matches = actual === expected;
    }

    const actualStr = typeof actual === 'string'
      ? `"${actual}"`
      : String(actual);

    const div = document.createElement('div');
    div.className = 'proof-item';
    div.innerHTML = `
      <div class="expr">${p.expr}</div>
      <div class="actual ${matches ? 'right' : 'wrong'}">
        → ${actualStr}
        ${matches ? '✓ (as expected)' : `✗ expected: ${expected}`}
      </div>
    `;
    grid.appendChild(div);
  });
}

/* ═══════════════════════════════════════════
   INIT
═══════════════════════════════════════════ */
renderProducts();
renderProof();
</script>
</body>
</html>
