// BROKEN: naive float arithmetic
// ═══════════════════════════════════════════════════════════════════════════
function brokenCart() {
  const tbody = document.getElementById('broken-items');
  let subtotal = 0;

  CART_ITEMS.forEach(item => {
    const lineTotal = item.qty * item.unitPrice; // float multiplication
    subtotal += lineTotal;                        // float accumulation
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td>${item.name}</td>
      <td>${item.qty}</td>
      <td class="price">$${item.unitPrice}</td>
      <td class="price">$${lineTotal}</td>`;
    tbody.appendChild(tr);
  });

  const tax   = subtotal * TAX_RATE;
  const total = subtotal + tax;

  document.getElementById('broken-subtotal').textContent = '$' + subtotal;
  document.getElementById('broken-tax').textContent      = '$' + tax;
  document.getElementById('broken-total').textContent    = '$' + total;

  // Comparisons using ===
  const expectedSubtotal = 14.99*2 + 8.49*3 + 6.99 + 3.49*4 + 2.99;
  const recomputedTotal  = expectedSubtotal + expectedSubtotal * TAX_RATE;

  const results = document.getElementById('broken-results');
  results.innerHTML = `
<span class="dim">// Raw float values (20 decimal places):</span>
subtotal.toFixed(20) =
  <span class="fail">${subtotal.toFixed(20)}</span>
tax.toFixed(20) =
  <span class="fail">${tax.toFixed(20)}</span>
total.toFixed(20) =
  <span class="fail">${total.toFixed(20)}</span>

<span class="dim">// Equality checks with ===:</span>
subtotal === ${expectedSubtotal.toFixed(2)} → <span class="${subtotal === expectedSubtotal ? 'pass'>true' : 'fail">false'}</span>
total === recomputedTotal → <span class="${total === recomputedTotal ? 'pass">true' : 'fail">false'}</span>
0.1 + 0.2 === 0.3 → <span class="fail">false</span>
1.005.toFixed(2) === "1.01" → <span class="fail">${(1.005).toFixed(2) === "1.01" ? 'true' : 'false'}</span>
`;

  const explosion = document.getElementById('broken-explosion');
  explosion.innerHTML = `
<span class="fail">💥 FAILURES DETECTED:</span>
• Subtotal displayed: <span class="warn">$${subtotal}</span>
  → Should be: <span class="pass">$${(14.99*2 + 8.49*3 + 6.99 + 3.49*4 + 2.99).toFixed(2)}</span>
• Tax displayed: <span class="warn">$${tax}</span>
  → Should be: <span class="pass">$${((14.99*2 + 8.49*3 + 6.99 + 3.49*4 + 2.99)*TAX_RATE).toFixed(2)}</span>
• Total displayed: <span class="warn">$${total}</span>
  → Should be: <span class="pass">$${((14.99*2 + 8.49*3 + 6.99 + 3.49*4 + 2.99)*(1+TAX_RATE)).toFixed(2)}</span>
• Discount threshold check: <span class="fail">BROKEN</span> (=== never fires correctly)
• Audit log would record wrong amounts
• Customer overcharged or undercharged
`;
}

// ═══════════════════════════════════════════════════════════════════════════
// FIXED: integer cents arithmetic
// ═══════════════════════════════════════════════════════════════════════════
function toCents(dollarString) {
  // Parse safely: avoid parseFloat errors by splitting on decimal point
  const str = String(dollarString);
  const parts = str.split('.');
  const dollars = parseInt(parts[0], 10);
  const cents   = parts[1] ? parseInt(parts[1].padEnd(2, '0').slice(0, 2), 10) : 0;
  return dollars * 100 + cents;
}

function formatCents(cents) {
  const sign    = cents < 0 ? '-' : '';
  const abs     = Math.abs(cents);
  const dollars = Math.floor(abs / 100);
  const c       = abs % 100;
  return sign + '$' + dollars + '.' + String(c).padStart(2, '0');
}

// Tax in basis points (1 basis point = 0.01%) to keep integer math
// 8.875% = 8875 basis points
const TAX_BP = 8875;

function fixedCart() {
  const tbody = document.getElementById('fixed-items');
  let subtotalCents = 0;

  CART_ITEMS.forEach(item => {
    const unitCents  = toCents(item.unitPrice);  // exact integer
    const lineCents  = item.qty * unitCents;      // exact integer multiplication
    subtotalCents   += lineCents;                 // exact integer addition
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td>${item.name}</td>
      <td>${item.qty}</td>
      <td class="price">${formatCents(unitCents)}</td>
      <td class="price">${formatCents(lineCents)}</td>`;
    tbody.appendChild(tr);
  });

  // Tax: multiply then round ONCE — never round intermediate values
  const taxCents   = Math.round(subtotalCents * TAX_BP / 1000000);
  const totalCents = subtotalCents + taxCents;

  document.getElementById('fixed-subtotal').textContent = formatCents(subtotalCents);
  document.getElementById('fixed-tax').textContent      = formatCents(taxCents);
  document.getElementById('fixed-total').textContent    = formatCents(totalCents);

  // Comparisons using === on integers — always correct
  const expectedSubtotalCents = toCents('14.99')*2 + toCents('8.49')*3 +
                                 toCents('6.99')   + toCents('3.49')*4 +
                                 toCents('2.99');
  const expectedTaxCents      = Math.round(expectedSubtotalCents * TAX_BP / 1000000);
  const expectedTotalCents    = expectedSubtotalCents + expectedTaxCents;

  const results = document.getElementById('fixed-results');
  results.innerHTML = `
<span class="dim">// All values are exact integers (cents):</span>
subtotalCents = <span class="pass">${subtotalCents}</span>  <span class="dim">// ${formatCents(subtotalCents)}</span>
taxCents      = <span class="pass">${taxCents}</span>   <span class="dim">// ${formatCents(taxCents)}</span>
totalCents    = <span class="pass">${totalCents}</span>  <span class="dim">// ${formatCents(totalCents)}</span>

<span class="dim">// Equality checks with === on integers:</span>
subtotalCents === ${expectedSubtotalCents} → <span class="${subtotalCents === expectedSubtotalCents ? 'pass">true ✅' : 'fail">false ❌'}</span>
totalCents === ${expectedTotalCents} → <span class="${totalCents === expectedTotalCents ? 'pass">true ✅' : 'fail">false ❌'}</span>
toCents('0.10') + toCents('0.20') === toCents('0.30') → <span class="${toCents('0.10')+toCents('0.20') === toCents('0.30') ? 'pass">true ✅' : 'fail">false ❌'}</span>
<span class="dim">// No rounding surprises, no phantom decimals, no silent failures</span>
`;
}

// ═══════════════════════════════════════════════════════════════════════════
// HORROR TABLE
// ═══════════════════════════════════════════════════════════════════════════
function buildHorrorTable() {
  const horrors = [
    { expr: '0.1 + 0.2',                  expected: '0.3',     actual: 0.1 + 0.2 },
    { expr: '0.1 + 0.2 === 0.3',          expected: 'true',    actual: 0.1 + 0.2 === 0.3 },
    { expr: '4.99 + 4.99',                expected: '9.98',    actual: 4.99 + 4.99 },
    { expr: '4.99 + 4.99 === 9.98',       expected: 'true',    actual: 4.99 + 4.99 === 9.98 },
    { expr: '1.005.toFixed(2)',            expected: '"1.01"',  actual: (1.005).toFixed(2) },
    { expr: '1.005.toFixed(2) === "1.01"',expected: 'true',    actual: (1.005).toFixed(2) === "1.01" },
    { expr: '0.3 - 0.1',                  expected: '0.2',     actual: 0.3 - 0.1 },
    { expr: '0.3 - 0.1 === 0.2',          expected: 'true',    actual: 0.3 - 0.1 === 0.2 },
    { expr: '1.1 + 2.2',                  expected: '3.3',     actual: 1.1 + 2.2 },
    { expr: '1.1 + 2.2 === 3.3',          expected: 'true',    actual: 1.1 + 2.2 === 3.3 },
    { expr: '8.99 * 3',                   expected: '26.97',   actual: 8.99 * 3 },
    { expr: '8.99 * 3 === 26.97',         expected: 'true',    actual: 8.99 * 3 === 26.97 },
    { expr: '0.1 * 0.2',                  expected: '0.02',    actual: 0.1 * 0.2 },
    { expr: '19.99 + 0.01',               expected: '20',      actual: 19.99 + 0.01 },
    { expr: '19.99 + 0.01 === 20',        expected: 'true',    actual: 19.99 + 0.01 === 20 },
    { expr: '(0.1+0.2+0.3) === 0.6',      expected: 'true',    actual: (0.1+0.2+0.3) === 0.6 },
    { expr: 'Math.round(1.255*100)/100',  expected: '1.26',    actual: Math.round(1.255*100)/100 },
    { expr: '6.99 - 0.01',               expected: '6.98',    actual: 6.99 - 0.01 },
    { expr: '6.99 - 0.01 === 6.98',      expected: 'true',    actual: 6.99 - 0.01 === 6.98 },
    { expr: '9.99 * 100',                 expected: '999',     actual: 9.99 * 100 },
    { expr: '9.99 * 100 === 999',         expected: 'true',    actual: 9.99 * 100 === 999 },
  ];

  const tbody = document.getElementById('horror-tbody');
  horrors.forEach(h => {
    const actualStr = String(h.actual);
    const isCorrect = actualStr === h.expected || h.actual == h.expected;
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td><code style="color:#e0e0e0">${h.expr}</code></td>
      <td class="expected">${h.expected}</td>
      <td class="actual">${actualStr}</td>
      <td class="verdict ${isCorrect ? 'pass' : 'fail'}">${isCorrect ? '✅ OK' : '❌ WRONG'}</td>`;
    tbody.appendChild(tr);
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// IEEE 754 BIT DISPLAY for 4.99
// ═══════════════════════════════════════════════════════════════════════════
function buildBitDisplay() {
  // Get 64-bit representation of 4.99
  const buf   = new ArrayBuffer(8);
  const view  = new DataView(buf);
  view.setFloat64(0, 4.99, false); // big-endian
  let bits = '';
  for (let i = 0; i < 8; i++) {
    bits += view.getUint8(i).toString(2).padStart(8, '0');
  }

  const container = document.getElementById('bit-display');
  const sign     = bits[0];
  const exponent = bits.slice(1, 12);
  const mantissa = bits.slice(12);

  // Sign
  const signGroup = document.createElement('div');
  signGroup.className = 'bit-group';
  signGroup.innerHTML = `<div class="bit-label">S</div><div class="bits"><div class="bit bit-sign">${sign}</div></div>`;
  container.appendChild(signGroup);

  // Exponent — split into chunks for readability
  for (let i = 0; i < 11; i += 4) {
    const chunk = exponent.slice(i, i+4);
    const g = document.createElement('div');
    g.className = 'bit-group';
    g.innerHTML = `<div class="bit-label">E${i}</div><div class="bits">${
      chunk.split('').map(b => `<div class="bit bit-exp">${b}</div>`).join('')
    }</div>`;
    container.appendChild(g);
  }

  // Mantissa — split into chunks
  for (let i = 0; i < 52; i += 4) {
    const chunk = mantissa.slice(i, i+4);
    const g = document.createElement('div');
    g.className = 'bit-group';
    g.innerHTML = `<div class="bit-label">M${i}</div><div class="bits">${
      chunk.split('').map((b,j) => `<div class="bit bit-mantissa${(i+j)%2===0?'':' b1'}">${b}</div>`).join('')
    }</div>`;
    container.appendChild(g);
  }

  const codeEl = document.getElementById('ieee-code');
  const expVal = parseInt(exponent, 2) - 1023;
  codeEl.innerHTML =
`<span class="c-comment">// 4.99 in IEEE 754 double precision:</span>
Bits:     <span style="color:#ff4757">${sign}</span> <span style="color:#ffa502">${exponent}</span> <span style="color:#7474ff">${mantissa.slice(0,26)}</span><span style="color:#5352ed">${mantissa.slice(26)}</span>
Sign:     ${sign === '0' ? 'positive' : 'negative'}
Exponent: ${exponent} (binary) = ${parseInt(exponent,2)} - 1023 = <span style="color:#ffa502">${expVal}</span>
Value:    (-1)^${sign} × 2^${expVal} × 1.${mantissa}₂

<span class="c-comment">// What JavaScript actually stores for 4.99:</span>
(4.99).toFixed(20) = <span class="c-bad">${(4.99).toFixed(20)}</span>
<span class="c-comment">//                      ↑ not 4.99000000000000000000</span>
<span class="c-comment">//  The error is ~4.4 × 10⁻¹⁶ per number.</span>
<span class="c-comment">//  Multiply by 10,000 transactions = $0.0044 unexplained per day.</span>
<span class="c-comment">//  Multiply by 365 days = $1.61 per year per price point.</span>
<span class="c-comment">//  Now multiply by thousands of SKUs. Enjoy your audit.</span>`;
}

