    <!-- EXPLANATION PANEL -->
    <div class="explanation-panel">
        <div class="explanation-title">
            🎓 Why Float Equality Fails for Financial Calculations
        </div>

        <div class="explanation-grid">
            <div class="explanation-card">
                <div class="explanation-card-title">
                    <span class="step-counter">1</span>IEEE 754 Binary Representation
                </div>
                <p>
                    JavaScript uses 64-bit IEEE 754 double-precision floats.
                    Most decimal fractions <strong>cannot be represented exactly</strong>
                    in binary — just like 1/3 cannot be written exactly in decimal.
                    The number 0.1 in binary is actually
                    0.1000000000000000055511151231257827021181583404541015625.
                    This is baked into the hardware.
                </p>
            </div>
            <div class="explanation-card">
                <div class="explanation-card-title">
                    <span class="step-counter">2</span>Errors Accumulate
                </div>
                <p>
                    Each arithmetic operation can introduce a tiny rounding error.
                    Add enough prices together and those errors compound.
                    <strong>$4.99 + $3.99 + $1.01</strong> might give you
                    <strong>9.989999999999999</strong> instead of
                    <strong>9.99</strong>. Using === to compare this to 9.99
                    returns <strong>false</strong> even though mathematically
                    it should be true.
                </p>
            </div>
            <div class="explanation-card">
                <div class="explanation-card-title">
                    <span class="step-counter">3</span>Real Financial Consequences
                </div>
                <p>
                    Discount codes that never apply. Tax calculations off by a penny.
                    Totals that don't match receipts. Refund amounts that are wrong.
                    Inventory reconciliation failures. In high-volume systems,
                    even sub-cent errors multiply into significant losses.
                    Banks and payment processors have strict requirements
                    around exact decimal arithmetic.
                </p>
            </div>
        </div>

        <div class="tab-container">
            <div class="tabs">
                <button class="tab active" onclick="showTab('tab-problem')">The Problem</button>
                <button class="tab" onclick="showTab('tab-solution')">The Solution</button>
                <button class="tab" onclick="showTab('tab-ieee')">IEEE 754 Bits</button>
                <button class="tab" onclick="showTab('tab-live')">Live Calculator</button>
            </div>

            <div class="tab-content active" id="tab-problem">
                <div class="code-block">
<span class="code-comment">// ❌ BROKEN: Raw float arithmetic — DO NOT USE FOR MONEY</span>

<span class="code-keyword">const</span> price1 = <span class="code-number">4.99</span>;   <span class="code-comment">// stored as 4.990000000000000213162820728...</span>
<span class="code-keyword">const</span> price2 = <span class="code-number">3.99</span>;   <span class="code-comment">// stored as 3.990000000000000213162820728...</span>
<span class="code-keyword">const</span> price3 = <span class="code-number">1.01</span>;   <span class="code-comment">// stored as 1.010000000000000008881784197...</span>

<span class="code-keyword">const</span> total = price1 + price2 + price3;
<span class="code-function">console</span>.<span class="code-function">log</span>(total);           <span class="code-comment">// 9.989999999999999 ← NOT 9.99!</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(total === <span class="code-number">9.99</span>);  <span class="code-bad">// false ← discount code never applies!</span>

<span class="code-comment">// Classic JavaScript float traps:</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.1</span> + <span class="code-number">0.2</span>);           <span class="code-comment">// 0.30000000000000004</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.1</span> + <span class="code-number">0.2</span> === <span class="code-number">0.3</span>); <span class="code-bad">// false</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">1.005</span>.<span class="code-function">toFixed</span>(<span class="code-number">2</span>));    <span class="code-comment">// "1.00" ← rounds wrong! (should be 1.01)</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.3</span> - <span class="code-number">0.2</span> === <span class="code-number">0.1</span>); <span class="code-bad">// false</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.7</span> + <span class="code-number">0.1</span> === <span class="code-number">0.8</span>); <span class="code-bad">// false</span>

<span class="code-comment">// Tax calculation nightmare:</span>
<span class="code-keyword">const</span> subtotal = <span class="code-number">19.99</span>;
<span class="code-keyword">const</span> taxRate  = <span class="code-number">0.085</span>;
<span class="code-keyword">const</span> tax      = subtotal * taxRate;
<span class="code-function">console</span>.<span class="code-function">log</span>(tax);  <span class="code-comment">// 1.6991499999999998 ← not 1.70</span>
                </div>
            </div>

            <div class="tab-content" id="tab-solution">
                <div class="code-block">
<span class="code-comment">// ✅ FIXED: Integer cents arithmetic — always use for money</span>

<span class="code-comment">// Rule: Store ALL prices as integer cents. Never as dollars.</span>
<span class="code-keyword">const</span> toCents  = (<span class="code-keyword">dollars</span>) => <span class="code-function">Math</span>.<span class="code-function">round</span>(dollars * <span class="code-number">100</span>);
<span class="code-keyword">const</span> toDollars = (<span class="code-keyword">cents</span>)   => (cents / <span class="code-number">100</span>).<span class="code-function">toFixed</span>(<span class="code-number">2</span>);

<span class="code-keyword">const</span> price1 = <span class="code-function">toCents</span>(<span class="code-number">4.99</span>);  <span class="code-comment">// 499  ← exact integer!</span>
<span class="code-keyword">const</span> price2 = <span class="code-function">toCents</span>(<span class="code-number">3.99</span>);  <span class="code-comment">// 399  ← exact integer!</span>
<span class="code-keyword">const</span> price3 = <span class="code-function">toCents</span>(<span class="code-number">1.01</span>);  <span class="code-comment">// 101  ← exact integer!</span>

<span class="code-keyword">const</span> totalCents = price1 + price2 + price3;  <span class="code-comment">// 999 ← exact!</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(totalCents === <span class="code-number">999</span>);              <span class="code-good">// true ← discount applies!</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-function">toDollars</span>(totalCents));           <span class="code-comment">// "9.99" ← correct display</span>

<span class="code-comment">// Safe tax calculation (round at the end, once):</span>
<span class="code-keyword">const</span> subtotalCents = <span class="code-number">1999</span>;
<span class="code-keyword">const</span> taxRateBps    = <span class="code-number">850</span>;   <span class="code-comment">// 8.50% in basis points (850/10000)</span>
<span class="code-keyword">const</span> taxCents      = <span class="code-function">Math</span>.<span class="code-function">round</span>(subtotalCents * taxRateBps / <span class="code-number">10000</span>);
<span class="code-function">console</span>.<span class="code-function">log</span>(taxCents);                         <span class="code-comment">// 170 ← exactly $1.70</span>

<span class="code-comment">// Comparison is now === safe because integers are exact:</span>
