<div class="floating-warning" id="float-warning">
    <button class="warning-close" onclick="document.getElementById('float-warning').classList.remove('show')">×</button>
    <strong>⚠️ Float Error Detected!</strong><br>
    <span id="warning-message"></span>
</div>

<script>
    // ============================================================
    // PRODUCTS
    // ============================================================
    const PRODUCTS = [
        { emoji: '☕', name: 'Coffee',      price: 4.99 },
        { emoji: '🥐', name: 'Croissant',   price: 3.99 },
        { emoji: '🧃', name: 'Juice',       price: 1.01 },
        { emoji: '🍕', name: 'Pizza Slice', price: 2.49 },
        { emoji: '🍫', name: 'Chocolate',   price: 1.75 },
        { emoji: '🥤', name: 'Soda',        price: 0.99 },
        { emoji: '🥗', name: 'Salad',       price: 7.49 },
        { emoji: '🍪', name: 'Cookie',      price: 0.89 },
    ];

    const TAX_RATE = 0.085;
    const TAX_BPS  = 850; // basis points

    // ============================================================
    // STATE
    // ============================================================
    const state = {
        broken: [],
        fixed:  []
    };

    // ============================================================
    // UTILITY
    // ============================================================
    const toCents    = (dollars) => Math.round(dollars * 100);
    const toDollars  = (cents)   => (cents / 100).toFixed(2);
    const formatUSD  = (amount)  => `$${amount}`;

    function preciseFloat(val) {
        // Show the "true" float value with high precision
        return parseFloat(val).toPrecision(20);
    }

    // ============================================================
    // RENDER PRODUCT GRIDS
    // ============================================================
    function renderProductGrids() {
        ['broken', 'fixed'].forEach(mode => {
            const container = document.getElementById(`${mode}-products`);
            container.innerHTML = PRODUCTS.map((p, i) => `
                <div class="product-card" onclick="addItem('${mode}', ${i})">
                    <span class="product-emoji">${p.emoji}</span>
                    <div class="product-name">${p.name}</div>
                    <div class="product-price">$${p.price.toFixed(2)}</div>
                </div>
            `).join('');
        });
    }

    // ============================================================
    // ADD / REMOVE ITEMS
    // ============================================================
    function addItem(mode, productIndex) {
        state[mode].push({ ...PRODUCTS[productIndex] });
        render(mode);
        showFloatWarning(mode);
    }

    function removeItem(mode, index) {
        state[mode].splice(index, 1);
        render(mode);
    }

    function clearCart(mode) {
        state[mode] = [];
        render(mode);
    }

    // ============================================================
    // BROKEN CALCULATIONS (raw floats)
    // ============================================================
    function calcBroken(items) {
        const subtotal = items.reduce((sum, item) => sum + item.price, 0);
        const tax      = subtotal * TAX_RATE;
        const total    = subtotal + tax;
        return { subtotal, tax, total };
    }

    // ============================================================
    // FIXED CALCULATIONS (integer cents)
    // ============================================================
    function calcFixed(items) {
        const subtotalCents = items.reduce((sum, item) => sum + toCents(item.price), 0);
        const taxCents      = Math.round(subtotalCents * TAX_BPS / 10000);
        const totalCents    = subtotalCents + taxCents;
        return { subtotalCents, taxCents, totalCents };
    }

    // ============================================================
    // RENDER
    // ============================================================
    function render(mode) {
        const items     = state[mode];
        const cartEl    = document.getElementById(`${mode}-cart-items`);
        const testsEl   = document.getElementById(`${mode}-tests`);

        // Cart items list
        if (items.length === 0) {
            cartEl.innerHTML = '<div class="cart-empty">Click products above to add them</div>';
        } else {
            cartEl.innerHTML = items.map((item, i) => `
                <div class="cart-item">
                    <span class="cart-item-name">${item.emoji} ${item.name}</span>
                    <span class="cart-item-price">$${item.price.toFixed(2)}</span>
                    <button class="cart-item-remove" onclick="removeItem('${mode}', ${i})">✕</button>
                </div>
            `).join('');
        }

        if (mode === 'broken') {
            renderBroken(items, testsEl);
        } else {
            renderFixed(items, testsEl);
        }
    }

    function renderBroken(items, testsEl) {
        if (items.length === 0) {
            document.getElementById('broken-subtotal').textContent = '$0.00';
            document.getElementById('broken-tax').textContent      = '$0.00';
            document.getElementById('broken-total').textContent    = '$0.00';
            document.getElementById('broken-raw-display').style.display = 'none';
            testsEl.innerHTML = '<div class="cart-empty" style="padding:10px">Add items to see comparison failures</div>';
            return;
        }

        const { subtotal, tax, total } = calcBroken(items);

        // Totals display
        document.getElementById('broken-subtotal').textContent = formatUSD(subtotal.toFixed(2));
        document.getElementById('broken-tax').textContent      = formatUSD(tax.toFixed(2));
        document.getElementById('broken-total').textContent    = formatUSD(total.toFixed(2));

        // Raw float display
        const rawDisplay = document.getElementById('broken-raw-display');
        rawDisplay.style.display = 'block';
        document.getElementById('broken-raw-value').textContent =
            `subtotal = ${preciseFloat(subtotal)}\ntax      = ${preciseFloat(tax)}\ntotal    = ${preciseFloat(total)}`;

        // Comparison tests
        const roundedSubtotal = parseFloat(subtotal.toFixed(2));
        const roundedTotal    = parseFloat(total.toFixed(2));
        const expectedSub     = items.reduce((s, i) => parseFloat((s + i.price).toFixed(2)), 0);

        const tests = [
            {
                expr:     `subtotal === ${roundedSubtotal}`,
                result:   subtotal === roundedSubtotal,
                expected: true,
                note:     `Actual: ${preciseFloat(subtotal)}`
            },
            {
                expr:     `(sum of prices) === subtotal`,
                result:   expectedSub === subtotal,
                expected: true,
                note:     `${expectedSub} vs ${preciseFloat(subtotal)}`
            },
            {
                expr:     `total === ${roundedTotal}`,
                result:   total === roundedTotal,
                expected: true,
                note:     `Actual: ${preciseFloat(total)}`
            },
            {
                expr:     `tax === parseFloat(tax.toFixed(2))`,
                result:   tax === parseFloat(tax.toFixed(2)),
                expected: true,
                note:     `Actual: ${preciseFloat(tax)}`
            },
            {
                expr:     `0.1 + 0.2 === 0.3`,
                result:   0.1 + 0.2 === 0.3,
                expected: true,
                note:     `0.1+0.2 = ${preciseFloat(0.1 + 0.2)}`
            },
        ];

        testsEl.innerHTML = tests.map(t => {
            const pass = t.result === t.expected;
            return `
                <div class="test-row">
                    <span class="test-expression">${t.expr}</span>
                    <span class="test-result ${pass ? 'pass' : 'fail'}">${t.result} ${pass ? '✓' : '✗'}</span>
                </div>
                <div style="font-size:0.72rem;color:#4a5568;padding:2px 10px 6px;font-family:monospace">${t.note}</div>
            `;
        }).join('');
    }

    function renderFixed(items, testsEl) {
        if (items.length === 0) {
            document.getElementById('fixed-subtotal').textContent = '$0.00';
            document.getElementById('fixed-tax').textContent      = '$0.00';
            document.getElementById('fixed-total').textContent    = '$0.00';
            document.getElementById('fixed-raw-display').style.display = 'none';
            testsEl.innerHTML = '<div class="cart-empty" style="padding:10px">Add items to see correct comparisons</div>';
            return;
        }

        const { subtotalCents, taxCents, totalCents } = calcFixed(items);

        document.getElementById('fixed-subtotal').textContent = formatUSD(toDollars(subtotalCents));
        document.getElementById('fixed-tax').textContent      = formatUSD(toDollars(taxCents));
        document.getElementById('fixed-total').textContent    = formatUSD(toDollars(totalCents));

        const rawDisplay = document.getElementById('fixed-raw-display');
        rawDisplay.style.display = 'block';
        document.getElementById('fixed-raw-value').textContent =
            `subtotalCents = ${subtotalCents} (exact integer)\ntaxCents      = ${taxCents} (exact integer)\ntotalCents    = ${totalCents} (exact integer)`;

        // Expected cents from sum
        const expectedSubCents = items.reduce((s, i) => s + toCents(i.price), 0);

        const tests = [
            {
                expr:     `subtotalCents === ${expectedSubCents}`,
                result:   subtotalCents === expectedSubCents,
                expected: true,
                note:     `Both are integer ${subtotalCents} — exact match`
            },
            {
                expr:     `totalCents === ${totalCents}`,
                result:   totalCents === totalCents,
                expected: true,
                note:     `Integer comparison always reliable`
            },
            {
                expr:     `toCents(0.1) + toCents(0.2) === toCents(0.3)`,
                result:   toCents(0.1) + toCents(0.2) === toCents(0.3),
                expected: true,
                note:     `10 + 20 === 30 → ${toCents(0.1) + toCents(0.2) === toCents(0.3)}`
            },
            {
                expr:     `taxCents is integer`,
                result:   Number.isInteger(taxCents),
                expected: true,
                note:     `Math.round ensures integer cents`
            },
            {
                expr:     `No floating point in sum`,
                result:   items.every(i => Number.isInteger(toCents(i.price))),
                expected: true,
                note:     `All prices converted to exact cents`
            },
        ];

        testsEl.innerHTML = tests.map(t => {
            const pass = t.result === t.expected;
            return `
                <div class="test-row">
                    <span class="test-expression">${t.expr}</span>
                    <span class="test-result ${pass ? 'pass' : 'fail'}">${t.result} ${pass ? '✓' : '✗'}</span>
                </div>
                <div style="font-size:0.72rem;color:#4a5568;padding:2px 10px 6px;font-family:monospace">${t.note}</div>
            `;
        }).join('');
    }

    // ============================================================
    // DISCOUNT CHECKS
    // ============================================================
    function checkDiscountBroken() {
        const input   = parseFloat(document.getElementById('broken-discount-input').value);
        const resultEl = document.getElementById('broken-discount-result');

        if (isNaN(input)) {
            resultEl.innerHTML = '';
            return;
        }

        const items = state.broken;
        if (items.length === 0) {
            resultEl.innerHTML = '<div class="discount-result broken-result">Add items to cart first</div>';
            return;
        }

        const { total } = calcBroken(items);
        const match      = total === input;
        const actualFull = preciseFloat(total);

        resultEl.innerHTML = `
            <div class="discount-result broken-result">
                <strong>total === ${input}</strong> → <strong>${match}</strong><br>
                <small>Float total: ${actualFull}</small><br>
                <small>Your input: ${input}</small><br>
                <small>${match ? '✅ Match (lucky!)' : '❌ No match — discount REJECTED even if mathematically correct'}</small>
            </div>
        `;
    }

    function checkDiscountFixed() {
        const input    = parseFloat(document.getElementById('fixed-discount-input').value);
        const resultEl = document.getElementById('fixed-discount-result');

        if (isNaN(input)) {
            resultEl.innerHTML = '';
            return;
        }

        const items = state.fixed;
        if (items.length === 0) {
            resultEl.innerHTML = '<div class="discount-result fixed-result">Add items to cart first</div>';
            return;
        }

        const { totalCents } = calcFixed(items);
        const
